const __ = -1

// enum classes
const (
	C_SPACE Classes = iota /* space */
	C_WHITE                /* other whitespace */
	C_LCURB                /* {  */
	C_RCURB                /* } */
	C_LSQRB                /* [ */
	C_RSQRB                /* ] */
	C_COLON                /* : */
	C_COMMA                /* , */
	C_QUOTE                /* " */
	C_BACKS                /* \ */
	C_SLASH                /* / */
	C_PLUS                 /* + */
	C_MINUS                /* - */
	C_POINT                /* . */
	C_ZERO                 /* 0 */
	C_DIGIT                /* 123456789 */
	C_LOW_A                /* a */
	C_LOW_B                /* b */
	C_LOW_C                /* c */
	C_LOW_D                /* d */
	C_LOW_E                /* e */
	C_LOW_F                /* f */
	C_LOW_L                /* l */
	C_LOW_N                /* n */
	C_LOW_R                /* r */
	C_LOW_S                /* s */
	C_LOW_T                /* t */
	C_LOW_U                /* u */
