package realmid

import (
	"chain/runtime/unsafe"
	"strings"
)

// Returns the identifier of the previous realm in the call chain.
func Previous() string {
	r := unsafe.PreviousRealm()
	if r.IsUser() {
		return r.Address().String()
	}
	return r.PkgPath()
}

// Returns the identifier of the current realm.
func Current() string {
	r := unsafe.CurrentRealm()
	if r.IsUser() {
		return r.Address().String()
	}
	return r.PkgPath()
}

// Checks if the given identifier is a package path.
// Package paths contain dots (e.g., "gno.land/p/demo/users").
func IsPackage(id string) bool {
	return strings.ContainsRune(id, '.')
}

// Checks if the given identifier is a user address.
// User addresses don't contain dots (e.g., "g1abc...def").
func IsUser(id string) bool {
	return !IsPackage(id)
}

package daocond

import (
	"gno.land/p/samcrew/avl"
)

type BallotAVL struct {
	tree *avl.Tree
}

// Creates a new ballot implementation using AVL tree.
func NewBallot() Ballot {
	return &BallotAVL{tree: avl.NewTree()}
}

// Records a vote from a specific voter, overwriting any previous vote.
func (b *BallotAVL) Vote(voter string, vote Vote) {
	b.tree.Set(voter, vote)
}

// Gets the vote from a specific voter, returns VoteAbstain if no vote recorded.
func (b *BallotAVL) Get(voter string) Vote {
	vote, ok := b.tree.Get(voter)
	if !ok {
		return VoteAbstain
	}
	return vote.(Vote)
}

// Returns the total number of votes cast.
func (b *BallotAVL) Total() int {
	return b.tree.Size()
}

// Iterates over all votes, calling fn for each voter-vote pair.
func (b *BallotAVL) Iterate(fn func(voter string, vote Vote) bool) {
	b.tree.Iterate("", "", func(key string, value interface{}) bool {
		v, ok := value.(Vote)
		if !ok {
			return false
		}
		return fn(key, v)
	})
}

package daocond

import (
	"strings"
)

type andCond struct {
	conditions []Condition
}

// Creates a new condition from multiple conditions
// where all must be true to pass.
//
// Example: And(MembersThreshold(0.6), RoleCount(2, "admin"))
// Requires both 60% member approval AND 2 admin votes.
func And(conditions ...Condition) Condition {
	if len(conditions) < 2 {
		panic("at least two conditions are required")
	}
	return &andCond{conditions: conditions}
}

// Checks if all conditions are true.
func (c *andCond) Eval(ballot Ballot) bool {
	for _, condition := range c.conditions {
		if !condition.Eval(ballot) {
			return false
		}
	}
	return true
}

// Returns average signal across all conditions between 0.0 and 1.0.
func (c *andCond) Signal(ballot Ballot) float64 {
	totalSignal := 0.0
	for _, condition := range c.conditions {
		totalSignal += condition.Signal(ballot)
	}
	return totalSignal / float64(len(c.conditions))
}

// Displays the condition as text.
// Example output: "[ 60% Members AND 2 admin ]"
func (c *andCond) Render() string {
	renders := []string{}
	for _, condition := range c.conditions {
		renders = append(renders, condition.Render())
	}
	return "**[** " + strings.Join(renders, " **AND** ") + " **]**"
}

// Displays the condition with current vote counts.
// Example output: "[ 3/5 Members AND 1/2 admin ]"
func (c *andCond) RenderWithVotes(ballot Ballot) string {
	renders := []string{}
	for _, condition := range c.conditions {
		renders = append(renders, condition.RenderWithVotes(ballot))
	}
	return "**[** " + strings.Join(renders, " **AND** ") + " **]**"
}

var _ Condition = (*andCond)(nil)

package daocond

import (
	"errors"
	"math"
	"strconv"
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

type gnolovDaoCondThreshold struct {
	threshold            float64
	roles                []string
	hasRoleFn            func(memberId string, role string) bool
	usersWithRoleCountFn func(role string) uint32
}

var roleWeights = []float64{3.0, 2.0, 1.0}

// Creates a weighted voting condition based on role tiers with dynamic power calculation.
// Example: GnoloveDAOCondThreshold(0.5, ["admin", "mod", "user"], hasRoleFn, countFn)
// This is our implementation of the govdao condition following Jae Kwon's specification: https://gist.github.com/jaekwon/918ad325c4c8f7fb5d6e022e33cb7eb3
func GnoloveDAOCondThreshold(threshold float64, roles []string, hasRoleFn func(memberId string, role string) bool, usersWithRoleCountFn func(role string) uint32) Condition {
	if threshold <= 0 || threshold > 1 {
		panic(errors.New("invalid threshold"))
	}
	if usersWithRoleCountFn == nil {
		panic(errors.New("nil usersWithRoleCountFn"))
	}
	if hasRoleFn == nil {
		panic(errors.New("nil hasRoleFn"))
	}
	if len(roles) > 3 {
		panic("the gnolove dao condition handles at most 3 roles")
	}
	return &gnolovDaoCondThreshold{
		threshold:            threshold,
		roles:                roles,
		hasRoleFn:            hasRoleFn,
		usersWithRoleCountFn: usersWithRoleCountFn,
	}
}

// Checks if weighted voting power meets the threshold.
func (c *gnolovDaoCondThreshold) Eval(ballot Ballot) bool {
	return c.voteRatio(ballot, VoteYes) >= c.threshold
}

// Returns progress toward meeting the weighted threshold between 0.0 and 1.0.
func (c *gnolovDaoCondThreshold) Signal(ballot Ballot) float64 {
	return math.Min(c.voteRatio(ballot, VoteYes)/c.threshold, 1)
}

// Displays the condition with role weights as text.
// Example output: "50% of total voting power | admin => 3.00 power | mod => 2.00 power"
func (c *gnolovDaoCondThreshold) Render() string {
	rolePowers := []string{}
	for i, role := range c.roles {
		weight := strconv.FormatFloat(roleWeights[i], 'f', 2, 64) // ufmt.Sprintf("%.2f", ...) is not working
		rolePowers = append(rolePowers, ufmt.Sprintf("%s => %s power", role, weight))
	}
	return ufmt.Sprintf("%g%% of total voting power | %s", c.threshold*100, strings.Join(rolePowers, " | "))
}

// Displays the condition with current weighted vote counts and breakdown.
// Shows detailed voting power analysis and vote distribution across roles.
func (c *gnolovDaoCondThreshold) RenderWithVotes(ballot Ballot) string {
	vPowers, totalPower := c.computeVotingPowers()
	rolePowers := []string{}
	for _, role := range c.roles {
		weight := strconv.FormatFloat(vPowers[role], 'f', 2, 64) // ufmt.Sprintf("%.2f", ...) is not working
		rolePowers = append(rolePowers, ufmt.Sprintf("%s => %s power", role, weight))
	}
	s := ""
	s += ufmt.Sprintf("%g%% of total voting power | %s\n\n", c.threshold*100, strings.Join(rolePowers, " | "))
	s += ufmt.Sprintf("Threshold needed: %g%% of total voting power\n\n", c.threshold*100)
	s += ufmt.Sprintf("Yes: %d/%d\n\n", c.voteRatio(ballot, VoteYes), totalPower)
	s += ufmt.Sprintf("No: %d/%d\n\n", c.voteRatio(ballot, VoteNo), totalPower)
	s += ufmt.Sprintf("Abstain: %d/%d\n\n", c.voteRatio(ballot, VoteAbstain), totalPower)
	s += ufmt.Sprintf("Voting power needed: %g%% of total voting power\n\n", c.threshold*totalPower)
	return s
}

var _ Condition = (*gnolovDaoCondThreshold)(nil)

func (c *gnolovDaoCondThreshold) voteRatio(ballot Ballot, vote Vote) float64 {
	var total float64
	votingPowersByTier, totalPower := c.computeVotingPowers()
	// Case when there are zero T1s
	if totalPower == 0.0 {
		return totalPower
	}

	ballot.Iterate(func(voter string, v Vote) bool {
		if v != vote {
			return false
		}
		tier := c.getUserRole(voter)
		total += votingPowersByTier[tier]
		return false
	})
	return total / totalPower
}

// Returns the voter's tier role, or "" when they hold none of this condition's
// roles.
//
// This used to panic. Core.Vote gates on membership only, never on holding a
// tier role, so a member without one can reach the ballot — as can any member
// when the condition is built over a subset of the DAO's roles. The panic was
// raised from inside the ballot walk, so a single such vote made every later
// Eval, Signal and Render on that proposal panic. On an immutable publish that
// is permanent, triggered by an ordinary member casting an ordinary vote.
//
// A voter with no tier role simply carries no voting power: "" is absent from
// votingPowersByTier, so the lookup yields 0.0 and they contribute nothing. That
// is also what the existing test matrix already expects — the "T3 abstaining"
// case asserts 7/10, which is precisely the tally with the T3 votes excluded.
func (c *gnolovDaoCondThreshold) getUserRole(userID string) string {
	for _, role := range c.roles {
		if c.hasRoleFn(userID, role) {
			return role
		}
	}
	return ""
}

func (c *gnolovDaoCondThreshold) computeVotingPowers() (map[string]float64, float64) {
	votingPowers := make(map[string]float64)
	totalPower := 0.0
	countsMembersPerRole := make(map[string]float64)

	for _, role := range c.roles {
		countsMembersPerRole[role] = float64(c.usersWithRoleCountFn(role))
	}

	for i, role := range c.roles {
		if i == 0 {
			votingPowers[role] = roleWeights[0] // Highest tier always gets max power (3.0)
		} else {
			votingPowers[role] = computePower(countsMembersPerRole[c.roles[0]], countsMembersPerRole[role], roleWeights[i])
		}
		totalPower += votingPowers[role] * countsMembersPerRole[role]
	}

	return votingPowers, totalPower
}

// max power here is the number of votes each tier gets when we have
// the same number of member on each tier
// T2 = 2.0 and T1 = 1.0 with the ration T1/Tn
// we compute the actual ratio
func computePower(T1, Tn, maxPower float64) float64 {
	// If there are 0 Tn (T2, T3) just return the max power
	// we could also return 0.0 as voting power
	if Tn <= 0.0 {
		return maxPower
	}

	computedPower := (T1 / Tn) * maxPower
	if computedPower >= maxPower {
		// If computed power is bigger than the max, this happens if Tn is lower than T1
		// cap the max power to max power.
		return maxPower
	}
	return computedPower
}

package daocond

import (
	"errors"
	"math"

	"gno.land/p/nt/ufmt/v0"
)

type membersThresholdCond struct {
	isMemberFn     func(memberId string) bool
	membersCountFn func() uint64
	threshold      float64
}

// Creates a condition requiring a percentage of members to vote yes.
//
// Example: MembersThreshold(0.6, isMemberFn, countFn)
// Requires 60% member approval.
func MembersThreshold(threshold float64, isMemberFn func(memberId string) bool, membersCountFn func() uint64) Condition {
	if threshold <= 0 || threshold > 1 {
		panic(errors.New("invalid threshold"))
	}
	if isMemberFn == nil {
		panic(errors.New("nil isMemberFn"))
	}
	if membersCountFn == nil {
		panic(errors.New("nil membersCountFn"))
	}
	return &membersThresholdCond{
		threshold:      threshold,
		isMemberFn:     isMemberFn,
		membersCountFn: membersCountFn,
	}
}

// Checks if enough members voted yes to meet the threshold.
func (c *membersThresholdCond) Eval(ballot Ballot) bool {
	return c.voteRatio(ballot, VoteYes) >= c.threshold
}

// Returns progress toward meeting the threshold between 0.0 and 1.0.
func (c *membersThresholdCond) Signal(ballot Ballot) float64 {
	return math.Min(c.voteRatio(ballot, VoteYes)/c.threshold, 1)
}

// Displays the condition as text.
// Example output: "60% of members"
func (c *membersThresholdCond) Render() string {
	return ufmt.Sprintf("%g%% of members", c.threshold*100)
}

// Displays the condition with current vote counts.
// Example output: "60% of members must vote yes\n\nYes: 3/5 = 60%"
func (c *membersThresholdCond) RenderWithVotes(ballot Ballot) string {
	s := ""
	s += ufmt.Sprintf("%g%% of members must vote yes\n\n", c.threshold*100)
	s += ufmt.Sprintf("Yes: %d/%d = %g%%\n\n", c.totalVote(ballot, VoteYes), c.membersCountFn(), c.voteRatio(ballot, VoteYes)*100)
	s += ufmt.Sprintf("No: %d/%d = %g%%\n\n", c.totalVote(ballot, VoteNo), c.membersCountFn(), c.voteRatio(ballot, VoteNo)*100)
	s += ufmt.Sprintf("Abstain: %d/%d = %g%%\n\n", c.totalVote(ballot, VoteAbstain), c.membersCountFn(), c.voteRatio(ballot, VoteAbstain)*100)
	return s
}

var _ Condition = (*membersThresholdCond)(nil)

func (c *membersThresholdCond) voteRatio(ballot Ballot, vote Vote) float64 {
	// See roleThresholdCond.voteRatio: 0/0 is NaN in gno, and NaN leaks into
	// Eval, Signal and Render. Zero members must read as 0.0, never 1.0.
	membersCount := c.membersCountFn()
	if membersCount == 0 {
		return 0
	}
	return float64(c.totalVote(ballot, vote)) / float64(membersCount)
}

func (c *membersThresholdCond) totalVote(ballot Ballot, vote Vote) uint64 {
	total := uint64(0)
	ballot.Iterate(func(voter string, v Vote) bool {
		if v == vote && c.isMemberFn(voter) {
			total += 1
		}
		return false
	})
	return total
}

package daocond

import (
	"math"
	"strings"
)

type orCond struct {
	conditions []Condition
}

// Creates a new condition from multiple conditions where any one must be true.
//
// Example: Or(MembersThreshold(0.6), RoleCount(2, "admin"))
// Requires either 60% member approval OR 2 admin votes.
func Or(conditions ...Condition) Condition {
	if len(conditions) < 2 {
		panic("at least two conditions are required")
	}
	return &orCond{conditions: conditions}
}

// Checks if any condition is true.
func (c *orCond) Eval(ballot Ballot) bool {
	for _, condition := range c.conditions {
		if condition.Eval(ballot) {
			return true
		}
	}
	return false
}

// Returns highest signal among all conditions between 0.0 and 1.0.
func (c *orCond) Signal(ballot Ballot) float64 {
	maxSignal := 0.0
	for _, condition := range c.conditions {
		maxSignal = math.Max(maxSignal, condition.Signal(ballot))
	}
	return maxSignal
}

// Displays the condition as text.
// Example output: "[ 60% Members OR 2 admin ]"
func (c *orCond) Render() string {
	renders := []string{}
	for _, condition := range c.conditions {
		renders = append(renders, condition.Render())
	}
	return "**[** " + strings.Join(renders, " **OR** ") + " **]**"
}

// Displays the condition with current vote counts.
// Example output: "[ 3/5 Members OR 1/2 admin ]"
func (c *orCond) RenderWithVotes(ballot Ballot) string {
	renders := []string{}
	for _, condition := range c.conditions {
		renders = append(renders, condition.RenderWithVotes(ballot))
	}
	return "**[** " + strings.Join(renders, " **OR** ") + " **]**"
}

var _ Condition = (*orCond)(nil)

