import (
	"errors"
	"math"

	"gno.land/p/nt/ufmt/v0"
)

type roleThresholdCond struct {
	hasRoleFn        func(memberId string, role string) bool
	usersRoleCountFn func(role string) uint32
	threshold        float64
	role             string
}

// Creates a condition requiring a percentage of role holders to vote yes.
//
// Example: RoleThreshold(0.6, "admin", hasRoleFn, countFn)
// Requires 60% of admins.
func RoleThreshold(threshold float64, role string, hasRoleFn func(memberId string, role string) bool, usersRoleCountFn func(role string) uint32) Condition {
	if threshold <= 0 || threshold > 1 {
		panic(errors.New("invalid threshold"))
	}
	if hasRoleFn == nil {
		panic(errors.New("nil hasRoleFn"))
	}
	if usersRoleCountFn == nil {
		panic(errors.New("nil usersRoleCountFn"))
	}
	return &roleThresholdCond{
		threshold:        threshold,
		hasRoleFn:        hasRoleFn,
		usersRoleCountFn: usersRoleCountFn,
		role:             role,
	}
}

// Checks if enough role holders voted yes to meet the threshold.
func (c *roleThresholdCond) Eval(ballot Ballot) bool {
	return c.voteRatio(ballot, VoteYes) >= c.threshold
}

// Returns progress toward meeting the threshold between 0.0 and 1.0.
func (c *roleThresholdCond) Signal(ballot Ballot) float64 {
	return math.Min(c.voteRatio(ballot, VoteYes)/c.threshold, 1)
}

// Displays the condition as text.
// Example output: "60% of admin members"
func (c *roleThresholdCond) Render() string {
	return ufmt.Sprintf("%g%% of %s members", c.threshold*100, c.role)
}

// Displays the condition with current vote counts.
// Example output: "60% of admin members with role admin must vote yes\n\nYes: 1/2 = 50%"
func (c *roleThresholdCond) RenderWithVotes(ballot Ballot) string {
	s := ""
	s += ufmt.Sprintf("%g%% of %s members with role %s must vote yes\n\n", c.threshold*100, c.role, c.role)
	s += ufmt.Sprintf("Yes: %d/%d = %g%%\n\n", c.totalVote(ballot, VoteYes), c.usersRoleCountFn(c.role), c.voteRatio(ballot, VoteYes)*100)
	s += ufmt.Sprintf("No: %d/%d = %g%%\n\n", c.totalVote(ballot, VoteNo), c.usersRoleCountFn(c.role), c.voteRatio(ballot, VoteNo)*100)
	s += ufmt.Sprintf("Abstain: %d/%d = %g%%\n\n", c.totalVote(ballot, VoteAbstain), c.usersRoleCountFn(c.role), c.voteRatio(ballot, VoteAbstain)*100)
	return s
}

var _ Condition = (*roleThresholdCond)(nil)

func (c *roleThresholdCond) voteRatio(ballot Ballot, vote Vote) float64 {
	// The role can reachably have zero holders while the DAO still has members
	// (RemoveRoleFromMember, RemoveRole, or removing the last holder), so the
	// minimum-member guard does not cover this. gno's float64 divide has no
	// zero guard, so 0/0 would yield NaN and leak into Eval, Signal and Render.
	// Zero must read as 0.0, never 1.0 — a vacuous-truth reading would let a
	// proposal pass with nobody entitled to vote on it.
	roleCount := c.usersRoleCountFn(c.role)
	if roleCount == 0 {
		return 0
	}
	return float64(c.totalVote(ballot, vote)) / float64(roleCount)
}

func (c *roleThresholdCond) totalVote(ballot Ballot, vote Vote) uint32 {
	total := uint32(0)
	ballot.Iterate(func(voter string, v Vote) bool {
		if v == vote && c.hasRoleFn(voter, c.role) {
			total += 1
		}
		return false
	})
	return total
}

package daocond

// Package daocond provides a stateless condition system for DAO voting.
//
// This model replaces complex event handlers. It works well for
// small DAOs with few voters, with plans to add stateful models for
// larger DAOs in the future.

// Represents a voting requirement.
type Condition interface {
	// Checks if the condition is satisfied by the current votes.
	Eval(ballot Ballot) bool
	// Returns progress toward satisfying the condition (0.0 to 1.0).
	Signal(ballot Ballot) float64

	// Displays the condition as human-readable text.
	// Example output: "[ 60% Members OR 2 admin ]"
	Render() string
	// Displays the condition with current vote counts.
	// Example output: "[ 3/5 Members OR 1/2 admin ]"
	RenderWithVotes(ballot Ballot) string
}

// Represents a collection of votes that can be evaluated against conditions.
type Ballot interface {
	// Records a vote from a specific voter.
	Vote(voter string, vote Vote)

	// Retrieves the vote from a specific voter.
	Get(voter string) Vote
	// Returns the total number of votes cast.
	Total() int

	// Iterate over all votes, calling fn for each voter/vote pair.
	// If fn returns false, iteration stops.
	// Useful for counting specific vote types or finding particular voters.
	Iterate(fn func(voter string, vote Vote) bool)
}

// Represents a voting decision.
type Vote string

// Available vote options.
//
// Typed as Vote, not as untyped strings: an untyped constant assigns to a plain
// string without complaint, so a caller could hold one in a string variable and
// only discover the mismatch at a conversion. Typing them is a source-breaking
// change for any such caller, which is why it has to happen before publication
// rather than after.
const (
	VoteYes     Vote = "yes"
	VoteNo      Vote = "no"
	VoteAbstain Vote = "abstain"
)

package daokit

// Defines executable operations that proposals can perform.
// Each action has a type and handler functions that implements the actual logic.
//
// Example: Adding a member, transferring funds, or updating configuration.

import (
	"errors"

	"gno.land/p/moul/md"
	"gno.land/p/nt/ufmt/v0"
)

// Interface storing Action's data.
//
// SECURITY: String() is what a member reads before voting, and for an action
// built with NewAction it is the PAYLOAD's own rendering — supplied by whoever
// created the proposal. It is not trustworthy on its own.
//
// Two things keep it honest. Type() must be truthful or the wrong handler is
// looked up and its type assertion fails, so the action's KIND cannot be
// disguised; and the proposal view renders the Resource's registered
// DisplayName, Description and Condition beside it, which come from the DAO's
// own registry keyed by Type(), not from the proposal. A member therefore always
// sees what KIND of action this is from a trusted source.
//
// What String() can still misrepresent is the payload's DETAIL — and only if the
// handler lets a hostile payload through. See NewActionHandler.
type Action interface {
	// Returns human-readable description of the action.
	String() string
	// Returns unique identifier for the action type.
	Type() string
}

// Interface storing executable function that processes Action's data.
type ActionHandler interface {
	// Executes the given action's logic. The rlm realm is threaded so
	// handlers can perform cross-realm calls during execution.
	Execute(action Action, rlm realm)
	// Returns the action type this handler processes.
	Type() string
}

// Generic action implementation that stores a type and a payload.
// Payload contains the data parameters that will be processed by the handler.
// Example: {kind="/p/demo/transfer.Transfer", payload={amount: 1000, recipient: "user123"}}
type genericAction struct {
	kind    string
	payload interface{}
}

// Generic action handler that executes a function with a given payload.
// Example: A transfer handler that processes {amount, recipient} to move funds.
// {kind="transfer", executor=transferFunds}
type genericActionHandler struct {
	kind     string
	executor func(payload interface{}, rlm realm)
}

func NewAction(kind string, payload interface{}) Action {
	return &genericAction{kind: kind, payload: payload}
}

// Returns string representation of the action's payload.
func (g *genericAction) String() string {
	return ufmt.Sprintf("%v", g.payload)
}

// Returns the action's type identifier.
func (g *genericAction) Type() string {
	return g.kind
}

// SECURITY: the executor MUST type-assert the payload to a CONCRETE type, never
// to an interface.
//
// The concrete assertion is what makes the action's own rendering safe to show a
// voter: a hostile proposer can submit any payload, but one of the wrong type is
// rejected before the executor sees it, and one of the right type renders
// through that type's own String(). Assert to an interface instead and any
// conforming type passes — including one whose String() understates what its
// data does, so the proposal reads as something milder than it executes.
//
// Stronger still, and what the destructive built-ins do: make the payload type
// UNEXPORTED and expose only a constructor, so a proposer cannot build one at
// all. basedao's ChangeDAOImplementation and daokit's InstantExecute both do.
//
// Moving rendering onto the handler would remove this footgun rather than
// document it, since the handler is registered by the DAO and the payload is
// not — gnodaokit#13. That changes ActionHandler, so it belongs to a version
// boundary rather than a patch.
func NewActionHandler(kind string, executor func(interface{}, realm)) ActionHandler {
	return &genericActionHandler{kind: kind, executor: executor}
}

// Executes the action by calling the executor function with the payload.
func (g *genericActionHandler) Execute(iaction Action, rlm realm) {
	action, ok := iaction.(*genericAction)
	if !ok {
		panic(errors.New("invalid action type"))
	}
	g.executor(action.payload, rlm)
}

// Returns the action's type identifier.
func (g *genericActionHandler) Type() string {
	return g.kind
}

// Creates a new empty action instance.
func (g *genericActionHandler) Instantiate() Action {
	return &genericAction{
		kind: g.kind,
	}
}

// //////////////////////////////////////////////////////////
// ActionExecuteLambdaKind
//
// Built-in action type for executing lambda functions.
const ActionExecuteLambdaKind = "gno.land/p/samcrew/daokit.ExecuteLambda"

func NewExecuteLambdaHandler() ActionHandler {
	return NewActionHandler(ActionExecuteLambdaKind, func(i interface{}, _ realm) {
		cb, ok := i.(func())
		if !ok {
			panic(errors.New("invalid action type"))
		}
		cb()
	})
}

func NewExecuteLambdaAction(cb func()) Action {
	return NewAction(ActionExecuteLambdaKind, cb)
}

// //////////////////////////////////////////////////////////
// ActionInstantExecuteKind
//
// Built-in action type for instantly executing sub-proposals.
const ActionInstantExecuteKind = "gno.land/p/samcrew/daokit.InstantExecute"

type actionInstantExecute struct {
	dao DAO             // Target DAO to execute on
	req ProposalRequest // Proposal to execute instantly
}

func (a *actionInstantExecute) String() string {
	// XXX: find a way to be explicit about the subdao
	s := ""
	s += md.Paragraph(md.Blockquote(a.req.Action.Type()))
	s += md.Paragraph(a.req.Action.String())
	return s
}

func NewInstantExecuteHandler() ActionHandler {
	return NewActionHandler(ActionInstantExecuteKind, func(i interface{}, rlm realm) {
		action, ok := i.(*actionInstantExecute)
		if !ok {
			panic(errors.New("invalid action type"))
		}
		InstantExecute(action.dao, action.req, rlm)
	})
}

// SAME REALM ONLY, for the reason on InstantExecute: the handler forwards the
// EXECUTING DAO's realm, so dao must be hosted by the same realm. A child DAO in
// another realm is refused — reach it through that realm's crossing function
// instead.
func NewInstantExecuteAction(dao DAO, req ProposalRequest) Action {
	return NewAction(ActionInstantExecuteKind, &actionInstantExecute{dao: dao, req: req})
}

package daokit

import (
	"time"

	"gno.land/p/samcrew/daocond"
)

// Every entry point threads the DAO realm's own realm value.
//
// It serves two purposes. Execute forwards it to the action handlers, which
// cross out under it, so the implementation must refuse any realm that is not
// its own — otherwise a caller holding this handle could make the DAO act under
// the CALLER's identity. And because the realm is then known to be the DAO's,
// rlm.Previous() names the DAO's immediate caller, which a stack walk cannot do:
// reached through this handle there is no DAO realm frame on the stack at all,
// so a walk reports the signing account instead.
//
// An implementation must require the realm to be BOTH its own by pkgpath and
// current: every realm the DAO crosses out into receives the DAO's own realm as
// its cur.Previous() and can hand it back within the same transaction, and only
// IsCurrent() tells that apart from the live one.
//
// The realm is deliberately never the first parameter: a function whose first
// parameter is a realm is read as crossing, which /p/ packages may not declare.
type DAO interface {
	// Creates a new proposal and returns its ID.
	Propose(req ProposalRequest, rlm realm) uint64
	// Casts a vote on a specific proposal.
	Vote(id uint64, vote daocond.Vote, rlm realm)
	// Executes a proposal if it meets the required conditions.
	Execute(id uint64, rlm realm)

	// Generates a web interface representation for the given path.
	Render(path string) string

	// Gets an extension by path, returns nil if not found. A PRIVATE extension
	// additionally requires the DAO realm's own live realm, on the same terms
	// as the entry points above; a public one ignores it.
	Extension(path string, rlm realm) Extension
	// Lists all available extensions.
	ExtensionsList() ExtensionsList
}

// Function type for updating DAO implementation during governance upgrades.
type SetImplemFn = func(implem DAO)

// Creates, votes yes, and immediately executes a proposal in one operation.
// Useful when you have enough permission to execute an action directly.
// Examples: migrations, adding members.
//
// SAME REALM ONLY. Every step threads rlm, and each entry point requires it to
// be the receiving DAO's own — so d must be a DAO hosted by the realm calling
// this. Handing it a DAO belonging to another realm is refused.
//
// That refusal is the point. Driving a foreign DAO by passing it your realm is
// the donation shape: it makes the DAO act under YOUR identity, and it is what a
// caller holding the handle could previously do to any DAO. It appeared to work
// only because nothing checked.
//
// A parent DAO can still drive a child. Reach the child through the child
// REALM's own crossing function — child.Propose(cross(cur), req) — so the child
// mints its own realm and sees the parent as its caller. Make the parent a
// member of the child; the child then authorises it like any other member.
func InstantExecute(d DAO, req ProposalRequest, rlm realm) uint64 {
	id := d.Propose(req, rlm)
	d.Vote(id, daocond.VoteYes, rlm)
	d.Execute(id, rlm)
	return id
}

// Manages the essential components of a DAO: resources, proposals, and extensions.
type Core struct {
	Resources  *ResourcesStore  // Available actions and their conditions
	Proposals  *ProposalsStore  // All proposals and their voting state
	Extensions *ExtensionsStore // Pluggable functionality modules
}

// Creates a new DAO core with empty stores.
func NewCore() *Core {
	return &Core{
		Resources:  NewResourcesStore(),
		Proposals:  NewProposalsStore(),
		Extensions: &ExtensionsStore{},
	}
}

// Records a vote for a specific proposal from a voter.
func (d *Core) Vote(voterID string, proposalID uint64, vote daocond.Vote) {
	proposal := d.Proposals.GetProposal(proposalID)
	if proposal == nil {
		panic("proposal not found")
	}

	// Same terminal state as Execute: a ballot stays open right up until the
	// proposal executes, so support can still be withdrawn after the condition
	// is first met. Anything narrower would let a proposal be locked in.
	if proposal.Status == ProposalStatusExecuted {
		panic("proposal is already executed")
	}

	proposal.Ballot.Vote(voterID, vote)
}

// Executes a proposal if it meets the required voting conditions.
func (d *Core) Execute(proposalID uint64, rlm realm) {
	proposal := d.Proposals.GetProposal(proposalID)
	if proposal == nil {
		panic("proposal not found")
	}

	// Executed is the only status that disqualifies a proposal. It used to be
	// "anything but Open", which made the status a second, weaker gate on top of
	// the condition — and any realm holding the DAO handle could trip it by
	// rendering, since the read paths wrote Open -> Passed as they walked.
	// Whether a proposal may execute is decided by its condition, below, and
	// nothing else.
	if proposal.Status == ProposalStatusExecuted {
		panic("proposal is already executed")
	}

	if !proposal.Condition.Eval(proposal.Ballot) {
		panic("proposal condition is not met")
	}

	// Marked BEFORE the handler runs, not after. The handler crosses out of the
	// DAO, so a callee can re-enter here within the same transaction; marking
	// afterwards would let it execute the same proposal again. The old code was
	// protected from this only incidentally, by a "must be Open" test that also
	// made rendering able to brick a proposal.
	//
	// The cost is that Execute is NOT retry-safe. gno's recover() does not roll
	// back realm state, so a host realm that recovers around a failing Execute
	// keeps the marker and burns the proposal permanently. Do not recover around
	// it: let the transaction abort, which reverts the marker with everything
	// else. Marking afterwards would trade this for re-entrancy, which is worse.
	proposal.Status = ProposalStatusExecuted
	proposal.ExecutedAt = time.Now()

	d.Resources.Get(proposal.Action.Type()).Handler.Execute(proposal.Action, rlm)
}

// Creates a new proposal for voting and returns its ID.
func (d *Core) Propose(proposerID string, req ProposalRequest) uint64 {
	actionType := req.Action.Type()

	resource := d.Resources.Get(actionType)
	if resource == nil {
		panic("action type is not registered as a resource")
	}

	prop := d.Proposals.newProposal(proposerID, req, resource.Condition)
	return uint64(prop.ID)
}

package daokit

// Extensions system enables DAOs to expose additional functionality that can be
// accessed by other packages or realms. It provides a secure way to make
// specific DAO capabilities available without exposing internal implementation details.

import "gno.land/p/samcrew/avl"

// Interface must be implemented by any object that wants to be
// registered as a DAO extension. Extensions expose functionality through
// well-defined interfaces while maintaining encapsulation.
type Extension interface {
	// Returns metadata about this extension including its path, version,
	// query path for external access, and privacy settings.
	Info() ExtensionInfo
}

type ExtensionInfo struct {
	Path      string // Unique extension identifier (e.g., "gno.land/p/samcrew/basedao.MembersView")
	Version   string // Extension version (e.g., "1", "2.0", etc.)
	QueryPath string // Path for external queries to access this extension's data
	// If true, only the registering realm can obtain the extension VALUE
	// through DAO.Extension — which is a capability, not a secret. Realm state
	// on a public chain is world-readable over ABCI regardless, and this
	// ExtensionInfo (including QueryPath) is listed by ExtensionsList without a
	// check. Private restricts who can call the extension's methods under the
	// DAO's authority; it does not hide anything.
	Private bool
}

type ExtensionsList interface {
	// Returns the total number of registered extensions.
	Len() int
	// Returns extension info at the specified index, or nil if index is out of bounds.
	Get(index int) *ExtensionInfo
	// Returns a slice of ExtensionInfo from startIndex to endIndex.
	Slice(startIndex, endIndex int) []ExtensionInfo
	// Iterates over all extensions, calling fn for each one.
	// Iteration stops if fn returns true.
	ForEach(fn func(index int, value ExtensionInfo) bool)
}

type ExtensionsStore struct {
	Tree avl.Tree
}

// Registers a new extension using its path as the key.
// Returns true if the extension was successfully registered.
// If an extension with the same path already exists, it will be replaced.
func (es *ExtensionsStore) Set(ext Extension) bool {
	info := ext.Info()
	return es.Tree.Set(info.Path, ext)
}

func (es *ExtensionsStore) Get(path string) (Extension, bool) {
	iface, ok := es.Tree.Get(path)
	if !ok {
		return nil, false
	}
	return iface.(Extension), true
}

// Remove unregisters an extension by its path.
// Returns the removed extension and true if found, nil and false otherwise.
func (es *ExtensionsStore) Remove(path string) (Extension, bool) {
	iface, ok := es.Tree.Remove(path)
	if !ok {
		return nil, false
	}
	return iface.(Extension), true
}

// Returns an ExtensionsList interface for iterating over all registered extensions.
// This provides read-only access to the extensions registry.
func (es *ExtensionsStore) List() ExtensionsList {
	return &extensionsList{es: es}
}

type extensionsList struct {
	es *ExtensionsStore
}

// Iterates over all extensions, calling fn for each extension with its index and info.
// Iteration stops early if fn returns true.
func (e *extensionsList) ForEach(fn func(index int, value ExtensionInfo) bool) {
	if e.es.Tree.Size() == 0 {
		return
	}

	index := 0
	e.es.Tree.IterateByOffset(0, e.es.Tree.Size(), func(_ string, value any) bool {
		result := fn(index, value.(Extension).Info())
		index++
		return result
	})
}

// Returns the ExtensionInfo at the specified index.
func (e *extensionsList) Get(index int) *ExtensionInfo {
	if index < 0 || index >= e.es.Tree.Size() {
		return nil
	}

	_, value := e.es.Tree.GetByIndex(index)
	info := value.(Extension).Info()
	return &info
}

// Returns the total number of registered extensions.
func (e *extensionsList) Len() int {
	return e.es.Tree.Size()
}

// Returns a slice of ExtensionInfo from startIndex (inclusive) to endIndex (exclusive).
// Bounds are automatically normalized: negative startIndex becomes 0, endIndex beyond size becomes size.
func (e *extensionsList) Slice(startIndex int, endIndex int) []ExtensionInfo {
	size := e.es.Tree.Size()

	// Normalize bounds
	if startIndex < 0 {
		startIndex = 0
	}

	if endIndex > size {
		endIndex = size
	}

	if startIndex >= endIndex {
		return nil
	}

	count := endIndex - startIndex
	result := make([]ExtensionInfo, count)

	i := 0
	e.es.Tree.IterateByOffset(startIndex, count, func(_ string, value any) bool {
		result[i] = value.(Extension).Info()
		i++
		return false
	})

	return result
}

package daokit

// Handles DAO governance through proposal voting and execution.
// They contain actions that run when voting requirements are satisfied.
//
// Common use cases: member management, treasury operations, rule updates.

import (
	"chain/runtime"
	"errors"
	"time"

	"gno.land/p/nt/seqid/v0"
	"gno.land/p/onbloc/json"
	"gno.land/p/samcrew/avl"
	"gno.land/p/samcrew/daocond"
)

type ProposalStatus int

const (
	ProposalStatusOpen     ProposalStatus = iota // Currently accepting votes
	ProposalStatusPassed                         // Met conditions, ready for execution
	ProposalStatusExecuted                       // Successfully executed
)

func (s ProposalStatus) String() string {
	switch s {
	case ProposalStatusOpen:
		return "Open"
	case ProposalStatusPassed:
		return "Passed"
	case ProposalStatusExecuted:
		return "Executed"
	default:
		return "Unknown"
	}
}

type Proposal struct {
	ID            seqid.ID
	Title         string
	Description   string
	CreatedAt     time.Time
	CreatedHeight int64
	ProposerID    string

	Action     Action            // What to execute if passed
	Condition  daocond.Condition // Voting conditions for this proposal
	Status     ProposalStatus
	ExecutedAt time.Time

	Ballot daocond.Ballot // All votes cast on this proposal
}

type ProposalsStore struct {
	Tree  *avl.Tree // int -> Proposal
	genID seqid.ID
}

// Data needed to create a new proposal.
type ProposalRequest struct {
	Title       string
	Description string
	Action      Action
}

func NewProposalsStore() *ProposalsStore {
	return &ProposalsStore{
		Tree: avl.NewTree(),
	}
}

func (p *ProposalsStore) GetProposal(id uint64) *Proposal {
	value, ok := p.Tree.Get(seqid.ID(id).String())
	if !ok {
		return nil
	}
	proposal := value.(*Proposal)
	return proposal
}

// Returns all proposals that match the given filter function.
func (p *ProposalsStore) GetProposals(filter func(Proposal) bool) *ProposalsStore {
	proposals := NewProposalsStore()
	p.Tree.Iterate("", "", func(key string, value interface{}) bool {
		prop, ok := value.(*Proposal)
		if !ok {
			panic(errors.New("unexpected invalid proposal type"))
		}
		if filter(*prop) {
			proposals.Tree.Set(key, prop)
		}
		return false
	})
	return proposals
}

// Reports the status a proposal should be displayed as, without writing it.
//
// Reading must never move a proposal. Render is on the cross-realm DAO
// interface, so anything it touches is reachable by any realm holding the
// handle: every read path used to call UpdateStatus on each proposal it walked,
// and a single Render flipped every condition-met proposal from Open to Passed —
// which, back when Execute demanded Open, bricked it permanently.
func (p *Proposal) DisplayStatus() ProposalStatus {
	if p.Status == ProposalStatusOpen && p.Condition.Eval(p.Ballot) {
		return ProposalStatusPassed
	}
	return p.Status
}

// Persists the status implied by the current votes: Open becomes Passed once the
// condition is met.
//
// Nothing in this package calls it. Execute evaluates the condition itself and
// the read paths use DisplayStatus, so a proposal that is never passed through
// here stays Open until it is Executed. It exists for a realm that wants the
// passed state on-chain rather than computed.
//
// SAFE ONLY BECAUSE Vote and Execute both key on Executed alone. When they
// demanded Open, calling this was destructive twice over: it froze the ballot,
// so support could not be withdrawn, and it made the proposal permanently
// unexecutable. Do not narrow either of those checks without removing this.
//
// It is also a READ path hazard — do not call it while rendering. And once
// persisted the status no longer tracks the votes: withdraw support afterwards
// and this still reads Passed, though Execute re-evaluates the condition and
// will refuse.
func (p *Proposal) UpdateStatus() {
	p.Status = p.DisplayStatus()
}

// Returns all proposals as a JSON string.
func (p *ProposalsStore) GetProposalsJSON() string {
	props := make([]*json.Node, 0, p.Tree.Size())
	// XXX: pagination
	p.Tree.Iterate("", "", func(key string, value interface{}) bool {
		prop, ok := value.(*Proposal)
		if !ok {
			panic(errors.New("unexpected invalid proposal type"))
		}
		props = append(props, json.ObjectNode("", map[string]*json.Node{
			"id":          json.NumberNode("", float64(prop.ID)),
			"title":       json.StringNode("", prop.Title),
			"description": json.StringNode("", prop.Description),
			"proposer":    json.StringNode("", prop.ProposerID),
			"status":      json.StringNode("", prop.DisplayStatus().String()),
			"startHeight": json.NumberNode("", float64(prop.CreatedHeight)),
			"signal":      json.NumberNode("", prop.Condition.Signal(prop.Ballot)),
		}))
		return false
	})
	bz, err := json.Marshal(json.ArrayNode("", props))
	if err != nil {
		panic(err)
	}
	return string(bz)
}

func (p *ProposalsStore) newProposal(proposer string, req ProposalRequest, condition daocond.Condition) *Proposal {
	id := p.genID.Next()
	proposal := &Proposal{
		ID:            id,
		Title:         req.Title,
		Description:   req.Description,
		ProposerID:    proposer,
		Status:        ProposalStatusOpen,
		Action:        req.Action,
		Condition:     condition,
		Ballot:        daocond.NewBallot(),
		CreatedAt:     time.Now(),
		CreatedHeight: runtime.ChainHeight(),
	}
	p.Tree.Set(id.String(), proposal)
	return proposal
}

package daokit

// Maps action types to their handlers and conditions.
//
// Example: "transfer" action requires 3 member votes for execution.

import (
	"gno.land/p/samcrew/avl"
	"gno.land/p/samcrew/daocond"
)

type ResourcesStore struct {
	Tree *avl.Tree // string -> daocond.Condition
}

type Resource struct {
	Handler     ActionHandler     // Executes the action when proposal passes
	Condition   daocond.Condition // Voting rules required for approval
	DisplayName string
	Description string
}

func NewResourcesStore() *ResourcesStore {
	return &ResourcesStore{
		Tree: avl.NewTree(),
	}
}

// Retrieves a resource by its handler type name.
func (r *ResourcesStore) Get(name string) *Resource {
	value, ok := r.Tree.Get(name)
	if !ok {
