package memba_dao

// MembaDAO — Community governance realm for the Memba ecosystem.
//
// Uses gnodaokit basedao for full DAO lifecycle:
//   - Role-based membership (admin, dev, ops, member)
//   - Proposal/Vote/Execute governance (66% threshold)
//   - Self-upgradable via ChangeDAOImplementation proposals
//   - Profile integration via r/samcrew/_deps/demo/profile
//
// Security:
//   - NO open AddMember — membership only via DAO proposals (66% vote)
//   - Caller identity via realmid.Previous (default in basedao)
//
// Founding member: samcrew-core-test1 multisig (testnet)
//
// interrealm v2: init takes a realm; basedao.New / localDAO.Execute thread it;
// the v1 crossing wrapper (daokit.NewCrossing / CrossFn / the public DAO var)
// is removed.

import (
	"gno.land/p/samcrew/basedao"
	"gno.land/p/samcrew/daocond"
	"gno.land/p/samcrew/daokit"
	"gno.land/r/demo/profile" // genesis profile (v2); REQUIRED — basedao.New() panics without GetProfileString
)

var (
	localDAO   daokit.DAO          // Local interface for maketx call
	daoPrivate *basedao.DAOPrivate // Full access to internal DAO state
)

// Initializes MembaDAO with roles, founding member, and governance rules.
func init(cur realm) {
	// ── Roles ────────────────────────────────────────────────
	roles := []basedao.RoleInfo{
		{Name: "admin", Description: "DAO administrators with full governance power", Color: "#329175"},
		{Name: "dev", Description: "Core developers building the Memba ecosystem", Color: "#4ecdc4"},
		{Name: "ops", Description: "Operations team managing infrastructure", Color: "#fdcb6e"},
		{Name: "member", Description: "Community members contributing to governance", Color: "#21577A"},
	}

	// ── Founding Member ─────────────────────────────────────
	// samcrew-core-test1 multisig — testnet equivalent of production multisig
	members := []basedao.Member{
		{
			Address: "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0",
			Roles:   []string{"admin", "dev"},
		},
	}

	// ── Governance ───────────────────────────────────────────
	store := basedao.NewMembersStore(roles, members)

	// 66% threshold — strong consensus required for all actions.
	// With 1 member (bootstrap), this effectively means 100% (1/1).
	condition := daocond.MembersThreshold(0.66, store.IsMember, store.MembersCount)

	// ── Initialize DAO ──────────────────────────────────────
	localDAO, daoPrivate = basedao.New(&basedao.Config{
		Name:             "MembaDAO",
		Description:      "Community governance for the Memba ecosystem — multisig wallet & DAO platform on Gno",
		Members:          store,
		InitialCondition: condition,
		GetProfileString: profile.GetStringField,
		SetProfileString: profile.SetStringField,
		PrivateVarName:   "daoPrivate",
		SetImplemFn:      setImplem,
	}, cur)
}

// ── Public API ───────────────────────────────────────────────

// Propose creates a new governance proposal.
// Must be called via MsgRun (gnokey maketx run) for cross-realm support.
func Propose(cur realm, req daokit.ProposalRequest) {
	localDAO.Propose(req, cur)
}

// Vote allows DAO members to cast their vote on a proposal.
func Vote(cur realm, proposalID uint64, vote daocond.Vote) {
	localDAO.Vote(proposalID, vote, cur)
}

// Execute triggers execution of an approved proposal's actions.
func Execute(cur realm, proposalID uint64) {
	localDAO.Execute(proposalID, cur)
}

// Render generates the web UI for gnoweb.
func Render(path string) string {
	return localDAO.Render(path)
}

// ── Internal ─────────────────────────────────────────────────

// setImplem updates the DAO implementation when governance proposals change it.
func setImplem(newLocalDAO daokit.DAO) {
	localDAO = newLocalDAO
}

package memba_dao_candidature_v3

// memba_dao_candidature — Membership application realm for MembaDAO.
//
// Provides a transparent, on-chain candidature flow:
//   1. Applicant calls Apply(bio, skills) with a deposit
//   2. Application is stored on-chain (visible to all)
//   3. Any DAO member can create an AddMember proposal referencing the application
//   4. DAO votes on the proposal (66% threshold)
//   5. If approved, member is added via basedao's built-in AddMember handler
//
// Anti-spam:
//   - Required deposit (10 GNOT default, 10x increase on re-application)
//   - Max bio/skills length (5000 chars)
//   - Cannot apply if already a member
//
// Security:
//   - Deposits are held in the realm until withdrawn by applicant
//   - MarkApproved/MarkRejected restricted to admin allowlist (owner-managed)
//   - Owner can add/remove admins and transfer ownership
//   - Admin cap of 20 addresses to limit blast radius

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"
)

// ── Constants ────────────────────────────────────────────────

const (
	MinDeposit      int64 = 10_000_000 // 10 GNOT in ugnot
	DepositMultiply int64 = 10         // 10x on re-application
	MaxApplyCount         = 10         // Maximum re-applications (prevents int64 overflow at 10^17)
	MaxBioLen             = 5000
	MaxSkillsLen          = 5000
	MaxAdmins             = 20   // Maximum number of admin addresses
	MaxApplications       = 1000 // Global cap to prevent unbounded state growth
)

// ── Types ────────────────────────────────────────────────────

type Application struct {
	Address    address
	Bio        string
	Skills     string
	Deposit    int64
	Status     string // "pending", "approved", "rejected", "withdrawn"
	AppliedAt  int64  // block height
	ApplyCount int    // number of times applied (for deposit scaling)
}

// ── State ────────────────────────────────────────────────────

var (
	applications *avl.Tree // address -> *Application
	applyCount   *avl.Tree // address -> int (total apply count, persists across withdrawals)
	admins       *avl.Tree // address -> bool (authorized callers for MarkApproved/MarkRejected)
	paused       bool
	// Owner is set at package load time via OriginCaller() — this captures the
	// deployer address (samcrew-core-test1 multisig on testnet).
	owner = unsafe.OriginCaller()
)

func init() {
	applications = avl.NewTree()
	applyCount = avl.NewTree()
	admins = avl.NewTree()
	admins.Set(owner.String(), true)
}

// ── Emergency Pause ────────────────────────────────────────

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

func Pause(cur realm) {
	assertCallerIsOwner()
	paused = true
}

func Unpause(cur realm) {
	assertCallerIsOwner()
	paused = false
}

func IsPaused() bool { return paused }

// ── Public API ───────────────────────────────────────────────

// Apply submits a membership application with a deposit.
// The caller must send at least MinDeposit * (10 ^ previousAttempts) ugnot.
func Apply(cur realm, bio string, skills string) {
	assertNotPaused()

	// P0 fund-guard: a payable entrypoint MUST be a direct user call. unsafe.OriginSend()
	// reports the tx-level `--send`, which is credited to the DIRECT message target realm
	// — not to an inner realm reached via a cross-call. Without this guard an attacker
	// routes Apply through their own intermediary realm (coins land there), records a
	// phantom Deposit this realm never received, then drains real pooled deposits via
	// Withdraw. Requiring a direct user call forces this realm to be the message target,
	// the one condition under which the OriginSend coins are guaranteed to be in its account.
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("Apply must be a direct user call")
	}

	caller := unsafe.PreviousRealm().Address()

	// Validate inputs
	if len(bio) == 0 {
		panic("bio cannot be empty")
	}
	if len(bio) > MaxBioLen {
		panic(ufmt.Sprintf("bio too long: %d/%d chars", len(bio), MaxBioLen))
	}
	if len(skills) > MaxSkillsLen {
		panic(ufmt.Sprintf("skills too long: %d/%d chars", len(skills), MaxSkillsLen))
	}

	// Check for existing pending application
	isNewApplicant := true
	if val, exists := applications.Get(caller.String()); exists {
		isNewApplicant = false
		app := val.(*Application)
		if app.Status == "pending" {
			panic("you already have a pending application")
		}
	}
	// Enforce global cap only for truly new applicants (not re-applications)
	if isNewApplicant && applications.Size() >= MaxApplications {
		panic(ufmt.Sprintf("application limit reached: %d", MaxApplications))
	}

	// Calculate required deposit (10x per previous attempt, capped to prevent overflow)
	count := getApplyCount(caller)
	if count >= MaxApplyCount {
		panic(ufmt.Sprintf("maximum re-application limit reached (%d)", MaxApplyCount))
	}
	required := MinDeposit
	for i := 0; i < count; i++ {
		required *= DepositMultiply
	}

	// Verify deposit (accumulate to handle multi-denom entries defensively)
	sent := unsafe.OriginSend()
	sentAmount := int64(0)
	for _, coin := range sent {
		if coin.Denom == "ugnot" {
			sentAmount += coin.Amount
		}
	}
	if sentAmount < required {
		panic(ufmt.Sprintf("insufficient deposit: sent %d, required %d ugnot", sentAmount, required))
	}

	// Store application
	app := &Application{
		Address:    caller,
		Bio:        bio,
		Skills:     skills,
		Deposit:    sentAmount,
		Status:     "pending",
		AppliedAt:  runtime.ChainHeight(),
		ApplyCount: count + 1,
	}
	applications.Set(caller.String(), app)
	applyCount.Set(caller.String(), count+1)

	chain.Emit("ApplicationSubmitted",
		"applicant", caller.String(),
		"deposit", strconv.FormatInt(sentAmount, 10),
		"attempt", strconv.Itoa(count+1),
	)
}

// Withdraw allows an applicant to withdraw their pending application and reclaim deposit.
func Withdraw(cur realm) {
	caller := unsafe.PreviousRealm().Address()

	val, exists := applications.Get(caller.String())
	if !exists {
		panic("no application found")
	}
	app := val.(*Application)
	if app.Status != "pending" {
		panic("can only withdraw pending applications")
	}

	// STATE-BEFORE-SEND: update status and zero deposit before coin transfer
	app.Status = "withdrawn"
	deposit := app.Deposit
	app.Deposit = 0
	applications.Set(caller.String(), app)

	// Return deposit
	if deposit > 0 {
		b := banker.NewBanker(banker.BankerTypeRealmSend, cur)
		b.SendCoins(unsafe.CurrentRealm().Address(), caller, chain.Coins{chain.NewCoin("ugnot", deposit)})
	}
}

// MarkApproved is called by authorized admins to mark an application as approved.
// Only addresses in the admin allowlist can call this function.
func MarkApproved(cur realm, applicant address) {
	assertCallerIsAdmin()

	val, exists := applications.Get(applicant.String())
	if !exists {
		panic("no application found for " + applicant.String())
	}
	app := val.(*Application)
	if app.Status != "pending" {
		panic("application is not pending")
	}
	// STATE-BEFORE-SEND: update status before returning deposit
	app.Status = "approved"
	deposit := app.Deposit
	app.Deposit = 0
	applications.Set(applicant.String(), app)

	// Return deposit on approval (same as rejection)
	if deposit > 0 {
		b := banker.NewBanker(banker.BankerTypeRealmSend, cur)
		b.SendCoins(unsafe.CurrentRealm().Address(), applicant, chain.Coins{chain.NewCoin("ugnot", deposit)})
	}

	chain.Emit("ApplicationApproved",
		"applicant", applicant.String(),
		"approvedBy", unsafe.PreviousRealm().Address().String(),
	)
}

// MarkRejected is called by authorized admins to mark an application as rejected.
// Only addresses in the admin allowlist can call this function.
func MarkRejected(cur realm, applicant address) {
	assertCallerIsAdmin()

	val, exists := applications.Get(applicant.String())
	if !exists {
		panic("no application found for " + applicant.String())
	}
	app := val.(*Application)
	if app.Status != "pending" {
		panic("application is not pending")
	}
	// STATE-BEFORE-SEND: update status and zero deposit before coin transfer
	app.Status = "rejected"
	deposit := app.Deposit
	app.Deposit = 0
	applications.Set(applicant.String(), app)

	// Return deposit on rejection
	if deposit > 0 {
		b := banker.NewBanker(banker.BankerTypeRealmSend, cur)
		b.SendCoins(unsafe.CurrentRealm().Address(), applicant, chain.Coins{chain.NewCoin("ugnot", deposit)})
	}

	chain.Emit("ApplicationRejected",
		"applicant", applicant.String(),
		"rejectedBy", unsafe.PreviousRealm().Address().String(),
	)
}

// ── Admin Management ────────────────────────────────────────

// AddAdmin adds an address to the admin allowlist. Only the owner can call this.
func AddAdmin(cur realm, addr address) {
	assertCallerIsOwner()
	assertValidAddress(addr)
	if admins.Size() >= MaxAdmins {
		panic(ufmt.Sprintf("admin limit reached: %d/%d", admins.Size(), MaxAdmins))
	}
	admins.Set(addr.String(), true)
}

// RemoveAdmin removes an address from the admin allowlist. Only the owner can call this.
func RemoveAdmin(cur realm, addr address) {
	assertCallerIsOwner()
	if addr == owner {
		panic("cannot remove owner from admins")
	}
	if _, exists := admins.Get(addr.String()); !exists {
		panic("address is not an admin: " + addr.String())
	}
	admins.Remove(addr.String())
}

// TransferOwnership transfers realm ownership to a new address.
// The new owner is also added as admin. The old owner remains as admin
// (the new owner can remove them via RemoveAdmin if desired).
// Only the current owner can call this.
func TransferOwnership(cur realm, newOwner address) {
	assertCallerIsOwner()
	assertValidAddress(newOwner)
	if newOwner == owner {
		panic("new owner is the same as current owner")
	}
	admins.Set(newOwner.String(), true)
	owner = newOwner
}

// IsAdmin returns whether an address is in the admin allowlist.
func IsAdmin(addr address) bool {
	_, exists := admins.Get(addr.String())
	return exists
}

// GetOwner returns the current realm owner address.
func GetOwner() address {
	return owner
}

// ListAdmins returns all admin addresses as a comma-separated string.
func ListAdmins() string {
	var addrs []string
	admins.Iterate("", "", func(key string, value any) bool {
		addrs = append(addrs, key)
		return false
	})
	return strings.Join(addrs, ",")
}

// ── Queries ──────────────────────────────────────────────────

// GetApplication returns the application for a given address (or empty if none).
func GetApplication(addr string) string {
	val, exists := applications.Get(addr)
	if !exists {
		return ""
	}
	app := val.(*Application)
	return ufmt.Sprintf("%s|%s|%s|%d|%s|%d|%d",
		app.Address, app.Bio, app.Skills, app.Deposit, app.Status, app.AppliedAt, app.ApplyCount)
}

// ── Render ───────────────────────────────────────────────────

func Render(path string) string {
	if path == "" {
		return renderHome()
	}
	if strings.HasPrefix(path, "application/") {
		addr := strings.TrimPrefix(path, "application/")
		return renderApplication(addr)
	}
	return "# 404\nPage not found: " + path
}

func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# MembaDAO Candidature\n\n")
	sb.WriteString("Apply to join the Memba community.\n\n")

	// Count by status
	pending, approved, rejected := 0, 0, 0
	applications.Iterate("", "", func(key string, value any) bool {
		app := value.(*Application)
		switch app.Status {
		case "pending":
			pending++
		case "approved":
			approved++
		case "rejected":
			rejected++
		}
		return false
	})

	sb.WriteString(ufmt.Sprintf("**Stats:** %d pending | %d approved | %d rejected\n", pending, approved, rejected))
	sb.WriteString(ufmt.Sprintf("**Owner:** %s | **Admins:** %d\n\n", owner, admins.Size()))

	// List pending applications
	if pending > 0 {
		sb.WriteString("## Pending Applications\n\n")
		applications.Iterate("", "", func(key string, value any) bool {
			app := value.(*Application)
			if app.Status == "pending" {
				sb.WriteString(ufmt.Sprintf("- [%s](:application/%s) — deposit: %s GNOT — block %d\n",
					app.Address, app.Address, formatGNOT(app.Deposit), app.AppliedAt))
			}
			return false
		})
	}

	return sb.String()
}

func renderApplication(addr string) string {
	val, exists := applications.Get(addr)
	if !exists {
		return "# Application Not Found\nNo application for " + addr
	}
	app := val.(*Application)

	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Application: %s\n\n", app.Address))
	sb.WriteString(ufmt.Sprintf("**Status:** %s\n", app.Status))
	sb.WriteString(ufmt.Sprintf("**Deposit:** %s GNOT\n", formatGNOT(app.Deposit)))
	sb.WriteString(ufmt.Sprintf("**Applied at block:** %d\n", app.AppliedAt))
	sb.WriteString(ufmt.Sprintf("**Attempt #:** %d\n\n", app.ApplyCount))
	sb.WriteString("## Bio\n\n")
	sb.WriteString(sanitizeForRender(app.Bio) + "\n\n")
	sb.WriteString("## Skills\n\n")
	sb.WriteString(sanitizeForRender(app.Skills) + "\n")

	return sb.String()
}

// ── Helpers ──────────────────────────────────────────────────

// sanitizeForRender strips markdown-sensitive characters to prevent injection.
func sanitizeForRender(s string) string {
	var out strings.Builder
	for _, c := range s {
		switch c {
		case '[', ']', '(', ')', '#', '*', '`', '!', '<', '>', '|', '\\', '_', '~', '\n', '\r', '\t':
			continue
		default:
			out.WriteRune(c)
		}
	}
	return out.String()
}

func assertCallerIsAdmin() {
	caller := unsafe.PreviousRealm().Address()
	if _, exists := admins.Get(caller.String()); !exists {
		panic("unauthorized: caller " + caller.String() + " is not an admin")
	}
}

func assertCallerIsOwner() {
	caller := unsafe.PreviousRealm().Address()
	if caller != owner {
		panic("unauthorized: caller " + caller.String() + " is not the owner")
	}
}

func assertValidAddress(addr address) {
	if addr == "" {
		panic("address cannot be empty")
	}
}

func getApplyCount(addr address) int {
	val, exists := applyCount.Get(addr.String())
	if !exists {
		return 0
	}
	return val.(int)
}

func formatGNOT(ugnot int64) string {
	gnot := ugnot / 1_000_000
	remainder := ugnot % 1_000_000
	if remainder == 0 {
		return strconv.FormatInt(gnot, 10)
	}
	return ufmt.Sprintf("%d.%06d", gnot, remainder)
}

package memba_dao_channels_v2

// memba_dao_channels — Social feed realm for MembaDAO.
//
// Provides Discord-like channels with threads, replies, and moderation.
// The Render() output MUST match the regex patterns in parser.ts (frontend).
//
// Render() contract (from parser.ts):
//
//   Home — Render(""):
//     # BoardName
//     description
//     ## Channels
//     - [#name](:_channel/name) 📢 (N threads)
//
//   Channel — Render("channelName"):
//     # #channelName
//     ### [Title](:channel/id)
//     by g1addr... | N replies | block H
//
//   Thread — Render("channel/id"):
//     # Title
//     body
//     ---
//     *Posted by g1addr at block H*
//     ## Replies
//     **g1addr...** (block H)
//     reply body
//     ---
//
//   ACL — Render("__acl/channel"):
//     read:role1,role2
//     write:role1,role2,role3
//     type:text
//
// Security:
//   - All write operations require membership (AddMember by owner)
//   - PostThread/PostReply check caller's roles against channel WriteRoles
//   - CreateChannel/RemoveThread restricted to owner only
//   - FlagThread requires membership (prevents sybil flagging by non-members)
//   - EditThread/DeleteThread require membership + original author check
//
// Moderation: flag → threshold (3) → auto-hide → DAO vote → remove

import (
	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"
)

// ── Constants ────────────────────────────────────────────────

const (
	MaxPostLen        = 5000
	MaxTitleLen       = 200
	MaxChannels       = 20
	MaxThreadsPerChan = 500
	FlagThreshold     = 3 // flags before auto-hide

	// AAA-1 B1 — render-DoS bounds for replies (mirrors MaxThreadsPerChan).
	// renderThread must never iterate the monotonic reply counter (post+delete
	// reply spam would inflate it without bound → unbounded render scan →
	// thread permanently unrenderable past maxGasQuery). The live-reply index
	// (replyLive/replyLiveIDs) caps the live set, and renderThread paginates a
	// fixed window over it, so render cost is bounded regardless of churn.
	MaxRepliesPerThread = 500 // live (non-deleted) replies per thread
	ReplyPageSize       = 50  // replies rendered per page
)

// ── Types ────────────────────────────────────────────────────

type ChannelType string

const (
	ChannelText          ChannelType = "text"
	ChannelAnnouncements ChannelType = "announcements"
	ChannelReadonly      ChannelType = "readonly"
)

type Channel struct {
	Name        string
	Description string
	Type        ChannelType
	Archived    bool
	ReadRoles   []string // roles that can read
	WriteRoles  []string // roles that can write
}

type Thread struct {
	ID        uint64
	Channel   string
	Title     string
	Body      string
	Author    address
	BlockH    int64
	Edited    bool
	EditedAt  int64
	Deleted   bool
	FlagCount int
	Hidden    bool
}

type Reply struct {
	ID       uint64
	ThreadID uint64
	Channel  string
	Body     string
	Author   address
	BlockH   int64
	Edited   bool
}

// ── State ────────────────────────────────────────────────────

var (
	channels      *avl.Tree // name -> *Channel
	threads       *avl.Tree // "channel/id" -> *Thread
	replies       *avl.Tree // "channel/threadId/replyId" -> *Reply
	threadCount   *avl.Tree // channel -> uint64 (next thread ID, monotonic)
	threadLive    *avl.Tree // channel -> uint64 (currently live (non-deleted) threads)
	threadLiveIDs *avl.Tree // channel -> []uint64 (live thread IDs, ascending) — bounds renderChannel
	replyCount    *avl.Tree // "channel/threadId" -> uint64 (next reply ID, monotonic)
	replyLive     *avl.Tree // "channel/threadId" -> uint64 (currently live (non-deleted) replies)
	replyLiveIDs  *avl.Tree // "channel/threadId" -> []uint64 (live reply IDs, ascending) — bounds renderThread
	threadTomb    *avl.Tree // channel -> []uint64 (soft-deleted thread IDs awaiting hard-GC via SweepTombstones) — B2
	flags         *avl.Tree // "channel/threadId" -> *avl.Tree (flagger addr -> bool)
	channelOrder  []string  // ordered channel names

	// Membership: address -> comma-separated roles (e.g., "admin,dev")
	members *avl.Tree
	paused  bool
	// Owner is set at package load time via OriginCaller() — this captures the
	// deployer address (samcrew-core-test1 multisig on testnet).
	owner = unsafe.OriginCaller()
)

func init() {
	channels = avl.NewTree()
	threads = avl.NewTree()
	replies = avl.NewTree()
	threadCount = avl.NewTree()
	threadLive = avl.NewTree()
	threadLiveIDs = avl.NewTree()
	replyCount = avl.NewTree()
	replyLive = avl.NewTree()
	replyLiveIDs = avl.NewTree()
	threadTomb = avl.NewTree()
	flags = avl.NewTree()
	channelOrder = []string{}
	members = avl.NewTree()
	members.Set(owner.String(), "admin")

	// Default channels matching MEMBA_DAO_CHANNELS in config.ts
	addChannel("general", "General discussion for all members", ChannelText,
		[]string{"admin", "dev", "ops", "member"}, []string{"admin", "dev", "ops", "member"})
	addChannel("announcements", "Official MembaDAO announcements — admin-write-only", ChannelAnnouncements,
		[]string{"admin", "dev", "ops", "member"}, []string{"admin"})
	addChannel("feature-requests", "Propose and discuss new features", ChannelText,
		[]string{"admin", "dev", "ops", "member"}, []string{"admin", "dev", "ops", "member"})
	addChannel("support", "Help and troubleshooting", ChannelText,
		[]string{"admin", "dev", "ops", "member"}, []string{"admin", "dev", "ops", "member"})
	addChannel("extensions", "Plugin and extension development", ChannelText,
		[]string{"admin", "dev", "ops", "member"}, []string{"admin", "dev", "member"})
	addChannel("partnerships", "Collaboration and partnership proposals", ChannelText,
		[]string{"admin", "dev", "ops", "member"}, []string{"admin", "dev", "ops", "member"})
}

// ── Channel Management ───────────────────────────────────────

func addChannel(name, description string, ctype ChannelType, readRoles, writeRoles []string) {
	ch := &Channel{
		Name:        name,
		Description: description,
		Type:        ctype,
		Archived:    false,
		ReadRoles:   readRoles,
		WriteRoles:  writeRoles,
	}
	channels.Set(name, ch)
	threadCount.Set(name, uint64(0))
	threadLive.Set(name, uint64(0))
	channelOrder = append(channelOrder, name)
}

// ── Membership Management ───────────────────────────────────

// AddMember adds an address with specified roles. Only the owner can call this.
// roles is a comma-separated list (e.g., "admin,dev" or "member").
func AddMember(cur realm, addr address, roles string) {
	assertCallerIsOwner()
	if addr == "" {
		panic("address cannot be empty")
	}
	if len(roles) == 0 {
		panic("roles cannot be empty")
	}
	if !isValidRoles(roles) {
		panic("invalid roles: must be comma-separated alphanumeric only")
	}
	members.Set(addr.String(), roles)

	chain.Emit("MemberAdded",
		"address", addr.String(),
		"roles", roles,
	)
}

// RemoveMember removes an address from the membership. Only the owner can call this.
func RemoveMember(cur realm, addr address) {
	assertCallerIsOwner()
	if addr == owner {
		panic("cannot remove owner")
	}
	if _, exists := members.Get(addr.String()); !exists {
		panic("address is not a member: " + addr.String())
	}
	members.Remove(addr.String())

	chain.Emit("MemberRemoved", "address", addr.String())
}

// UpdateMemberRoles updates the roles for an existing member. Only the owner can call this.
func UpdateMemberRoles(cur realm, addr address, newRoles string) {
	assertCallerIsOwner()
	if _, exists := members.Get(addr.String()); !exists {
		panic("address is not a member: " + addr.String())
	}
	if len(newRoles) == 0 {
		panic("roles cannot be empty")
	}
	if !isValidRoles(newRoles) {
		panic("invalid roles: must be comma-separated alphanumeric only")
	}
	members.Set(addr.String(), newRoles)

	chain.Emit("MemberRolesUpdated", "address", addr.String(), "roles", newRoles)
}

// TransferOwnership transfers realm ownership to a new address. Only the current owner can call this.
// The new owner gets "admin" added to their existing roles (not overwritten).
// The old owner is demoted from "admin" to "member".
func TransferOwnership(cur realm, newOwner address) {
	assertCallerIsOwner()
	if newOwner == "" {
		panic("address cannot be empty")
	}
	if newOwner == owner {
		panic("new owner is the same as current owner")
	}
	prevOwner := owner
	// Preserve existing roles for new owner, ensure they have admin
	existingRoles := GetMemberRoles(newOwner)
	if existingRoles == "" {
		members.Set(newOwner.String(), "admin")
	} else if !hasRole(newOwner, "admin") {
		members.Set(newOwner.String(), existingRoles+",admin")
	}
	// Remove "admin" from old owner's roles, keep other roles.
	// If no roles remain, set to "member".
	oldRoles := GetMemberRoles(owner)
	var kept []string
	for _, r := range strings.Split(oldRoles, ",") {
		r = strings.TrimSpace(r)
		if r != "admin" && r != "" {
			kept = append(kept, r)
		}
	}
	if len(kept) == 0 {
		members.Set(owner.String(), "member")
	} else {
		members.Set(owner.String(), strings.Join(kept, ","))
	}
	owner = newOwner

	chain.Emit("OwnershipTransferred",
		"previousOwner", prevOwner.String(),
		"newOwner", newOwner.String(),
	)
}

// SyncMembers allows the owner to batch-sync membership from the DAO.
// addresses and rolesList are comma-separated, with roles pipe-delimited per address.
// Example: SyncMembers("g1a,g1b", "admin,dev|member")
func SyncMembers(cur realm, addresses string, rolesList string) {
	assertCallerIsOwner()
	addrs := strings.Split(addresses, ",")
	roles := strings.Split(rolesList, "|")
	if len(addrs) != len(roles) {
		panic("addresses and roles count mismatch")
	}
	synced := 0
	for i, addr := range addrs {
		addr = strings.TrimSpace(addr)
		if addr == "" {
			continue
		}
		role := strings.TrimSpace(roles[i])
		if !isValidRoles(role) {
			panic("invalid roles in entry " + strconv.Itoa(i))
		}
		members.Set(addr, role)
		synced++
	}

	chain.Emit("MembersSynced", "count", strconv.Itoa(synced))
}

// PurgeNonMembers removes all members not in the provided comma-separated list.
// The owner is never purged.
func PurgeNonMembers(cur realm, keepAddresses string) {
	assertCallerIsOwner()
	keep := make(map[string]bool)
	for _, addr := range strings.Split(keepAddresses, ",") {
		keep[strings.TrimSpace(addr)] = true
	}
	keep[owner.String()] = true // owner is never purged
	var toRemove []string
	members.Iterate("", "", func(key string, _ interface{}) bool {
		if !keep[key] {
			toRemove = append(toRemove, key)
		}
		return false
	})
	for _, addr := range toRemove {
		members.Remove(addr)
	}

	chain.Emit("MembersPurged", "count", strconv.Itoa(len(toRemove)))
}

// IsMember returns whether an address is a member.
func IsMember(addr address) bool {
	_, exists := members.Get(addr.String())
	return exists
}

// GetMemberRoles returns the roles for a member (comma-separated) or empty string.
func GetMemberRoles(addr address) string {
	val, exists := members.Get(addr.String())
	if !exists {
		return ""
	}
	return val.(string)
}

// GetOwner returns the current realm owner address.
func GetOwner() address {
	return owner
}

// ── Emergency Pause ────────────────────────────────────────
//
// Pause policy (AAA-1 B3 — one policy, enforced everywhere):
//   While paused, every member-facing content write is blocked via
//   assertNotPaused() — PostThread, PostReply, EditThread, DeleteThread/Reply,
//   FlagThread, RemoveThread/Reply, and SweepTombstones.
//
//   Owner-only governance (AddMember/RemoveMember/UpdateMemberRoles/SyncMembers/
//   PurgeNonMembers/TransferOwnership/CreateChannel) is intentionally NOT gated:
//   pause halts user activity during an incident, but the owner must stay able to
//   fix membership/ownership while paused. This realm holds no funds, so there is
//   no value-exit exemption to carve out.

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

func PauseRealm(cur realm) {
	assertCallerIsOwner()
	paused = true
	chain.Emit("RealmPaused", "by", owner.String())
}

func UnpauseRealm(cur realm) {
	assertCallerIsOwner()
	paused = false
	chain.Emit("RealmUnpaused", "by", owner.String())
}

func IsPaused() bool { return paused }

// ── Channel Management ───────────────────────────────────────

// CreateChannel adds a new channel. Only the owner (admin) can create channels.
func CreateChannel(cur realm, name, description string, ctype string) {
	assertCallerIsOwner()

	if len(channelOrder) >= MaxChannels {
		panic(ufmt.Sprintf("max channels reached: %d", MaxChannels))
	}
	if _, exists := channels.Get(name); exists {
		panic("channel already exists: " + name)
	}
	if !isValidChannelName(name) {
		panic("invalid channel name: must be 1-50 lowercase alphanumeric characters or hyphens, no leading underscore")
	}

	ct := ChannelText
	switch ctype {
	case "announcements":
		ct = ChannelAnnouncements
	case "readonly":
		ct = ChannelReadonly
	}

	addChannel(name, description, ct,
		[]string{"admin", "dev", "ops", "member"},
		[]string{"admin", "dev", "ops", "member"})

	chain.Emit("ChannelCreated", "name", name, "type", string(ct))
}

// ── Post Management ─────────────────────────────────────────

// PostThread creates a new thread in a channel.
// Caller must be a member with a role listed in the channel's WriteRoles.
func PostThread(cur realm, channel, title, body string) uint64 {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	// Validate membership and channel write access
	ch := getChannel(channel)
	assertCallerHasWriteAccess(caller, ch)
	if ch.Archived {
		panic("channel is archived")
	}
	// Cap on LIVE (non-deleted) threads so deleted threads free up slots.
	if getLiveThreadCount(channel) >= MaxThreadsPerChan {
		panic(ufmt.Sprintf("channel live thread limit reached: %d — delete old threads to make room", MaxThreadsPerChan))
	}
	if len(title) == 0 || len(title) > MaxTitleLen {
		panic(ufmt.Sprintf("title must be 1-%d characters", MaxTitleLen))
	}
	if len(body) > MaxPostLen {
		panic(ufmt.Sprintf("body too long: %d/%d chars", len(body), MaxPostLen))
	}

	// Get next ID
	nextID := getThreadCount(channel)
	key := channel + "/" + strconv.FormatUint(nextID, 10)

	t := &Thread{
		ID:      nextID,
		Channel: channel,
		Title:   title,
		Body:    body,
		Author:  caller,
		BlockH:  runtime.ChainHeight(),
	}
	threads.Set(key, t)
	threadCount.Set(channel, nextID+1)
	threadLive.Set(channel, getLiveThreadCount(channel)+1)
	addLiveThreadID(channel, nextID)
	replyCount.Set(key, uint64(0))

	chain.Emit("ThreadPosted",
		"channel", channel,
		"threadId", strconv.FormatUint(nextID, 10),
		"author", caller.String(),
	)

	return nextID
}

// PostReply adds a reply to a thread.
// Caller must be a member with a role listed in the channel's WriteRoles.
func PostReply(cur realm, channel string, threadID uint64, body string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	// Validate membership and channel write access
	ch := getChannel(channel)
	assertCallerHasWriteAccess(caller, ch)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	tval, texists := threads.Get(threadKey)
	if !texists {
		panic("thread not found")
	}
	thread := tval.(*Thread)
	if thread.Deleted {
		panic("cannot reply to a deleted thread")
	}
	if thread.Hidden {
		panic("cannot reply to a hidden thread")
	}

	if len(body) == 0 || len(body) > MaxPostLen {
		panic(ufmt.Sprintf("reply must be 1-%d characters", MaxPostLen))
	}

	// B1: bound the LIVE reply set so renderThread stays under the gas budget.
	// Deleting replies frees slots (mirrors MaxThreadsPerChan / getLiveThreadCount).
	if getLiveReplyCount(threadKey) >= MaxRepliesPerThread {
		panic(ufmt.Sprintf("thread reply limit reached: %d — older replies must be removed", MaxRepliesPerThread))
	}

	nextReplyID := getReplyCount(threadKey)
	replyKey := threadKey + "/" + strconv.FormatUint(nextReplyID, 10)

	r := &Reply{
		ID:       nextReplyID,
		ThreadID: threadID,
		Channel:  channel,
		Body:     body,
		Author:   caller,
		BlockH:   runtime.ChainHeight(),
	}
	replies.Set(replyKey, r)
	replyCount.Set(threadKey, nextReplyID+1)
	// Track the live reply so renderThread iterates only live IDs (bounded set),
	// never the monotonic counter.
	addLiveReplyID(threadKey, nextReplyID)
	replyLive.Set(threadKey, getLiveReplyCount(threadKey)+1)

	chain.Emit("ReplyPosted",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"replyId", strconv.FormatUint(nextReplyID, 10),
		"author", caller.String(),
	)
}

// dropReply hard-removes a reply: deletes the node (storage reclaimed — B2),
// drops it from the live index, and decrements the live count. Shared by
// DeleteReply and RemoveReply. renderThread only walks the live index, so a
// removed reply is never looked up — no tombstone is needed.
func dropReply(threadKey, replyKey string, replyID uint64) {
	replies.Remove(replyKey)
	removeLiveReplyID(threadKey, replyID)
	if live := getLiveReplyCount(threadKey); live > 0 {
		replyLive.Set(threadKey, live-1)
	}
}

// DeleteReply lets the reply's author delete it. Caller must be a member and the
// original author. The reply node is hard-removed (B2 state-shrink) and a slot is
// freed under MaxRepliesPerThread (B1).
func DeleteReply(cur realm, channel string, threadID, replyID uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	replyKey := threadKey + "/" + strconv.FormatUint(replyID, 10)
	rval, exists := replies.Get(replyKey)
	if !exists {
		panic("reply not found")
	}
	if rval.(*Reply).Author != caller {
		panic("only the author can delete")
	}

	dropReply(threadKey, replyKey, replyID)

	chain.Emit("ReplyDeleted",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"replyId", strconv.FormatUint(replyID, 10),
		"author", caller.String(),
	)
}

// RemoveReply permanently removes a reply (moderation — admin role only). Hard-
// removes the node like DeleteReply, bounding renderThread (B1) + reclaiming
// storage (B2).
func RemoveReply(cur realm, channel string, threadID, replyID uint64) {
	assertCallerIsAdminRole()
	caller := unsafe.PreviousRealm().Address()

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	replyKey := threadKey + "/" + strconv.FormatUint(replyID, 10)
	if _, exists := replies.Get(replyKey); !exists {
		panic("reply not found")
	}

	dropReply(threadKey, replyKey, replyID)

	chain.Emit("ReplyRemoved",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"replyId", strconv.FormatUint(replyID, 10),
		"admin", caller.String(),
	)
}

// EditThread allows the original author to edit their thread. Caller must be a member.
func EditThread(cur realm, channel string, threadID uint64, newBody string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if t.Author != caller {
		panic("only the author can edit")
	}
	if t.Deleted {
		panic("cannot edit a deleted thread")
	}
	if t.Hidden {
		panic("cannot edit a hidden thread")
	}
	if len(newBody) > MaxPostLen {
		panic("body too long")
	}

	t.Body = newBody
	t.Edited = true
	t.EditedAt = runtime.ChainHeight()
	threads.Set(threadKey, t)

	chain.Emit("ThreadEdited",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"author", caller.String(),
	)
}

// DeleteThread soft-deletes a thread (marks as deleted). Caller must be a member and the original author.
func DeleteThread(cur realm, channel string, threadID uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)

	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if t.Author != caller {
		panic("only the author can delete")
	}
	if t.Deleted {
		panic("thread already deleted")
	}

	t.Deleted = true
	t.Title = "[Deleted]"
	t.Body = ""
	threads.Set(threadKey, t)
	// Free a slot for new threads
	live := getLiveThreadCount(channel)
	if live > 0 {
		threadLive.Set(channel, live-1)
	}
	removeLiveThreadID(channel, threadID)
	enqueueThreadTomb(channel, threadID) // B2: queue for hard-GC via SweepTombstones

	chain.Emit("ThreadDeleted",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"author", caller.String(),
	)
}

// ── Moderation ──────────────────────────────────────────────

// FlagThread flags a thread for moderation review.
// After FlagThreshold flags, the thread is auto-hidden.
// Caller must be a member (any role) to flag content.
func FlagThread(cur realm, channel string, threadID uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	assertCallerIsMember(caller)
	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)

	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if t.Deleted {
		panic("cannot flag a deleted thread")
	}
	if t.Hidden {
		panic("thread is already hidden")
	}

	// Track unique flaggers
	var flagTree *avl.Tree
	if fval, fexists := flags.Get(threadKey); fexists {
		flagTree = fval.(*avl.Tree)
	} else {
		flagTree = avl.NewTree()
	}

	if _, already := flagTree.Get(caller.String()); already {
		panic("already flagged")
	}
	flagTree.Set(caller.String(), true)
	flags.Set(threadKey, flagTree)

	// Update thread flag count and auto-hide.
	// Dynamic threshold: max(FlagThreshold, 5% of members), scales with DAO size.
	t.FlagCount = flagTree.Size()
	dynamicThreshold := FlagThreshold
	fivePct := members.Size() / 20
	if fivePct > dynamicThreshold {
		dynamicThreshold = fivePct
	}
	wasHidden := t.Hidden
	if t.FlagCount >= dynamicThreshold {
		t.Hidden = true
	}
	threads.Set(threadKey, t)

	chain.Emit("ThreadFlagged",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"flagger", caller.String(),
		"flagCount", strconv.Itoa(t.FlagCount),
	)
	if !wasHidden && t.Hidden {
		chain.Emit("ThreadAutoHidden",
			"channel", channel,
			"threadId", strconv.FormatUint(threadID, 10),
		)
	}
}

// UnhideThread allows the owner or an admin to clear flags and un-hide a thread.
func UnhideThread(cur realm, channel string, threadID uint64) {
	assertCallerIsAdminRole()
	caller := unsafe.PreviousRealm().Address()
	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)

	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}
	t := val.(*Thread)
	t.Hidden = false
	t.FlagCount = 0
	threads.Set(threadKey, t)
	// Clear flag tree
	flags.Remove(threadKey)

	chain.Emit("ThreadUnhidden",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"admin", caller.String(),
	)
}

// RemoveThread permanently removes a thread (moderation action — admin role only).
func RemoveThread(cur realm, channel string, threadID uint64) {
	assertCallerIsAdminRole()
	caller := unsafe.PreviousRealm().Address()
	threadKey := channel + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		panic("thread not found")
	}

	t := val.(*Thread)
	if !t.Deleted {
		live := getLiveThreadCount(channel)
		if live > 0 {
			threadLive.Set(channel, live-1)
		}
		removeLiveThreadID(channel, threadID)
		enqueueThreadTomb(channel, threadID) // B2: queue for hard-GC (skip if already tombstoned)
	}
	t.Deleted = true
	t.Hidden = true
	t.Title = "[Removed by moderation]"
	t.Body = ""
	threads.Set(threadKey, t)

	chain.Emit("ThreadRemoved",
		"channel", channel,
		"threadId", strconv.FormatUint(threadID, 10),
		"admin", caller.String(),
	)
}

// SweepTombstones hard-removes up to `limit` soft-deleted threads in a channel
// (and all of their remaining reply state), reclaiming AVL storage so that
// post+delete spam can no longer accrete permanent state (B2).
//
// Permissionless GC by design: anyone may call it. Released storage deposits go
// to the calling tx per the chain's deposit policy (an explicit caller bounty);
// on restricted-denom chains (e.g. test12/test13 `restricted_denoms=["ugnot"]`)
// they route to the StorageFeeCollector instead — so this is a state-shrink/
// hygiene primitive, not a user-refund path (see plan B2 / Q11).
//
// Bounded + idempotent: each soft-deleted thread holds at most
// MaxRepliesPerThread reply nodes, so keep `limit` small (1–5) to stay well
// within block gas; re-running drains the next batch and stops at 0.
// Returns the number of threads swept.
func SweepTombstones(cur realm, channel string, limit int) int {
	assertNotPaused()
	if limit <= 0 {
		return 0
	}

	tomb := getThreadTomb(channel)
	n := limit
	if n > len(tomb) {
		n = len(tomb)
	}

	for i := 0; i < n; i++ {
		threadKey := channel + "/" + strconv.FormatUint(tomb[i], 10)
		// Collect-then-remove: read the live reply IDs (a stored slice) and remove
		// each reply node — we never iterate the tree we mutate (AVL footgun).
		for _, rid := range getLiveReplyIDs(threadKey) {
			replies.Remove(threadKey + "/" + strconv.FormatUint(rid, 10))
		}
		replyLiveIDs.Remove(threadKey)
		replyLive.Remove(threadKey)
		replyCount.Remove(threadKey)
		flags.Remove(threadKey)
		threads.Remove(threadKey)
	}

	// Drop the processed prefix; copy the tail into a fresh slice to avoid aliasing.
	remaining := append([]uint64{}, tomb[n:]...)
	if len(remaining) == 0 {
		threadTomb.Remove(channel)
	} else {
		threadTomb.Set(channel, remaining)
	}

	if n > 0 {
		chain.Emit("TombstonesSwept",
			"channel", channel,
			"count", strconv.Itoa(n),
		)
	}
	return n
}

// GetTombstoneCount returns how many soft-deleted threads in a channel are still
// awaiting hard-GC (read-only; lets ops/indexers decide when to call SweepTombstones).
func GetTombstoneCount(channel string) int {
	return len(getThreadTomb(channel))
}

// ── Render ───────────────────────────────────────────────────
// CRITICAL: Output format MUST match parser.ts regex patterns.

func Render(path string) string {
	if path == "" {
		return renderHome()
	}
	if strings.HasPrefix(path, "__acl/") {
		channelName := strings.TrimPrefix(path, "__acl/")
		return renderACL(channelName)
	}
	if strings.HasPrefix(path, "__member/") {
		addr := strings.TrimPrefix(path, "__member/")
		roles := GetMemberRoles(address(addr))
		if roles == "" {
			return "not found"
		}
		return "roles:" + roles
	}
	if strings.HasPrefix(path, "_channel/") {
		channelName := strings.TrimPrefix(path, "_channel/")
		return renderChannel(channelName)
	}

	// Check for "channel/threadId" pattern, optionally with a "?page=N" suffix
	// for reply pagination (B1).
	parts := strings.SplitN(path, "/", 2)
	if len(parts) == 2 {
		idPart := parts[1]
		page := uint64(0)
		if qi := strings.IndexByte(idPart, '?'); qi >= 0 {
			page = parsePageQuery(idPart[qi+1:])
			idPart = idPart[:qi]
		}
		threadID, err := strconv.ParseUint(idPart, 10, 64)
		if err == nil {
			return renderThread(parts[0], threadID, page)
		}
	}

	// Try as channel name directly
	if _, exists := channels.Get(path); exists {
		return renderChannel(path)
	}

	return "# 404\nPage not found: " + path
}

// renderHome produces the board home page.
// Format: parser.ts parseBoardHome() expects:
//   - [#name](:_channel/name) 📢 (N threads)
func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# MembaDAO Channels\n\n")
	sb.WriteString("Community discussion channels for the Memba ecosystem.\n\n")
	sb.WriteString(ufmt.Sprintf("**Owner:** %s | **Members:** %d\n\n", owner, members.Size()))
	sb.WriteString("## Channels\n\n")

	for _, name := range channelOrder {
		val, exists := channels.Get(name)
		if !exists {
			continue
		}
		ch := val.(*Channel)
		if ch.Archived {
			continue
		}

		count := getThreadCount(name)
		typeIcon := ""
		switch ch.Type {
		case ChannelAnnouncements:
			typeIcon = " 📢"
		case ChannelReadonly:
			typeIcon = " 🔒"
		}

		sb.WriteString(ufmt.Sprintf("- [#%s](:_channel/%s)%s (%d threads)\n",
			name, name, typeIcon, count))
	}

	return sb.String()
}

// renderChannel produces a channel's thread list.
// Format: parser.ts parseThreadList() expects:
//   ### [Title](:channel/id)
//   by g1addr... | N replies | block H
func renderChannel(channelName string) string {
	if _, exists := channels.Get(channelName); !exists {
		return "# 404\nChannel not found: " + channelName
	}

	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# #%s\n\n", channelName))

	// Iterate the LIVE thread-ID index (bounded by getLiveThreadCount), newest
	// first. Never loop over the monotonic threadCount — a post+delete spam
	// loop inflates it without bound (gas DoS); deleted IDs are not in this index.
	ids := getLiveThreadIDs(channelName)
	if len(ids) == 0 {
		sb.WriteString("*No threads yet. Be the first to post!*\n")
		return sb.String()
	}

	for i := len(ids) - 1; i >= 0; i-- {
		threadKey := channelName + "/" + strconv.FormatUint(ids[i], 10)
		val, exists := threads.Get(threadKey)
		if !exists {
			continue
		}
		t := val.(*Thread)
		if t.Hidden || t.Deleted {
			continue
		}

		// Count live (non-deleted) replies — matches what renderThread shows.
		rCount := getLiveReplyCount(threadKey)
		authorStr := truncAddr(t.Author)

		sb.WriteString(ufmt.Sprintf("### [%s](:%s/%d)\n", sanitizeForRender(t.Title), channelName, t.ID))
		sb.WriteString(ufmt.Sprintf("by %s | %d replies | block %d\n\n", authorStr, rCount, t.BlockH))
	}

	return sb.String()
}

// renderThread produces a single thread with replies.
// Format: parser.ts parseThreadDetail() expects:
//   # Title
//   body
//   ---
//   *Posted by g1addr at block H* *(edited at block M)*
//   ## Replies
//   **g1addr...** (block H) *(edited)*
//   reply body
//   ---
func renderThread(channelName string, threadID, page uint64) string {
	threadKey := channelName + "/" + strconv.FormatUint(threadID, 10)
	val, exists := threads.Get(threadKey)
	if !exists {
		return "# 404\nThread not found"
	}

	t := val.(*Thread)

	// Suppress content for hidden (flag-auto-hidden or admin-hidden) and
	// soft-deleted threads. renderChannel omits these from the list, but the
	// direct path Render("channel/id") must not leak the original title/body.
	if t.Hidden || t.Deleted {
		return "# Thread unavailable\n\n*This thread has been hidden or removed.*\n"
	}

	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# %s\n\n", sanitizeForRender(t.Title)))
	sb.WriteString(sanitizeForRender(t.Body) + "\n\n")
	sb.WriteString("---\n\n")
	sb.WriteString(ufmt.Sprintf("*Posted by %s at block %d*", string(t.Author), t.BlockH))
	if t.Edited {
		sb.WriteString(ufmt.Sprintf(" *(edited at block %d)*", t.EditedAt))
	}
	sb.WriteString("\n\n")

	// B1: render only LIVE replies (bounded by MaxRepliesPerThread), paginated to
	// a fixed window so render cost is O(ReplyPageSize) regardless of total churn.
	// Never iterate the monotonic replyCount — that is the render-DoS surface.
	liveIDs := getLiveReplyIDs(threadKey) // ascending (oldest→newest), <= MaxRepliesPerThread
	total := uint64(len(liveIDs))
	if total > 0 {
		totalPages := (total + ReplyPageSize - 1) / ReplyPageSize
		// page 1 = oldest window … totalPages = newest. Default (0) and any
		// out-of-range value snap to the newest page (most-recent replies).
		if page == 0 || page > totalPages {
			page = totalPages
		}
		start := (page - 1) * ReplyPageSize
		end := start + ReplyPageSize
		if end > total {
			end = total
		}

		sb.WriteString("## Replies\n\n")
		if totalPages > 1 {
			sb.WriteString(ufmt.Sprintf(
				"*Showing %d–%d of %d • page %d/%d — older: `?page=%d`, newer: `?page=%d`*\n\n",
				start+1, end, total, page, totalPages, pageClamp(page-1, totalPages), pageClamp(page+1, totalPages)))
		}

		for i := start; i < end; i++ {
			replyKey := threadKey + "/" + strconv.FormatUint(liveIDs[i], 10)
			rval, rexists := replies.Get(replyKey)
			if !rexists {
				continue // live index never points at a removed reply, but stay safe
			}
			r := rval.(*Reply)
			authorStr := truncAddr(r.Author)
			editStr := ""
			if r.Edited {
				editStr = " *(edited)*"
			}
			sb.WriteString(ufmt.Sprintf("**%s** (block %d)%s\n\n", authorStr, r.BlockH, editStr))
			sb.WriteString(sanitizeForRender(r.Body) + "\n\n")
			sb.WriteString("---\n\n")
		}
	}

	return sb.String()
}

// parsePageQuery extracts the page number from a "?page=N" query string (also
// tolerates extra &-separated params). Returns 0 (= default/newest) on absence
// or parse error.
func parsePageQuery(q string) uint64 {
	for _, kv := range strings.Split(q, "&") {
		if strings.HasPrefix(kv, "page=") {
			if n, err := strconv.ParseUint(strings.TrimPrefix(kv, "page="), 10, 64); err == nil {
				return n
			}
		}
	}
	return 0
}

// pageClamp keeps a page link within [1, totalPages].
func pageClamp(p, totalPages uint64) uint64 {
	if p < 1 {
		return 1
	}
	if p > totalPages {
		return totalPages
	}
	return p
}

// renderACL produces the ACL response for a channel.
// Format: parser.ts parseACL() expects:
//   read:role1,role2
//   write:role1,role2,role3
//   type:text
func renderACL(channelName string) string {
	val, exists := channels.Get(channelName)
	if !exists {
		return "not found"
	}
	ch := val.(*Channel)

	var sb strings.Builder
	sb.WriteString("read:" + strings.Join(ch.ReadRoles, ",") + "\n")
	sb.WriteString("write:" + strings.Join(ch.WriteRoles, ",") + "\n")
	sb.WriteString("type:" + string(ch.Type) + "\n")

	return sb.String()
}

// ── Helpers ──────────────────────────────────────────────────

func getChannel(name string) *Channel {
	val, exists := channels.Get(name)
	if !exists {
		panic("channel not found: " + name)
	}
	return val.(*Channel)
}

func getThreadCount(channel string) uint64 {
	val, exists := threadCount.Get(channel)
	if !exists {
		return 0
	}
	return val.(uint64)
}

// getLiveThreadCount returns the number of non-deleted threads in a channel.
// Unlike getThreadCount (monotonic ID counter), this decreases when threads
// are deleted, so deleted threads free up slots under MaxThreadsPerChan.
func getLiveThreadCount(channel string) uint64 {
	val, exists := threadLive.Get(channel)
	if !exists {
		return 0
	}
	return val.(uint64)
}

// ── Live thread-ID index ─────────────────────────────────────
// renderChannel must iterate only live (non-deleted) thread IDs, never the
// monotonic threadCount: a member can post+delete in a loop to inflate
// threadCount without bound (the live cap only limits live threads), turning
// renderChannel into an unbounded O(threadCount) scan (gas DoS). This index
// stays bounded by getLiveThreadCount (<= MaxThreadsPerChan).

func getLiveThreadIDs(channel string) []uint64 {
	if val, exists := threadLiveIDs.Get(channel); exists {
		return val.([]uint64)
	}
	return nil
}

func addLiveThreadID(channel string, id uint64) {
	threadLiveIDs.Set(channel, append(getLiveThreadIDs(channel), id))
}

func removeLiveThreadID(channel string, id uint64) {
	ids := getLiveThreadIDs(channel)
	for i, x := range ids {
		if x == id {
			threadLiveIDs.Set(channel, append(ids[:i], ids[i+1:]...))
			return
		}
	}
}

// ── Live reply-ID index ──────────────────────────────────────
// Same rationale as the thread index, one level down: renderThread must iterate
// only live reply IDs (bounded by MaxRepliesPerThread), never the monotonic
// replyCount, or a member can post+delete replies in a loop to make a thread
// unrenderable. Keyed by "channel/threadId".

func getLiveReplyCount(threadKey string) uint64 {
	if val, exists := replyLive.Get(threadKey); exists {
		return val.(uint64)
	}
	return 0
}

func getLiveReplyIDs(threadKey string) []uint64 {
	if val, exists := replyLiveIDs.Get(threadKey); exists {
		return val.([]uint64)
	}
	return nil
}

func addLiveReplyID(threadKey string, id uint64) {
	replyLiveIDs.Set(threadKey, append(getLiveReplyIDs(threadKey), id))
}

func removeLiveReplyID(threadKey string, id uint64) {
	ids := getLiveReplyIDs(threadKey)
	for i, x := range ids {
		if x == id {
			replyLiveIDs.Set(threadKey, append(ids[:i], ids[i+1:]...))
			return
		}
	}
}

// ── Thread tombstone queue (B2 hard-GC) ──────────────────────
// Soft-deleted thread IDs awaiting permanent removal by SweepTombstones. A queue
// (not a scan of the threads tree) keeps the sweep O(limit) — it never walks the
// unbounded set of past tombstones.

func getThreadTomb(channel string) []uint64 {
	if val, exists := threadTomb.Get(channel); exists {
		return val.([]uint64)
	}
	return nil
}

func enqueueThreadTomb(channel string, id uint64) {
	threadTomb.Set(channel, append(getThreadTomb(channel), id))
}

func getReplyCount(threadKey string) uint64 {
	val, exists := replyCount.Get(threadKey)
	if !exists {
		return 0
	}
	return val.(uint64)
}

func truncAddr(addr address) string {
	s := string(addr)
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

// isValidRoles validates a comma-separated role list contains only safe characters.
// Allowed: a-z, A-Z, 0-9, hyphen, comma. No spaces, no markdown chars, no null bytes.
func isValidRoles(s string) bool {
	if len(s) > 200 {
		return false
	}
	for _, c := range s {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '-' || c == ',') {
			return false
		}
	}
	return true
}

// sanitizeForRender strips markdown-sensitive characters to prevent injection.
func sanitizeForRender(s string) string {
	var out strings.Builder
	for _, c := range s {
		switch c {
		case '[', ']', '(', ')', '#', '*', '`', '!', '<', '>', '|', '\\', '_', '~', '\n', '\r', '\t':
			continue
		default:
			out.WriteRune(c)
		}
	}
	return out.String()
}

// ── ACL Enforcement ─────────────────────────────────────────

func assertCallerIsOwner() {
	caller := unsafe.PreviousRealm().Address()
	if caller != owner {
		panic("unauthorized: caller " + caller.String() + " is not the owner")
	}
}

func assertCallerIsMember(caller address) {
	if _, exists := members.Get(caller.String()); !exists {
		panic("unauthorized: caller " + caller.String() + " is not a member")
	}
}

// assertCallerHasWriteAccess checks that the caller is a member AND has at least
// one role that matches the channel's WriteRoles.
func assertCallerHasWriteAccess(caller address, ch *Channel) {
	rolesStr, exists := members.Get(caller.String())
	if !exists {
		panic("unauthorized: caller " + caller.String() + " is not a member")
	}

	callerRoles := strings.Split(rolesStr.(string), ",")
	for _, cr := range callerRoles {
		cr = strings.TrimSpace(cr)
		for _, wr := range ch.WriteRoles {
			if cr == wr {
				return // Access granted
			}
		}
	}

	panic("unauthorized: caller " + caller.String() + " lacks write access to channel " + ch.Name)
}

func hasRole(caller address, role string) bool {
	rolesStr, exists := members.Get(caller.String())
	if !exists {
		return false
	}
	callerRoles := strings.Split(rolesStr.(string), ",")
	for _, cr := range callerRoles {
		if strings.TrimSpace(cr) == role {
			return true
		}
	}
	return false
}

// assertCallerIsAdminRole checks that the caller is a member with the "admin" role.
// Used for moderation actions (RemoveThread, UnhideThread) so any admin can moderate,
// not just the single owner.
func assertCallerIsAdminRole() {
	caller := unsafe.PreviousRealm().Address()
	if !hasRole(caller, "admin") {
		panic("unauthorized: caller " + caller.String() + " does not have admin role")
	}
}

// isValidChannelName validates that a channel name contains only
// lowercase alphanumeric characters and hyphens, and does not start with underscore.
func isValidChannelName(name string) bool {
	if len(name) == 0 || len(name) > 50 {
		return false
	}
	if name[0] == '_' {
		return false // Prevent collision with __acl/, __member/ paths
	}
	for _, c := range name {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-') {
			return false
		}
	}
	return true
}

package agent_registry_v2

// Agent Registry — On-chain AI Agent Marketplace for the Memba ecosystem.
//
// Agents self-register with MCP metadata (endpoint, transport, pricing).
// Anyone can query via Render() for agent listings.
// Reviews are stored on-chain with 1-5 star ratings.
// Pay-per-use agents support a prepaid credit system.
//
// Render() contract:
//
//   Home — Render(""):
//     # Memba Agent Registry
//     description
//     ## Agents
//     | ID | Name | Category | Rating | Pricing |
//     | --- | --- | --- | --- | --- |
//     | id | name | category | 4.2 (5) | free |
//
//   Agent — Render("agent/id"):
//     # AgentName
//     description
//     **Category:** category
//     **Creator:** g1addr
//     **Endpoint:** endpoint
//     **Transport:** stdio|sse|streamable-http
//     **Pricing:** free|pay-per-use|subscription
//     **Rating:** 4.2 (5 reviews)
//     ## Capabilities
//     - capability1
//     - capability2
//     ## Reviews
//     **g1addr...** stars (block H)
//     review text
//
//   Stats — Render("stats"):
//     Total agents, total reviews, total calls

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"
)

// ── Constants ────────────────────────────────────────────────

const (
	MaxAgents    = 100
	MaxNameLen   = 100
	MaxDescLen   = 1000
	MaxCapsLen   = 2000
	MaxReviewLen = 500
	// AR-1 render-DoS bound: reviews are sybil-growable (one per address, no cap), and
	// renderAgent previously iterated the entire slice — an attacker could make an agent
	// page unrenderable past the query gas cap. Render only the newest window.
	ReviewRenderMax = 20
	AdminAddress = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0" // samcrew-core-test1 multisig

	// AAA-1 B4 — anti-squat + fund-lock-DoS bounds.
	// MaxAgentsPerCreator caps how many agents one address can register, so a
	// single funded address cannot squat the whole MaxAgents global supply.
	MaxAgentsPerCreator = 10
	// MaxDepositorsPerAgent bounds the distinct depositor set per agent. RemoveAgent
	// refunds EVERY depositor in one transaction (the credits prefix scan below); an
	// unbounded set would make RemoveAgent exceed the block gas budget and become
	// permanently uncallable, locking all deposited funds. At this cap the full
	// refund loop measures ≈3M gas in `gno test` — a small fraction of the block
	// budget, so RemoveAgent stays callable with wide headroom.
	MaxDepositorsPerAgent = 50
)

// ── Types ────────────────────────────────────────────────────

type Agent struct {
	ID           string
	Name         string
	Description  string
	Category     string
	Capabilities string // comma-separated
	Creator      address
	Endpoint     string
	Transport    string // "stdio" | "sse" | "streamable-http"
	Pricing      string // "free" | "pay-per-use" | "subscription"
	PricePerCall int64  // in ugnot (0 if free)
	Version      string
	TotalCalls   int64
	RatingSum    int64
	RatingCount  int64
	BlockH       int64
}

type Review struct {
	Reviewer address
	Rating   int // 1-5
	Comment  string
	BlockH   int64
}

// ── State ────────────────────────────────────────────────────

var (
	agents    *avl.Tree // id -> *Agent
	reviews   *avl.Tree // agentId -> []*Review
	reviewers *avl.Tree // "agentId/addr" -> true (dedup: one review per agent per address)
	credits   *avl.Tree // "agentId/userAddr" -> int64 (prepaid credits in ugnot)
	usage     *avl.Tree // "agentId/userAddr" -> int64 (total calls)
	earnings  *avl.Tree // agentId -> int64 (accumulated creator earnings in ugnot)
	paused    bool
)

func init() {
	agents = avl.NewTree()
	reviews = avl.NewTree()
	reviewers = avl.NewTree()
	credits = avl.NewTree()
	usage = avl.NewTree()
	earnings = avl.NewTree()
}

// ── Emergency Pause ────────────────────────────────────────
//
// Pause policy (AAA-1 B3 — one policy, enforced everywhere):
//   While paused, every state-mutating user operation is blocked
//   (RegisterAgent, UpdateAgent, ReviewAgent, RemoveAgent, DepositCredits,
//   UseCredit, WithdrawEarnings) via assertNotPaused().
//
//   EXEMPTION — RefundCredits is deliberately NOT gated: a user must always be
//   able to reclaim their own deposited principal, even during emergency
//   maintenance. A credit balance only ever equals real ugnot the user sent
//   (DepositCredits) minus what they spent (UseCredit), so refunding it is
//   always safe and never exploit-amplifying. WithdrawEarnings (creator profit,
//   which an exploit could inflate) stays blocked by design.

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

// Pause blocks all state-mutating operations EXCEPT RefundCredits (users keep the
// right to reclaim their own deposits). Admin only. See the pause policy above.
func Pause(cur realm) {
	caller := unsafe.PreviousRealm().Address()
	if caller != address(AdminAddress) {
		panic("only admin can pause")
	}
	paused = true
}

// Unpause resumes normal operations. Admin only.
func Unpause(cur realm) {
	caller := unsafe.PreviousRealm().Address()
	if caller != address(AdminAddress) {
		panic("only admin can unpause")
	}
	paused = false
}

// IsPaused returns the current pause state.
func IsPaused() bool {
	return paused
}

// ── Public Functions ─────────────────────────────────────────

// RegisterAgent registers a new agent in the registry.
func RegisterAgent(
	cur realm,
	id, name, description, category, capabilities,
	endpoint, transport, pricing, version string,
	pricePerCall int64,
) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	if _, exists := agents.Get(id); exists {
		panic("agent ID already exists: " + id)
	}
	if len(id) == 0 || len(id) > 50 {
		panic("ID must be 1-50 characters")
	}
	if !isValidAgentID(id) {
		panic("ID must contain only alphanumeric characters, hyphens, or underscores")
	}
	if len(name) == 0 || len(name) > MaxNameLen {
		panic(ufmt.Sprintf("name must be 1-%d characters", MaxNameLen))
	}
	if len(description) > MaxDescLen {
		panic("description too long")
	}
	if len(capabilities) > MaxCapsLen {
		panic("capabilities too long")
	}
	if len(category) > MaxNameLen {
		panic("category too long")
	}
	if len(endpoint) > MaxDescLen {
		panic("endpoint too long")
	}
	if len(version) > 50 {
		panic("version too long")
	}
	if agents.Size() >= MaxAgents {
		panic("registry full")
	}
	// B4: per-creator cap — stop a single address squatting the global supply.
	if countAgentsByCreator(caller) >= MaxAgentsPerCreator {
		panic("creator agent limit reached")
	}
	if !isValidTransport(transport) {
		panic("transport must be stdio, sse, or streamable-http")
	}
	if !isValidPricing(pricing) {
		panic("pricing must be free, pay-per-use, or subscription")
	}
	if pricePerCall < 0 {
		panic("pricePerCall must be >= 0")
	}

	a := &Agent{
		ID:           id,
		Name:         name,
		Description:  description,
		Category:     category,
		Capabilities: capabilities,
		Creator:      caller,
		Endpoint:     endpoint,
		Transport:    transport,
		Pricing:      pricing,
		PricePerCall: pricePerCall,
		Version:      version,
		BlockH:       runtime.ChainHeight(),
	}
	agents.Set(id, a)
	reviews.Set(id, []*Review{})

	chain.Emit("AgentRegistered",
		"id", id,
		"name", name,
		"creator", caller.String(),
		"pricing", pricing,
	)
}

// UpdateAgent allows the creator to update their agent.
func UpdateAgent(
	cur realm,
	id, description, capabilities, endpoint, version, pricing string,
	pricePerCall int64,
) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	val, exists := agents.Get(id)
	if !exists {
		panic("agent not found: " + id)
	}
	a := val.(*Agent)
	if a.Creator != caller {
		panic("only the creator can update")
	}
	if len(description) > 0 {
		if len(description) > MaxDescLen {
			panic("description too long")
		}
		a.Description = description
	}
	if len(capabilities) > 0 {
		if len(capabilities) > MaxCapsLen {
			panic("capabilities too long")
		}
		a.Capabilities = capabilities
	}
	if len(endpoint) > 0 {
		a.Endpoint = endpoint
	}
	if len(version) > 0 {
		a.Version = version
	}
	if pricePerCall < 0 {
		panic("pricePerCall must be >= 0")
	}
	if len(pricing) > 0 {
		if !isValidPricing(pricing) {
			panic("pricing must be free, pay-per-use, or subscription")
		}
		// Prevent pricing model change when ANY credit entry exists for this agent,
		// including zero-balance entries. This closes the price-lock bypass where
		// the creator drains user balances to 0 then raises the price before the
		// user's next deposit lands.
		if pricing != a.Pricing && hasAnyCreditsEntry(id) {
			panic("cannot change pricing model while credit entries exist for this agent")
		}
		a.Pricing = pricing
	}
	if pricePerCall != a.PricePerCall && hasAnyCreditsEntry(id) {
		panic("cannot change price per call while credit entries exist for this agent")
	}
	a.PricePerCall = pricePerCall
	agents.Set(id, a)

	chain.Emit("AgentUpdated",
		"id", id,
		"creator", caller.String(),
	)
}

// ReviewAgent adds a review for an agent. One review per address per agent.
func ReviewAgent(cur realm, agentId string, rating int, comment string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	val, exists := agents.Get(agentId)
	if !exists {
		panic("agent not found")
	}
	if rating < 1 || rating > 5 {
		panic("rating must be 1-5")
	}
	if len(comment) > MaxReviewLen {
		panic("review too long")
	}

	// Enforce one review per address per agent
	reviewKey := agentId + "/" + caller.String()
	if _, already := reviewers.Get(reviewKey); already {
		panic("already reviewed this agent")
	}
	reviewers.Set(reviewKey, true)

	a := val.(*Agent)
	a.RatingSum += int64(rating)
	a.RatingCount++
	agents.Set(agentId, a)

	rval, _ := reviews.Get(agentId)
	revs := rval.([]*Review)
	revs = append(revs, &Review{
		Reviewer: caller,
		Rating:   rating,
		Comment:  comment,
		BlockH:   runtime.ChainHeight(),
	})
	reviews.Set(agentId, revs)

	chain.Emit("AgentReviewed",
		"agentId", agentId,
		"reviewer", caller.String(),
		"rating", strconv.Itoa(rating),
	)
}

// RemoveAgent removes an agent (admin or creator only).
// All outstanding credits are refunded to their depositors before removal.
func RemoveAgent(cur realm, id string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	val, exists := agents.Get(id)
	if !exists {
		panic("agent not found")
	}
	a := val.(*Agent)
	if a.Creator != caller && caller != address(AdminAddress) {
		panic("only creator or admin can remove")
	}

	// Refund all outstanding credits before removal.
	// Use prefix + "\xff" as exclusive upper bound for the AVL prefix scan —
	// any key starting with "id/" sorts strictly before "id/\xff".
	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	realmAddr := unsafe.CurrentRealm().Address()
	prefix := id + "/"
	var creditsToRefund []string
	credits.Iterate(prefix, prefix+"\xff", func(key string, value interface{}) bool {
		creditsToRefund = append(creditsToRefund, key)
		return false
	})
	for _, key := range creditsToRefund {
		cval, cok := credits.Get(key)
		if !cok {
			continue
		}
		balance := cval.(int64)
		if balance > 0 {
			userAddr := key[len(prefix):]
			// STATE-BEFORE-SEND: zero balance before coin transfer
			credits.Set(key, int64(0))
			bnk.SendCoins(realmAddr, address(userAddr),
				chain.Coins{chain.NewCoin("ugnot", balance)})
		}
	}

	// Pay out the creator's accrued earnings BEFORE deleting the record.
	// UseCredit moves ugnot from credits -> earnings, so these are real funds
	// the realm holds; removing the record without paying would strand them
	// permanently (WithdrawEarnings would then panic "agent not found").
	if earned := GetEarnings(id); earned > 0 {
		earnings.Set(id, int64(0)) // STATE-BEFORE-SEND
		bnk.SendCoins(realmAddr, a.Creator,
			chain.Coins{chain.NewCoin("ugnot", earned)})
	}

	// Clean up orphaned state: earnings and usage entries for this agent
	earnings.Remove(id)
	// Clean up usage entries with this agent prefix
	usagePrefix := id + "/"
	var usageToRemove []string
	usage.Iterate(usagePrefix, usagePrefix+"\xff", func(k string, _ interface{}) bool {
		usageToRemove = append(usageToRemove, k)
		return false
	})
	for _, k := range usageToRemove {
		usage.Remove(k)
	}
	// Also clean up any zero-balance residual credit entries
	var creditsToRemove []string
	credits.Iterate(usagePrefix, usagePrefix+"\xff", func(k string, _ interface{}) bool {
		creditsToRemove = append(creditsToRemove, k)
		return false
	})
	for _, k := range creditsToRemove {
		credits.Remove(k)
	}

	agents.Remove(id)
	reviews.Remove(id)

	chain.Emit("AgentRemoved",
		"id", id,
		"remover", caller.String(),
	)
}

// ── Pay-Per-Use Credit System ────────────────────────────────

// DepositCredits deposits GNOT as prepaid credits for an agent.
// Send ugnot with the transaction to fund the credits.
func DepositCredits(cur realm, agentId string) {
	assertNotPaused()

	// P0 fund-guard: a payable entrypoint MUST be a direct user call. unsafe.OriginSend()
	// reports the tx-level `--send`, credited to the DIRECT message target realm — not to
	// an inner realm reached via a cross-call. Without this guard an attacker deposits
	// through their own intermediary realm (coins land there), this realm credits an amount
	// it never received, then the attacker drains real pooled prepaid credits via
	// RefundCredits/WithdrawEarnings. Requiring a direct user call forces this realm to be
	// the message target, the one case where the OriginSend coins are in its own account.
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("DepositCredits must be a direct user call")
	}

	caller := unsafe.PreviousRealm().Address()
	if _, exists := agents.Get(agentId); !exists {
		panic("agent not found")
	}

	sent := unsafe.OriginSend()
	amount := int64(0)
	for _, coin := range sent {
		if coin.Denom == "ugnot" {
			amount += coin.Amount
		}
	}
	if amount == 0 {
		panic("must send ugnot to deposit credits")
	}

	key := agentId + "/" + caller.String()
	existing := int64(0)
	alreadyDepositor := false
	if val, ok := credits.Get(key); ok {
		existing = val.(int64)
		alreadyDepositor = true
	}
	// B4: bound the distinct depositor set so RemoveAgent's refund loop stays within
	// the gas budget. Existing depositors may always top up; only NEW depositors are
	// capped.
	if !alreadyDepositor && countDepositors(agentId) >= MaxDepositorsPerAgent {
		panic("agent depositor limit reached")
	}
	credits.Set(key, existing+amount)

	chain.Emit("CreditsDeposited",
		"agentId", agentId,
		"user", caller.String(),
		"amount", strconv.FormatInt(amount, 10),
	)
}

// UseCredit deducts one invocation credit. Only the agent creator or admin can call.
// Returns the remaining credits.
func UseCredit(cur realm, agentId, userAddr string) int64 {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	val, exists := agents.Get(agentId)
	if !exists {
		panic("agent not found")
	}
	a := val.(*Agent)

	// Only the agent creator (who runs the MCP backend) or platform admin
	// can deduct credits on behalf of users
	if a.Creator != caller && caller != address(AdminAddress) {
		panic("only agent creator or admin can deduct credits")
	}

	key := agentId + "/" + userAddr
	if a.Pricing == "pay-per-use" && a.PricePerCall > 0 {
		cval, cexists := credits.Get(key)
		if !cexists {
			panic("no credits deposited")
		}
		balance := cval.(int64)
		if balance < a.PricePerCall {
			panic(ufmt.Sprintf("insufficient credits: %d < %d", balance, a.PricePerCall))
		}
		credits.Set(key, balance-a.PricePerCall)

		// Track earnings for creator withdrawal
		earned := int64(0)
		if ev, eok := earnings.Get(agentId); eok {
			earned = ev.(int64)
		}
		earnings.Set(agentId, earned+a.PricePerCall)
	}

	// Track usage
	a.TotalCalls++
	agents.Set(agentId, a)

	uval := int64(0)
	if uv, uok := usage.Get(key); uok {
		uval = uv.(int64)
	}
	usage.Set(key, uval+1)

	remaining := int64(0)
	if rv, rok := credits.Get(key); rok {
		remaining = rv.(int64)
	}

	// B6: every state transition emits a typed event for indexers/agents.
	chain.Emit("CreditUsed",
		"agentId", agentId,
		"user", userAddr,
		"caller", caller.String(),
		"remaining", strconv.FormatInt(remaining, 10),
	)
	return remaining
}

// GetCredits returns the credit balance for a user on an agent.
func GetCredits(agentId, userAddr string) int64 {
	key := agentId + "/" + userAddr
	if val, ok := credits.Get(key); ok {
		return val.(int64)
	}
	return 0
}

// GetUsage returns the total invocation count for a user on an agent.
func GetUsage(agentId, userAddr string) int64 {
	key := agentId + "/" + userAddr
	if val, ok := usage.Get(key); ok {
		return val.(int64)
	}
	return 0
}

// GetEarnings returns accumulated earnings for an agent.
func GetEarnings(agentId string) int64 {
	if val, ok := earnings.Get(agentId); ok {
		return val.(int64)
	}
	return 0
}

// WithdrawEarnings allows the agent creator to withdraw accumulated usage fees.
// Earnings accumulate when UseCredit deducts from user credit balances.
func WithdrawEarnings(cur realm, agentId string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	val, exists := agents.Get(agentId)
	if !exists {
		panic("agent not found")
	}
	a := val.(*Agent)
	if a.Creator != caller {
		panic("only agent creator can withdraw earnings")
	}

	earned := int64(0)
	if ev, eok := earnings.Get(agentId); eok {
		earned = ev.(int64)
	}
	if earned == 0 {
		panic("no earnings to withdraw")
	}

	// STATE-BEFORE-SEND: zero earnings before coin transfer
	earnings.Set(agentId, int64(0))

	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	bnk.SendCoins(
		unsafe.CurrentRealm().Address(),
		caller,
		chain.Coins{chain.NewCoin("ugnot", earned)},
	)

	chain.Emit("EarningsWithdrawn",
		"agentId", agentId,
		"creator", caller.String(),
		"amount", strconv.FormatInt(earned, 10),
	)
}

// RefundCredits refunds remaining credits to the caller.
func RefundCredits(cur realm, agentId string) {
	caller := unsafe.PreviousRealm().Address()
	key := agentId + "/" + caller.String()

	cval, cexists := credits.Get(key)
	if !cexists {
		panic("no credits to refund")
	}
	balance := cval.(int64)
	if balance == 0 {
		panic("zero balance")
	}

	// STATE-BEFORE-SEND: fully REMOVE the entry (not just zero it) so that the
	// pricing lock in UpdateAgent doesn't remain triggered after a full refund.
	credits.Remove(key)

	bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
	bnk.SendCoins(
		unsafe.CurrentRealm().Address(),
		caller,
		chain.Coins{chain.NewCoin("ugnot", balance)},
	)

	chain.Emit("CreditsRefunded",
		"agentId", agentId,
		"user", caller.String(),
		"amount", strconv.FormatInt(balance, 10),
	)
}

// ── Render ───────────────────────────────────────────────────

func Render(path string) string {
	if path == "" {
		return renderHome()
	}
	if path == "stats" {
		return renderStats()
	}
	if strings.HasPrefix(path, "agent/") {
		agentId := strings.TrimPrefix(path, "agent/")
		return renderAgent(agentId)
	}
	return "# 404\nNot found: " + path
}

func renderHome() string {
	var sb strings.Builder
	sb.WriteString("# Memba Agent Registry\n\n")
	sb.WriteString("On-chain AI Agent Marketplace for the Gno ecosystem.\n\n")

	if agents.Size() == 0 {
		sb.WriteString("*No agents registered yet.*\n")
		return sb.String()
	}

	sb.WriteString("## Agents\n\n")
	sb.WriteString("| ID | Name | Category | Rating | Pricing |\n")
	sb.WriteString("| --- | --- | --- | --- | --- |\n")

	agents.Iterate("", "", func(key string, value interface{}) bool {
		a := value.(*Agent)
		rating := "unrated"
		if a.RatingCount > 0 {
			rating = formatRating(a.RatingSum, a.RatingCount)
		}
		pricing := a.Pricing
		if a.Pricing == "pay-per-use" && a.PricePerCall > 0 {
			pricing = ufmt.Sprintf("pay-per-use (%d ugnot)", a.PricePerCall)
		}
		sb.WriteString(ufmt.Sprintf("| %s | [%s](:agent/%s) | %s | %s | %s |\n",
			a.ID, sanitizeForRender(a.Name), a.ID, sanitizeForRender(a.Category), rating, pricing))
		return false
	})

	return sb.String()
}

func renderAgent(id string) string {
	val, exists := agents.Get(id)
	if !exists {
		return "# 404\nAgent not found: " + id
	}
	a := val.(*Agent)

	var sb strings.Builder
	sb.WriteString("# " + sanitizeForRender(a.Name) + "\n\n")
	sb.WriteString(sanitizeForRender(a.Description) + "\n\n")
	sb.WriteString("**ID:** " + a.ID + "\n")
	sb.WriteString("**Category:** " + sanitizeForRender(a.Category) + "\n")
	sb.WriteString("**Creator:** " + a.Creator.String() + "\n")
	sb.WriteString("**Endpoint:** " + sanitizeForRender(a.Endpoint) + "\n")
	sb.WriteString("**Transport:** " + a.Transport + "\n")
	sb.WriteString("**Pricing:** " + a.Pricing + "\n")
	if a.PricePerCall > 0 {
		sb.WriteString("**Price:** " + strconv.FormatInt(a.PricePerCall, 10) + " ugnot/call\n")
	}
	sb.WriteString("**Version:** " + sanitizeForRender(a.Version) + "\n")
	sb.WriteString("**Total Calls:** " + strconv.FormatInt(a.TotalCalls, 10) + "\n")
	sb.WriteString("**Registered:** block " + strconv.FormatInt(a.BlockH, 10) + "\n")

	if a.RatingCount > 0 {
		sb.WriteString("**Rating:** " + formatRating(a.RatingSum, a.RatingCount) +
			" (" + strconv.FormatInt(a.RatingCount, 10) + " reviews)\n")
	}

	// Capabilities
	sb.WriteString("\n## Capabilities\n\n")
	for _, cap := range strings.Split(a.Capabilities, ",") {
		cap = strings.TrimSpace(cap)
		if len(cap) > 0 {
			sb.WriteString("- " + sanitizeForRender(cap) + "\n")
		}
	}

	// Reviews — AR-1: render only the newest ReviewRenderMax so a sybil review flood can't
	// make this page exceed the query gas cap. AR-2: every user-controlled field sanitized.
	rval, rexists := reviews.Get(id)
	if rexists {
		revs := rval.([]*Review)
		if len(revs) > 0 {
			sb.WriteString("\n## Reviews\n\n")
			start := 0
			if len(revs) > ReviewRenderMax {
				start = len(revs) - ReviewRenderMax
				sb.WriteString(ufmt.Sprintf("_showing newest %d of %d reviews_\n\n",
					ReviewRenderMax, len(revs)))
			}
			for _, r := range revs[start:] {
				stars := strings.Repeat("*", r.Rating) + strings.Repeat(".", 5-r.Rating)
				sb.WriteString(ufmt.Sprintf("**%s** [%s] (block %d)\n\n",
					truncAddr(r.Reviewer), stars, r.BlockH))
				if len(r.Comment) > 0 {
					sb.WriteString(sanitizeForRender(r.Comment) + "\n\n")
				}
				sb.WriteString("---\n\n")
			}
		}
	}

	return sb.String()
}

func renderStats() string {
	var sb strings.Builder
	sb.WriteString("# Registry Stats\n\n")

	totalAgents := agents.Size()
	totalReviews := int64(0)
	totalCalls := int64(0)

	agents.Iterate("", "", func(key string, value interface{}) bool {
		a := value.(*Agent)
		totalReviews += a.RatingCount
		totalCalls += a.TotalCalls
		return false
	})

	sb.WriteString(ufmt.Sprintf("**Total Agents:** %d\n", totalAgents))
	sb.WriteString(ufmt.Sprintf("**Total Reviews:** %d\n", totalReviews))
	sb.WriteString(ufmt.Sprintf("**Total Calls:** %d\n", totalCalls))

	return sb.String()
}

// ── Helpers ──────────────────────────────────────────────────

// formatRating formats a rating as "X.Y" using integer math (no float in ufmt).
func formatRating(sum, count int64) string {
	if count == 0 {
		return "0.0"
	}
	whole := sum / count
	// One decimal place: (sum * 10 / count) % 10
	frac := ((sum * 10) / count) % 10
	return strconv.FormatInt(whole, 10) + "." + strconv.FormatInt(frac, 10)
}

func truncAddr(addr address) string {
	s := addr.String()
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

func isValidTransport(t string) bool {
	return t == "stdio" || t == "sse" || t == "streamable-http"
}

func isValidPricing(p string) bool {
	return p == "free" || p == "pay-per-use" || p == "subscription"
}

// sanitizeForRender strips markdown-sensitive characters from user-controlled strings
// before rendering in gnoweb to prevent injection attacks.
func sanitizeForRender(s string) string {
	var out strings.Builder
	for _, c := range s {
		switch c {
		case '[', ']', '(', ')', '#', '*', '`', '!', '<', '>', '|', '\\', '_', '~', '\n', '\r', '\t':
			continue
		default:
			out.WriteRune(c)
		}
	}
	return out.String()
}

// countAgentsByCreator counts how many agents `creator` currently owns (B4 cap).
// Bounded by MaxAgents (global), so O(MaxAgents) worst case.
func countAgentsByCreator(creator address) int {
	n := 0
	agents.Iterate("", "", func(_ string, value interface{}) bool {
		if value.(*Agent).Creator == creator {
			n++
		}
		return false
	})
	return n
}

// countDepositors counts the distinct credit entries for an agent (B4 cap).
// Bounded by MaxDepositorsPerAgent in steady state (the cap enforces its own
// bound), so the scan stays cheap.
func countDepositors(agentId string) int {
	prefix := agentId + "/"
	n := 0
	credits.Iterate(prefix, prefix+"\xff", func(_ string, _ interface{}) bool {
		n++
		return false
	})
	return n
}

// hasAnyCreditsEntry returns true if ANY credit entry exists for the agent,
// even with zero balance. This prevents a price-lock bypass where the creator
// drains a user's balance to 0, then raises the price, then the user tops up.
// Zero-balance entries remain as markers until explicitly cleaned via
// RefundCredits (which removes the entry) or RemoveAgent.
func hasAnyCreditsEntry(agentId string) bool {
	prefix := agentId + "/"
	found := false
	credits.Iterate(prefix, prefix+"\xff", func(key string, value interface{}) bool {
		found = true
		return true // stop iteration
	})
	return found
}

// isValidAgentID ensures the ID contains only safe characters (no "/" or other delimiters
// that would cause key collisions in the credits/usage AVL trees).
func isValidAgentID(id string) bool {
	for _, c := range id {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '-' || c == '_') {
			return false
		}
	}
	return true
}

package memba_reviews_v1

// Memba Reviews / Web-of-Trust realm.
//
// OPEN, on-chain ratings + reviews for any Memba subject (validator/candidate/
// individual address, or an org/DAO realm path). Anyone with a wallet may post
// ONE editable review per subject, react (like/dislike), reply (flat, one
// level), and flag. A running net-likes reputation counter per author drives
// ranking. Moderation = author delete (tombstone) + community flag + multisig
// hide (soft-delete). Text is permanent on-chain; Hide only omits from reads.
//
// Reads: exported *JSON funcs queried via RPC vm/qeval (paginated). Render() is
// a secondary human view for gnoweb.

import (
	"strconv"
	"strings"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"
)

// ── Constants ────────────────────────────────────────────────
const (
	MaxBodyLen    = 2000 // review body
	MaxCommentLen = 1000 // comment body
	MaxPageLimit  = 100  // hard cap on any paginated read (DoS guard)

	// Memba moderator multisig (samcrew-core-test1 on testnet). CONFIRM before deploy.
	ModeratorAddress = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0"
)

// ── Types ────────────────────────────────────────────────────
type Review struct {
	ID        uint64
	Subject   string  // g1… address OR realm path
	Author    address
	Rating    int     // 1..5
	Body      string  // optional, ≤ MaxBodyLen
	CreatedAt int64   // block height
	EditedAt  int64   // block height of last edit (0 if never)
	Hidden    bool    // multisig soft-delete / auto-hide
	Deleted   bool    // author tombstone
	Likes     uint64
	Dislikes  uint64
	FlagCount uint64
}

type Comment struct {
	ID        uint64
	ReviewID  uint64
	Author    address
	Body      string // ≤ MaxCommentLen
	CreatedAt int64
	EditedAt  int64
	Hidden    bool
	Deleted   bool
	Likes     uint64
	Dislikes  uint64
	FlagCount uint64
}

// ── State ────────────────────────────────────────────────────
var (
	reviews       *avl.Tree // strID(id) -> *Review
	comments      *avl.Tree // strID(id) -> *Comment
	subjectIndex  *avl.Tree // subject -> []uint64 (review IDs, ascending) — bounds reads
	commentIndex  *avl.Tree // strID(reviewID) -> []uint64 (comment IDs, ascending)
	authorSubject *avl.Tree // subject + "\x00" + author -> uint64 (reviewID) — one-per-pair
	reactions     *avl.Tree // strID(targetID) + "/" + addr -> "like"|"dislike"
	flags         *avl.Tree // strID(targetID) + "/" + addr -> true (one flag per acct/target)
	reputation    *avl.Tree // addr -> int64 (Σ likes−dislikes on their reviews+comments)
	flaggedIDs    *avl.Tree // strID(targetID) -> true (visible targets with ≥1 flag, for the mod dashboard)
	nextID        uint64
)

func init() {
	reviews = avl.NewTree()
	comments = avl.NewTree()
	subjectIndex = avl.NewTree()
	commentIndex = avl.NewTree()
	authorSubject = avl.NewTree()
	reactions = avl.NewTree()
	flags = avl.NewTree()
	reputation = avl.NewTree()
	flaggedIDs = avl.NewTree()
	nextID = 1
}

// ── Helpers ──────────────────────────────────────────────────
func strID(id uint64) string { return strconv.FormatUint(id, 10) }

func getReview(id uint64) (*Review, bool) {
	v, ok := reviews.Get(strID(id))
	if !ok {
		return nil, false
	}
	return v.(*Review), true
}

func getComment(id uint64) (*Comment, bool) {
	v, ok := comments.Get(strID(id))
	if !ok {
		return nil, false
	}
	return v.(*Comment), true
}

func assertModerator() {
	caller := unsafe.PreviousRealm().Address()
	if caller != address(ModeratorAddress) {
		panic("unauthorized: moderator multisig only")
	}
}

func getReputation(addr string) int64 {
	if v, ok := reputation.Get(addr); ok {
		return v.(int64)
	}
	return 0
}

func addReputation(addr string, delta int64) {
	reputation.Set(addr, getReputation(addr)+delta)
}

func idList(t *avl.Tree, key string) []uint64 {
	if v, ok := t.Get(key); ok {
		return v.([]uint64)
	}
	return nil
}

// removeID returns ids with the first occurrence of target removed.
func removeID(ids []uint64, target uint64) []uint64 {
	out := make([]uint64, 0, len(ids))
	removed := false
	for _, id := range ids {
		if !removed && id == target {
			removed = true
			continue
		}
		out = append(out, id)
	}
	return out
}

// sanitizeForRender strips markdown/HTML-sensitive chars from user strings used
// inside Render() markdown (defense-in-depth; the frontend also DOMPurifies).
// "&" is escaped FIRST to prevent entity-injection (e.g. "&lt;" → "&amp;lt;").
func sanitizeForRender(s string) string {
	r := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;", ">", "&gt;",
		"[", "(", "]", ")",
		"`", "'", "|", "/",
		"\n", " ", "\r", " ",
	)
	return r.Replace(s)
}

// jsonEscape escapes a string for embedding in the realm's hand-built JSON.
func jsonEscape(s string) string {
	var b strings.Builder
	for _, c := range s {
		switch c {
		case '"':
			b.WriteString("\\\"")
		case '\\':
			b.WriteString("\\\\")
		case '\n':
			b.WriteString("\\n")
		case '\r':
			b.WriteString("\\r")
		case '\t':
			b.WriteString("\\t")
		default:
			if c < 0x20 {
				const hexDigits = "0123456789abcdef"
				b.WriteString("\\u00")
				b.WriteByte(hexDigits[int((c>>4)&0xf)])
				b.WriteByte(hexDigits[int(c&0xf)])
			} else {
				b.WriteRune(c)
			}
		}
	}
	return b.String()
}

// ── Validation helpers (pure, no side-effects) ────────────────

func validRating(r int) bool { return r >= 1 && r <= 5 }

func validBody(b string) bool { return len(b) <= MaxBodyLen }

// pairKey returns the authorSubject tree key for a (subject, author) pair.
// The NUL separator prevents prefix collisions between subject and author.
func pairKey(subject string, a address) string { return subject + "\x00" + a.String() }

// ── Write functions ───────────────────────────────────────────

// PostReview creates the caller's review for `subject`, or replaces it in place
// if one already exists (the "one editable review per pair" rule).
func PostReview(cur realm, subject string, rating int, body string) {
	caller := unsafe.PreviousRealm().Address()
	if subject == "" {
		panic("subject required")
	}
	if !validRating(rating) {
		panic("rating must be 1..5")
	}
	if !validBody(body) {
		panic("body too long")
	}

	pk := pairKey(subject, caller)
	if v, ok := authorSubject.Get(pk); ok {
		r, found := getReview(v.(uint64))
		if found && !r.Deleted && !r.Hidden {
			r.Rating = rating
			r.Body = body
			r.EditedAt = runtime.ChainHeight()
			reviews.Set(strID(r.ID), r)
			chain.Emit("ReviewUpdated", "id", strID(r.ID), "subject", subject)
			return
		}
	}

	id := nextID
	nextID++
	r := &Review{
		ID:        id,
		Subject:   subject,
		Author:    caller,
		Rating:    rating,
		Body:      body,
		CreatedAt: runtime.ChainHeight(),
	}
	reviews.Set(strID(id), r)
	authorSubject.Set(pk, id)
	subjectIndex.Set(subject, append(idList(subjectIndex, subject), id))
	chain.Emit("ReviewPosted", "id", strID(id), "subject", subject, "author", caller.String())
}

// EditReview updates rating + body of an existing non-deleted review.
// Only the original author may edit.
func EditReview(cur realm, reviewID uint64, rating int, body string) {
	caller := unsafe.PreviousRealm().Address()
	r, ok := getReview(reviewID)
	if !ok || r.Deleted {
		panic("review not found")
	}
	if r.Author != caller {
		panic("author only")
	}
	if !validRating(rating) {
		panic("rating must be 1..5")
	}
	if !validBody(body) {
		panic("body too long")
	}
	r.Rating = rating
	r.Body = body
	r.EditedAt = runtime.ChainHeight()
	reviews.Set(strID(reviewID), r)
	chain.Emit("ReviewUpdated", "id", strID(reviewID), "subject", r.Subject)
}

// DeleteReview tombstones the caller's review: keeps the ID + reaction history,
// clears the body, and frees the (author, subject) pair for a fresh review.
// Only the original author may delete.
func DeleteReview(cur realm, reviewID uint64) {
	caller := unsafe.PreviousRealm().Address()
	r, ok := getReview(reviewID)
	if !ok || r.Deleted {
		panic("review not found")
	}
	if r.Author != caller {
		panic("author only")
	}
	r.Deleted = true
	r.Body = ""
	reviews.Set(strID(reviewID), r)
	authorSubject.Remove(pairKey(r.Subject, caller))
	subjectIndex.Set(r.Subject, removeID(idList(subjectIndex, r.Subject), reviewID))
	chain.Emit("ReviewDeleted", "id", strID(reviewID), "subject", r.Subject)
}

// ── Comment validation (pure, no side-effects) ────────────────

// validComment returns true iff body is non-empty and within MaxCommentLen.
func validComment(b string) bool { return b != "" && len(b) <= MaxCommentLen }

// ── Comment write functions ───────────────────────────────────

// PostComment posts a flat reply to an existing, non-deleted, non-hidden review.
func PostComment(cur realm, reviewID uint64, body string) {
	caller := unsafe.PreviousRealm().Address()
	r, ok := getReview(reviewID)
	if !ok || r.Deleted || r.Hidden {
		panic("review not found")
	}
	if !validComment(body) {
		panic("comment length invalid")
	}
	id := nextID
	nextID++
	c := &Comment{
		ID:        id,
		ReviewID:  reviewID,
		Author:    caller,
		Body:      body,
		CreatedAt: runtime.ChainHeight(),
	}
	comments.Set(strID(id), c)
	commentIndex.Set(strID(reviewID), append(idList(commentIndex, strID(reviewID)), id))
	chain.Emit("CommentPosted", "id", strID(id), "review", strID(reviewID), "author", caller.String())
}

// EditComment updates the body of an existing, non-deleted comment.
// Only the original author may edit.
func EditComment(cur realm, commentID uint64, body string) {
	caller := unsafe.PreviousRealm().Address()
	c, ok := getComment(commentID)
	if !ok || c.Deleted {
		panic("comment not found")
	}
	if c.Author != caller {
		panic("author only")
	}
	if !validComment(body) {
		panic("comment length invalid")
	}
	c.Body = body
	c.EditedAt = runtime.ChainHeight()
	comments.Set(strID(commentID), c)
	chain.Emit("CommentUpdated", "id", strID(commentID))
}

// DeleteComment tombstones the caller's comment: clears the body.
// Only the original author may delete.
func DeleteComment(cur realm, commentID uint64) {
	caller := unsafe.PreviousRealm().Address()
	c, ok := getComment(commentID)
	if !ok || c.Deleted {
		panic("comment not found")
	}
	if c.Author != caller {
		panic("author only")
	}
	c.Deleted = true
	c.Body = ""
	comments.Set(strID(commentID), c)
	chain.Emit("CommentDeleted", "id", strID(commentID))
}

// ── Reaction helpers (pure, no side-effects) ──────────────────

func boolToInt(b bool) int {
	if b {
		return 1
	}
	return 0
}

// reactionDelta returns how a reaction change (old -> newKind, each "" | "like" | "dislike")
// moves the target's like count, dislike count, and the target author's reputation.
// repDelta = likesDelta - dislikesDelta.
func reactionDelta(old, newKind string) (likesDelta, dislikesDelta, repDelta int) {
	likesDelta = boolToInt(newKind == "like") - boolToInt(old == "like")
	dislikesDelta = boolToInt(newKind == "dislike") - boolToInt(old == "dislike")
	repDelta = likesDelta - dislikesDelta
	return
}

// applyDelta adjusts an unsigned counter by ±1-style delta without underflow.
func applyDelta(v uint64, delta int) uint64 {
	if delta < 0 {
		d := uint64(-delta)
		if v < d {
			return 0
		}
		return v - d
	}
	return v + uint64(delta)
}

// ── React ─────────────────────────────────────────────────────

// React records or toggles a like/dislike on a review or comment.
// Re-reacting with the same kind toggles it off; switching kind replaces it.
// Updates the target's Likes/Dislikes counters and the author's reputation by
// Δ(likes−dislikes). Self-reactions are rejected. Deleted/hidden targets are rejected.
func React(cur realm, targetID uint64, kind string) {
	caller := unsafe.PreviousRealm().Address()
	if kind != "like" && kind != "dislike" {
		panic("kind must be like or dislike")
	}

	r, isReview := getReview(targetID)
	c, isComment := getComment(targetID)
	if !isReview && !isComment {
		panic("target not found")
	}

	var author address
	if isReview {
		author = r.Author
		if r.Deleted || r.Hidden {
			panic("target not found")
		}
	} else {
		author = c.Author
		if c.Deleted || c.Hidden {
			panic("target not found")
		}
	}
	if author == caller {
		panic("cannot react to your own review or comment")
	}

	rk := strID(targetID) + "/" + caller.String()
	var old string
	if v, ok := reactions.Get(rk); ok {
		old = v.(string)
	}

	newKind := kind
	if old == kind {
		newKind = "" // toggle off
	}

	likesDelta, dislikesDelta, repDelta := reactionDelta(old, newKind)

	if newKind == "" {
		reactions.Remove(rk)
	} else {
		reactions.Set(rk, newKind)
	}

	if isReview {
		r.Likes = applyDelta(r.Likes, likesDelta)
		r.Dislikes = applyDelta(r.Dislikes, dislikesDelta)
		reviews.Set(strID(targetID), r)
	} else {
		c.Likes = applyDelta(c.Likes, likesDelta)
		c.Dislikes = applyDelta(c.Dislikes, dislikesDelta)
		comments.Set(strID(targetID), c)
	}
	addReputation(author.String(), int64(repDelta))
	chain.Emit("Reacted", "target", strID(targetID), "kind", newKind, "by", caller.String())
}

// ── Flag + moderation ─────────────────────────────────────────

// Flag records one community flag per account per target (review or comment).
// Auto-hide is NOT performed here; takedowns are multisig-only (HideReview/HideComment).
// Deleted/hidden targets are rejected.
func Flag(cur realm, targetID uint64) {
	caller := unsafe.PreviousRealm().Address()
	r, isReview := getReview(targetID)
	c, isComment := getComment(targetID)
	if !isReview && !isComment {
		panic("target not found")
	}
	if isReview && (r.Deleted || r.Hidden) {
		panic("target not found")
	}
	if isComment && (c.Deleted || c.Hidden) {
		panic("target not found")
	}
	fk := strID(targetID) + "/" + caller.String()
	if _, ok := flags.Get(fk); ok {
		panic("already flagged")
	}
	flags.Set(fk, true)

	if isReview {
		r.FlagCount++
		reviews.Set(strID(targetID), r)
	} else {
		c.FlagCount++
		comments.Set(strID(targetID), c)
	}
	flaggedIDs.Set(strID(targetID), true)
	chain.Emit("Flagged", "target", strID(targetID), "by", caller.String())
}

// HideReview soft-deletes a review. Moderator (multisig) only.
func HideReview(cur realm, id uint64) {
	assertModerator()
	r, ok := getReview(id)
	if !ok {
		panic("review not found")
	}
	r.Hidden = true
	reviews.Set(strID(id), r)
	chain.Emit("Hidden", "target", strID(id))
}

// HideComment soft-deletes a comment. Moderator (multisig) only.
func HideComment(cur realm, id uint64) {
	assertModerator()
	c, ok := getComment(id)
	if !ok {
		panic("comment not found")
	}
	c.Hidden = true
	comments.Set(strID(id), c)
	chain.Emit("Hidden", "target", strID(id))
}

// Unhide reverses a hide (manual or auto-flag) on a review or comment.
// Moderator (multisig) only. Also removes the target from the mod dashboard index.
func Unhide(cur realm, targetID uint64) {
	assertModerator()
	if r, ok := getReview(targetID); ok {
		r.Hidden = false
		reviews.Set(strID(targetID), r)
		flaggedIDs.Remove(strID(targetID))
		chain.Emit("Unhidden", "target", strID(targetID))
		return
	}
	if c, ok := getComment(targetID); ok {
		c.Hidden = false
		comments.Set(strID(targetID), c)
		flaggedIDs.Remove(strID(targetID))
		chain.Emit("Unhidden", "target", strID(targetID))
		return
	}
	panic("target not found")
}

// ── Read helpers ──────────────────────────────────────────────

// clampLimit ensures limit is in [1, MaxPageLimit]. Zero or negative values and
// values above MaxPageLimit are all clamped to MaxPageLimit.
func clampLimit(limit int) int {
	if limit <= 0 || limit > MaxPageLimit {
		return MaxPageLimit
	}
	return limit
}

// window slices ids[offset : offset+limit] safely (no panics on out-of-range).
func window(ids []uint64, offset, limit int) []uint64 {
	limit = clampLimit(limit)
	if offset < 0 {
		offset = 0
	}
	if offset >= len(ids) {
		return nil
	}
	end := offset + limit
	if end > len(ids) {
		end = len(ids)
	}
	return ids[offset:end]
}

func reviewJSON(r *Review) string {
	body := ""
	if !r.Deleted {
		body = jsonEscape(r.Body)
	}
	return ufmt.Sprintf(
		`{"id":%d,"subject":"%s","author":"%s","rating":%d,"body":"%s","createdAt":%d,"editedAt":%d,"deleted":%t,"likes":%d,"dislikes":%d,"flags":%d,"reputation":%d}`,
		r.ID, jsonEscape(r.Subject), jsonEscape(r.Author.String()), r.Rating, body,
		r.CreatedAt, r.EditedAt, r.Deleted, r.Likes, r.Dislikes, r.FlagCount,
		getReputation(r.Author.String()),
	)
}

func commentJSON(c *Comment) string {
	body := ""
	if !c.Deleted {
		body = jsonEscape(c.Body)
	}
	return ufmt.Sprintf(
		`{"id":%d,"reviewId":%d,"author":"%s","body":"%s","createdAt":%d,"editedAt":%d,"deleted":%t,"likes":%d,"dislikes":%d,"flags":%d,"reputation":%d}`,
		c.ID, c.ReviewID, jsonEscape(c.Author.String()), body,
		c.CreatedAt, c.EditedAt, c.Deleted, c.Likes, c.Dislikes, c.FlagCount,
		getReputation(c.Author.String()),
	)
}

// GetReviewsJSON returns a JSON array of a subject's non-hidden reviews (paginated).
// Deleted reviews are included as tombstones (empty body, deleted:true).
func GetReviewsJSON(subject string, offset, limit int) string {
	ids := window(idList(subjectIndex, subject), offset, limit)
	var b strings.Builder
	b.WriteString("[")
	first := true
	for _, id := range ids {
		r, ok := getReview(id)
		if !ok || r.Hidden {
			continue
		}
		if !first {
			b.WriteString(",")
		}
		b.WriteString(reviewJSON(r))
		first = false
	}
	b.WriteString("]")
	return b.String()
}

// GetCommentsJSON returns a JSON array of a review's non-hidden comments (paginated).
func GetCommentsJSON(reviewID uint64, offset, limit int) string {
	ids := window(idList(commentIndex, strID(reviewID)), offset, limit)
	var b strings.Builder
	b.WriteString("[")
	first := true
	for _, id := range ids {
		c, ok := getComment(id)
		if !ok || c.Hidden {
			continue
		}
		if !first {
			b.WriteString(",")
		}
		b.WriteString(commentJSON(c))
		first = false
	}
	b.WriteString("]")
	return b.String()
}

// GetSubjectSummaryJSON returns {"count":N,"average":A,"sum":S} over non-hidden,
// non-deleted reviews for a subject. Average is integer-rounded.
func GetSubjectSummaryJSON(subject string) string {
	ids := idList(subjectIndex, subject)
	var sum, n int64
	for _, id := range ids {
		r, ok := getReview(id)
		if !ok || r.Hidden || r.Deleted {
			continue
		}
		sum += int64(r.Rating)
		n++
	}
	avg := int64(0)
	if n > 0 {
		avg = (sum + n/2) / n // round to nearest
	}
	return ufmt.Sprintf(`{"count":%d,"average":%d,"sum":%d}`, n, avg, sum)
}

// GetReputation returns the net likes−dislikes reputation for an address.
// Returns 0 for unknown addresses. Queried via vm/qeval (bare int64).
func GetReputation(addr string) int64 { return getReputation(addr) }

// GetFlaggedJSON returns a JSON array of flagged target IDs for the mod dashboard,
// paginated. IDs are returned as bare integers (not quoted strings).
// Uses early-stop iteration to avoid loading the entire tree.
func GetFlaggedJSON(offset, limit int) string {
	limit = clampLimit(limit)
	if offset < 0 {
		offset = 0
	}
	var ids []uint64
	skipped := 0
	flaggedIDs.Iterate("", "", func(key string, _ interface{}) bool {
		if skipped < offset {
			skipped++
			return false
		}
		id, _ := strconv.ParseUint(key, 10, 64)
		ids = append(ids, id)
		return len(ids) >= limit // stop once collected enough
	})
	var b strings.Builder
	b.WriteString("[")
	for i, id := range ids {
		if i > 0 {
			b.WriteString(",")
		}
		b.WriteString(strID(id))
	}
	b.WriteString("]")
	return b.String()
}

// Render — human gnoweb view.
// "" → home (total count); "s/<subject>" → subject review list; else 404.
func Render(path string) string {
	if path == "" {
		return ufmt.Sprintf("# Memba Reviews\n\nOn-chain web-of-trust. %d reviews total.\n", reviews.Size())
	}
	if strings.HasPrefix(path, "s/") {
		subject := strings.TrimPrefix(path, "s/")
		var b strings.Builder
		b.WriteString("# Reviews for " + sanitizeForRender(subject) + "\n\n")
		written := false
		renderedCount := 0
		for _, id := range idList(subjectIndex, subject) {
			if renderedCount >= MaxPageLimit {
				break
			}
			r, ok := getReview(id)
			if !ok || r.Hidden || r.Deleted {
				continue
			}
			b.WriteString(ufmt.Sprintf("**%d/5** by %s\n\n%s\n\n---\n",
				r.Rating, r.Author.String(), sanitizeForRender(r.Body)))
			written = true
			renderedCount++
		}
		if !written {
			b.WriteString("No reviews yet.\n")
		}
		return b.String()
	}
	return "# 404\n"
}

// Package memba_quest_attestation_v1 is the on-chain quest/XP attestation realm
// for Memba (audit Q-05, Track A — "Model B" offline-signed voucher).
//
// WHY: Memba quest XP lives in a centralized backend DB; the chain holds no
// verifiable record. This realm makes a quest completion + its XP an independently
// verifiable on-chain fact, WITHOUT giving the backend a hot key that can write
// arbitrary state.
//
// HOW (Model B — offline voucher):
//   - The backend holds an OFFLINE ed25519 signing key; it NEVER broadcasts.
//   - For a server-verified completion it issues a voucher
//     (address, questId, xp, nonce) + ed25519 signature
//     over the canonical message
//     addr "|" questId "|" itoa(xp) "|" nonce            (UTF-8 bytes)
//   - The USER broadcasts RecordCompletion(...) with the voucher (they pay gas).
//   - This realm verifies the signature against the configured signer pubkey,
//     rejects reused nonces (replay), bounds xp, and records the completion +
//     cumulative attested XP.
//
// TRUST MODEL: the signature is the authority, NOT the caller — anyone may
// broadcast a valid voucher (it can only record the backend-attested fact). The
// only privileged action is rotating the signer pubkey (owner multisig).
//
// The canonical message format is a CONTRACT with the backend signer — it MUST
// stay byte-identical on both sides. See canonicalMsg.
package memba_quest_attestation_v1

import (
	"crypto/ed25519"
	"encoding/hex"
	"strconv"
	"strings"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"

	"chain/runtime"
	"chain/runtime/unsafe"
)

// ── Constants ────────────────────────────────────────────────
const (
	// OwnerAddress is the samcrew-core-test1 multisig on test13 (realm owner /
	// signer-key rotator). CONFIRM before deploy.
	OwnerAddress = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0"

	// MaxAttestXP bounds the XP a single voucher can carry. This caps the blast
	// radius if the offline signer key ever leaks: a leaked key can still forge
	// vouchers, but cannot mint unbounded XP in one call. Generous vs the real
	// max single-quest XP (≤100).
	MaxAttestXP = 1000

	pubKeySize = 32 // ed25519 public key length (gno crypto/ed25519 exposes no const)
	sigSize    = 64 // ed25519 signature length
	fieldSep   = "|"
)

// ── State ────────────────────────────────────────────────────
var (
	// signerPubKey is the backend's offline ed25519 PUBLIC key (32 bytes). Set by
	// the owner via SetSigner after deploy; until then NO voucher verifies.
	signerPubKey []byte

	completions *avl.Tree // addr + ":" + questId -> int64 (block height recorded)
	attestedXP  *avl.Tree // addr               -> int   (cumulative attested XP)
	usedNonce   *avl.Tree // nonce              -> true  (replay guard)
)

func init() {
	completions = avl.NewTree()
	attestedXP = avl.NewTree()
	usedNonce = avl.NewTree()
}

// ── Pure helpers (unit-tested) ───────────────────────────────

// canonicalMsg is the EXACT byte string the backend signs offline and this realm
// verifies. It MUST stay byte-identical to the backend signer (ADR Track A / A.3).
// strconv.Itoa gives a canonical decimal with no leading zeros, so both sides
// agree for any xp.
func canonicalMsg(addr, questId string, xp int, nonce string) []byte {
	return []byte(addr + fieldSep + questId + fieldSep + strconv.Itoa(xp) + fieldSep + nonce)
}

func completionKey(addr, questId string) string { return addr + ":" + questId }

// validXP bounds the attestable XP (see MaxAttestXP).
func validXP(xp int) bool { return xp > 0 && xp <= MaxAttestXP }

// fieldsClean rejects any voucher field containing the separator. This makes the
// canonical message PROVABLY unambiguous (no field-injection collision) without
// trusting the backend's nonce charset: with no field able to contain "|", a
// given canonical byte string maps to exactly one (addr, questId, xp, nonce).
func fieldsClean(addr, questId, nonce string) bool {
	return !strings.Contains(addr, fieldSep) &&
		!strings.Contains(questId, fieldSep) &&
		!strings.Contains(nonce, fieldSep)
}

// verifyVoucher reports whether sigHex is a valid ed25519 signature by pub over
// the canonical voucher message. Pure (no state) so it is unit-tested directly
// with offline-generated test vectors.
func verifyVoucher(pub []byte, addr, questId string, xp int, nonce, sigHex string) bool {
	if len(pub) != pubKeySize {
		return false
	}
	sig, err := hex.DecodeString(sigHex)
	if err != nil || len(sig) != sigSize {
		return false
	}
	return ed25519.Verify(pub, canonicalMsg(addr, questId, xp, nonce), sig)
}

// ── Owner: rotate the signer key ─────────────────────────────

// SetSigner installs/rotates the backend's offline signer PUBLIC key (32-byte
// hex). Owner-multisig only. This is a crossing function, so PreviousRealm()
// correctly identifies the immediate caller (see gno interrealm semantics).
func SetSigner(cur realm, pubKeyHex string) {
	if unsafe.PreviousRealm().Address() != address(OwnerAddress) {
		panic("unauthorized: owner multisig only")
	}
	pub, err := hex.DecodeString(pubKeyHex)
	if err != nil || len(pub) != pubKeySize {
		panic("signer pubkey must be 32-byte hex")
	}
	signerPubKey = pub
}

// ── User-broadcast: record a signed completion voucher ───────

// RecordCompletion verifies a backend-signed voucher and records the completion
// + its XP on-chain. Idempotent per (addr, questId); replay-proof per nonce.
// Panics (reverting the tx) on any invalid/again-used/out-of-range voucher.
func RecordCompletion(cur realm, addr, questId string, xp int, nonce, sigHex string) {
	if len(signerPubKey) != pubKeySize {
		panic("attestation signer not configured")
	}
	if addr == "" || questId == "" || nonce == "" {
		panic("missing voucher field")
	}
	if !fieldsClean(addr, questId, nonce) {
		panic("voucher field must not contain the separator")
	}
	if !validXP(xp) {
		panic("xp out of range")
	}
	if _, used := usedNonce.Get(nonce); used {
		panic("nonce already used")
	}
	if !verifyVoucher(signerPubKey, addr, questId, xp, nonce, sigHex) {
		panic("invalid voucher signature")
	}

	// Consume the nonce (replay guard) before the idempotency early-return below,
	// so a replayed voucher always fails even for an already-recorded completion.
	usedNonce.Set(nonce, true)

	// Idempotent on (addr, questId): a second, distinct-nonce voucher for an
	// already-recorded completion must NOT double-count XP.
	ck := completionKey(addr, questId)
	if _, exists := completions.Get(ck); exists {
		return
	}
	completions.Set(ck, runtime.ChainHeight())

	prev := 0
	if v, ok := attestedXP.Get(addr); ok {
		prev = v.(int)
	}
	attestedXP.Set(addr, prev+xp)
}

// ── Public reads ─────────────────────────────────────────────

// GetAttestedXP returns addr's cumulative on-chain attested XP (0 if none).
func GetAttestedXP(addr string) int {
	if v, ok := attestedXP.Get(addr); ok {
		return v.(int)
	}
	return 0
}

// GetRecordedCompletions returns addr's attested quest IDs as a comma-separated
// list (empty string if none), in ascending key order.
func GetRecordedCompletions(addr string) string {
	prefix := addr + ":"
	out := []string{}
	completions.Iterate(prefix, addr+";", func(key string, _ interface{}) bool {
		out = append(out, strings.TrimPrefix(key, prefix))
		return false
	})
	return strings.Join(out, ",")
}

// Render is the human/gnoweb view; the authoritative reads are the exported
// Get* funcs (queried via vm/qeval).
func Render(path string) string {
	if path == "" {
		signer := "not configured"
		if len(signerPubKey) == pubKeySize {
			signer = "configured"
		}
		return ufmt.Sprintf(
			"# Memba Quest Attestation\n\nVerifiable on-chain quest/XP records (offline-signed vouchers).\n\n- Completions attested: %d\n- Accounts with attested XP: %d\n- Signer: %s\n",
			completions.Size(), attestedXP.Size(), signer)
	}
	if strings.HasPrefix(path, "user/") {
		addr := strings.TrimPrefix(path, "user/")
		comps := GetRecordedCompletions(addr)
		if comps == "" {
			comps = "(none)"
		}
		return ufmt.Sprintf("# %s\n\n- Attested XP: %d\n- Completions: %s\n", addr, GetAttestedXP(addr), comps)
	}
	return "404"
}

package memba_feed_v1

// memba_feed_v1 — Global social feed realm for Memba (W7.2 P0).
//
// OPEN-WRITE: any wallet may post. This inverts every assumption of the
// DAO-scoped memba_dao_channels_v2 (members-only, 20 channels / 500 threads),
// so the realm is NEW — what is ported VERBATIM from channels_v2 is its
// hardening discipline:
//
//   B1 render-DoS bounds — reads NEVER iterate the monotonic nextPostID.
//     Live (visible) posts are tracked in dedicated AVL indexes and every
//     read path is paginated to a fixed window. channels_v2 used []uint64
//     slices (safe under its 500-per-channel cap); an open feed is unbounded,
//     so the live indexes here are composite-key AVL trees instead —
//     O(log n) insert/remove, O(page) scan, no single node that grows forever.
//   B2 state-shrink — author deletes soft-delete + enqueue a tombstone;
//     SweepTombstones hard-removes nodes (bounded, permissionless GC).
//   B3 pause policy — every user-facing write is blocked while paused;
//     owner/moderation stays operational (no funds in this realm).
//   Flag pipeline — one flag per address per post, threshold auto-hide.
//     Open write invites brigading, so the threshold is higher than
//     channels_v2's 3 and flagging is further gated by account age and a
//     per-day flag budget.
//
// Anti-spam (open write has no membership gate to lean on):
//   - per-address block cooldown between posts, stricter for accounts first
//     seen fewer than YoungAccountBlocks ago;
//   - body length cap; media CID count cap (CIDs stored on-chain only —
//     pinning/serving is the backend's PinMedia pipeline, P2).
//
// Reads: exported *JSON funcs via RPC vm/qeval — cursor-paginated, O(limit)
// at any depth (the app reads from the indexer; these are the fallback).
// Render() is the human gnoweb view: bounded pages with a hard depth cap
// (MaxRenderPage) — deep history belongs to the cursor API, not qrender.
//
// Moderation P0: realm owner only (ModRemovePost / UnhidePost / BanAuthor is
// W8.2's moderation board via a daokit moderator role — p/samcrew/modboard).
// Every moderation action emits for public audit.
//
// This realm holds NO funds: no banker, no OriginSend, no fee lane. A future
// tipping lane is a separate SAFETY_GATED flag + fee-spine lane "feed".

import (
	"strconv"
	"strings"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"
)

// ── Constants ────────────────────────────────────────────────

const (
	MaxBodyLen   = 1000 // post body (roadmap 4.1)
	MaxMediaCIDs = 4    // stored per post; pin/serve pipeline is P2
	MaxCIDLen    = 128  // defensive cap on a single CID string

	FeedPageSize  = 20  // posts per rendered page / default JSON window
	MaxPageLimit  = 100 // hard cap on any JSON read window (DoS guard)
	MaxRenderPage = 50  // deepest gnoweb page; beyond → use the cursor API

	// B1 reply bound (mirrors channels_v2's MaxRepliesPerThread). Caps the
	// LIVE reply set per post so (a) the byParent index under any one parent is
	// bounded, and (b) SweepTombstones can range-delete a swept parent's reply
	// links in bounded work. Deleting a reply frees a slot.
	MaxRepliesPerPost = 500

	// Flag pipeline. channels_v2 auto-hides at 3 member flags; the feed is
	// open-write, so the threshold starts higher and flagging is rate-limited.
	// These are damping knobs, not a brigade-proof gate: 5 aged sybils can
	// still hide a post (the age gate is one post + a one-time wait, farmable
	// in parallel). They raise the cost and slow coordination; genuine brigade
	// resistance is the W8.2 moderation board (reversible mod actions + audit).
	// All are governance-tunable post-deploy via a future realm version; they
	// are constants here so the adversarial tests pin their behavior.
	FlagThreshold        = 5     // unique flags before auto-hide
	MinAccountAgeForFlag = 1200  // blocks since first post (~1-2h)
	FlagsPerDayBudget    = 10    // per address per BlocksPerDay window
	BlocksPerDay         = 17280 // ~5s blocks; approximation is fine

	// Posting cooldowns (blocks). Young accounts (first seen < YoungAccountBlocks
	// ago) wait longer between posts — cheap sybil throttle.
	MinPostIntervalBlocks      = 2
	YoungMinPostIntervalBlocks = 12
	YoungAccountBlocks         = 17280 // first ~day
)

// ── Types ────────────────────────────────────────────────────

type Post struct {
	ID        uint64
	Author    address
	Body      string
	MediaCIDs []string // IPFS CIDs only; serving goes through the backend proxy
	ReplyTo   uint64   // 0 = top-level
	RepostOf  uint64   // 0 = original (entrypoint lands in P1; field is schema-stable)
	BlockH    int64
	EditedAt  int64 // block height of last edit (0 = never)
	FlagCount int
	Hidden    bool // flag auto-hide or moderation hide
	Deleted   bool // author tombstone (awaiting SweepTombstones hard-GC)
}

type flagBudget struct {
	DayStartH int64
	Used      int
}

// ── State ────────────────────────────────────────────────────

var (
	posts *avl.Tree // padID(id) -> *Post (live + hidden + not-yet-swept tombstones)

	// Live indexes (B1): ONLY visible (not hidden, not deleted) posts.
	// Every read path iterates one of these — never `posts`, never nextPostID.
	liveFeed   *avl.Tree // padID(id) -> true
	byAuthor   *avl.Tree // author + ":" + padID(id) -> true
	byParent   *avl.Tree // padID(parent) + ":" + padID(child) -> true
	liveCount  uint64    // number of keys in liveFeed
	replyCount *avl.Tree // padID(parent) -> uint64 (live replies)

	nextPostID uint64 // monotonic; NEVER iterated by reads

	// Anti-spam / flag state.
	lastPostH  *avl.Tree // addr -> int64 (last CreatePost height)
	firstSeenH *avl.Tree // addr -> int64 (first write interaction height)
	flags      *avl.Tree // padID(id) -> *avl.Tree (flagger addr -> true)
	flagSpend  *avl.Tree // addr -> *flagBudget

	// Reactions (one-per-emoji toggle). padID(id) -> *avl.Tree keyed by
	// reactionSubKey(emoji, addr) -> true. Enforces per-(post,emoji,addr)
	// uniqueness on-chain; per-emoji COUNTS are aggregated off-chain by the
	// indexer from ReactionAdded/ReactionRemoved (no unbounded on-chain scan —
	// B1 render bounds hold; a hot post's reaction set is never iterated here).
	reactions *avl.Tree

	// Soft-deleted post IDs awaiting hard-GC (B2). An AVL tree (not a slice):
	// a slice re-serializes wholesale on every enqueue, so post+delete spam
	// would inflate the gas of every write touching it (a slow write-path DoS).
	// The tree gives O(log n) enqueue and lets the sweep drain a bounded
	// ascending window without rewriting the backlog.
	tombstones *avl.Tree // padID(id) -> true

	// Moderator set (W8.2): owner-granted addresses that can ModRemovePost /
	// UnhidePost WITHOUT owner-multisig-per-post — fast, reversible moderation.
	// Granting/revoking stays owner-only. addr -> true.
	moderators *avl.Tree

	paused bool
	// Deployer address (samcrew-core-test1 multisig on testnet), captured at
	// package load — same pattern as channels_v2.
	owner = unsafe.OriginCaller()
)

func init() {
	posts = avl.NewTree()
	liveFeed = avl.NewTree()
	byAuthor = avl.NewTree()
	byParent = avl.NewTree()
	replyCount = avl.NewTree()
	lastPostH = avl.NewTree()
	firstSeenH = avl.NewTree()
	flags = avl.NewTree()
	flagSpend = avl.NewTree()
	reactions = avl.NewTree()
	moderators = avl.NewTree()
	tombstones = avl.NewTree()
	nextPostID = 1
}

// ── Helpers ──────────────────────────────────────────────────

// padID zero-pads to 12 digits so AVL string order == numeric order.
// 12 digits ≥ 31,000 years of one post per block — effectively unbounded.
func padID(id uint64) string {
	s := strconv.FormatUint(id, 10)
	for len(s) < 12 {
		s = "0" + s
	}
	return s
}

func getPost(id uint64) (*Post, bool) {
	v, ok := posts.Get(padID(id))
	if !ok {
		return nil, false
	}
	return v.(*Post), true
}

func mustGetPost(id uint64) *Post {
	p, ok := getPost(id)
	if !ok {
		panic("post not found: " + strconv.FormatUint(id, 10))
	}
	return p
}

func authorKey(addr address, id uint64) string { return addr.String() + ":" + padID(id) }
func parentKey(parent, child uint64) string    { return padID(parent) + ":" + padID(child) }

func getReplyCount(parent uint64) uint64 {
	if v, ok := replyCount.Get(padID(parent)); ok {
		return v.(uint64)
	}
	return 0
}

// addToLiveIndexes registers a visible post in every live index (B1).
//
// A reply is only linked into its parent's byParent/replyCount indexes when the
// parent is still LIVE. On CreatePost the parent was just verified live, so this
// is always true there. The guard matters on the UnhidePost re-add path: if the
// parent was deleted+swept while the reply sat hidden, re-linking would recreate
// an orphan byParent/replyCount entry under a parent id no longer in `posts`
// (never sweepable again) — the exact leak SweepTombstones' byParent-prefix
// cleanup was added to prevent. An unhidden reply whose parent is gone simply
// becomes standalone live content, which is how a reply to a removed parent is
// already treated everywhere else.
func addToLiveIndexes(p *Post) {
	liveFeed.Set(padID(p.ID), true)
	byAuthor.Set(authorKey(p.Author, p.ID), true)
	liveCount++
	if p.ReplyTo != 0 && liveFeed.Has(padID(p.ReplyTo)) {
		byParent.Set(parentKey(p.ReplyTo, p.ID), true)
		replyCount.Set(padID(p.ReplyTo), getReplyCount(p.ReplyTo)+1)
	}
}

// removeFromLiveIndexes drops a post from every live index (hide/delete).
func removeFromLiveIndexes(p *Post) {
	if _, ok := liveFeed.Get(padID(p.ID)); !ok {
		return // already invisible (e.g. delete after auto-hide)
	}
	liveFeed.Remove(padID(p.ID))
	byAuthor.Remove(authorKey(p.Author, p.ID))
	if liveCount > 0 {
		liveCount--
	}
	if p.ReplyTo != 0 {
		byParent.Remove(parentKey(p.ReplyTo, p.ID))
		if rc := getReplyCount(p.ReplyTo); rc > 0 {
			replyCount.Set(padID(p.ReplyTo), rc-1)
		}
	}
}

func assertNotPaused() {
	if paused {
		panic("realm is paused — emergency maintenance")
	}
}

func assertCallerIsOwner() {
	caller := unsafe.PreviousRealm().Address()
	if caller != owner {
		panic("unauthorized: caller " + caller.String() + " is not the owner")
	}
}

// touchFirstSeen records the first write interaction height for an address.
func touchFirstSeen(addr address, h int64) {
	if _, ok := firstSeenH.Get(addr.String()); !ok {
		firstSeenH.Set(addr.String(), h)
	}
}

func accountAge(addr address, now int64) int64 {
	if v, ok := firstSeenH.Get(addr.String()); ok {
		return now - v.(int64)
	}
	return 0
}

// ── Emergency pause (B3 — one policy, enforced everywhere) ───
// While paused every user-facing content write is blocked. Owner moderation
// and pause management stay live: pause halts user activity during an
// incident, but the owner must stay able to act. No funds here, so there is
// no value-exit exemption to carve out.

func PauseRealm(cur realm) {
	assertCallerIsOwner()
	paused = true
	chain.Emit("RealmPaused", "by", owner.String())
}

func UnpauseRealm(cur realm) {
	assertCallerIsOwner()
	paused = false
	chain.Emit("RealmUnpaused", "by", owner.String())
}

func IsPaused() bool { return paused }

// TransferOwnership moves realm ownership (deployer multisig rotation).
func TransferOwnership(cur realm, newOwner address) {
	assertCallerIsOwner()
	if newOwner == "" {
		panic("address cannot be empty")
	}
	if newOwner == owner {
		panic("new owner is the same as current owner")
	}
	prev := owner
	owner = newOwner
	chain.Emit("OwnershipTransferred",
		"previousOwner", prev.String(),
		"newOwner", newOwner.String(),
	)
}

// GetOwner returns the current realm owner address.
func GetOwner() address { return owner }

// ── Writes ───────────────────────────────────────────────────

// CreatePost publishes a post (replyTo == 0) or a reply (replyTo == parent id).
// Open write: any wallet, subject to the block cooldown and body caps.
// Returns the new post id.
func CreatePost(cur realm, body string, replyTo uint64) uint64 {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	now := runtime.ChainHeight()

	// Cooldown BEFORE touching state: young accounts wait longer.
	touchFirstSeen(caller, now)
	interval := int64(MinPostIntervalBlocks)
	if accountAge(caller, now) < YoungAccountBlocks {
		interval = YoungMinPostIntervalBlocks
	}
	if v, ok := lastPostH.Get(caller.String()); ok {
		if now-v.(int64) < interval {
			panic(ufmt.Sprintf("posting too fast: wait %d blocks between posts", interval))
		}
	}

	if len(body) == 0 || len(body) > MaxBodyLen {
		panic(ufmt.Sprintf("body must be 1-%d characters", MaxBodyLen))
	}

	var parent *Post
	if replyTo != 0 {
		parent = mustGetPost(replyTo)
		if parent.Deleted {
			panic("cannot reply to a deleted post")
		}
		if parent.Hidden {
			panic("cannot reply to a hidden post")
		}
		// B1: bound the LIVE reply set so the byParent index under one parent
		// stays bounded (and a swept parent's link cleanup stays bounded).
		if getReplyCount(replyTo) >= MaxRepliesPerPost {
			panic(ufmt.Sprintf("reply limit reached: %d per post", MaxRepliesPerPost))
		}
	}

	id := nextPostID
	nextPostID++

	p := &Post{
		ID:      id,
		Author:  caller,
		Body:    body,
		ReplyTo: replyTo,
		BlockH:  now,
	}
	posts.Set(padID(id), p)
	addToLiveIndexes(p)
	lastPostH.Set(caller.String(), now)

	chain.Emit("PostCreated",
		"postId", strconv.FormatUint(id, 10),
		"author", caller.String(),
		"replyTo", strconv.FormatUint(replyTo, 10),
		"body", body,
	)
	return id
}

// EditPost lets the author replace the body of a visible post.
func EditPost(cur realm, id uint64, newBody string) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	p := mustGetPost(id)
	if p.Author != caller {
		panic("only the author can edit")
	}
	if p.Deleted {
		panic("cannot edit a deleted post")
	}
	if p.Hidden {
		panic("cannot edit a hidden post")
	}
	if len(newBody) == 0 || len(newBody) > MaxBodyLen {
		panic(ufmt.Sprintf("body must be 1-%d characters", MaxBodyLen))
	}

	p.Body = newBody
	p.EditedAt = runtime.ChainHeight()
	posts.Set(padID(id), p)

	chain.Emit("PostEdited",
		"postId", strconv.FormatUint(id, 10),
		"author", caller.String(),
		"body", newBody,
	)
}

// DeletePost soft-deletes the author's own post: content cleared, dropped from
// every live index (frees render slots immediately — B1), queued for hard-GC
// (B2). Replies stay: they render as replies to an unavailable post.
func DeletePost(cur realm, id uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()

	p := mustGetPost(id)
	if p.Author != caller {
		panic("only the author can delete")
	}
	if p.Deleted {
		panic("post already deleted")
	}

	removeFromLiveIndexes(p)
	p.Deleted = true
	p.Body = ""
	p.MediaCIDs = nil
	posts.Set(padID(id), p)
	tombstones.Set(padID(id), true)

	chain.Emit("PostDeleted",
		"postId", strconv.FormatUint(id, 10),
		"author", caller.String(),
	)
}

// ── Flag pipeline ────────────────────────────────────────────

// FlagPost files a community flag. Guards, in order:
//   - flag rights are EARNED BY PARTICIPATION: the caller must have a
//     firstSeen record (anchored by their first successful CreatePost) at
//     least MinAccountAgeForFlag blocks old. A failed flag cannot anchor age
//     itself — an on-chain abort reverts every write in the tx, so recording
//     firstSeen here and then panicking would revert the record and deadlock
//     pure flaggers; requiring a prior post is the honest, implementable
//     account-age gate (realms cannot query global account age);
//   - one flag per address per post;
//   - per-day flag budget per address (blunts coordinated flag-brigades).
//
// At FlagThreshold unique flags the post auto-hides (reversible via UnhidePost).
func FlagPost(cur realm, id uint64) {
	assertNotPaused()
	caller := unsafe.PreviousRealm().Address()
	now := runtime.ChainHeight()

	if accountAge(caller, now) < MinAccountAgeForFlag {
		panic(ufmt.Sprintf("flagging requires having posted at least %d blocks ago", MinAccountAgeForFlag))
	}

	p := mustGetPost(id)
	if p.Deleted {
		panic("cannot flag a deleted post")
	}
	if p.Hidden {
		panic("post is already hidden")
	}

	// Per-day budget window.
	var fb *flagBudget
	if v, ok := flagSpend.Get(caller.String()); ok {
		fb = v.(*flagBudget)
	} else {
		fb = &flagBudget{DayStartH: now}
	}
	if now-fb.DayStartH >= BlocksPerDay {
		fb.DayStartH = now
		fb.Used = 0
	}
	if fb.Used >= FlagsPerDayBudget {
		panic(ufmt.Sprintf("daily flag budget reached: %d per %d blocks", FlagsPerDayBudget, BlocksPerDay))
	}

	// Unique flaggers per post.
	var flagTree *avl.Tree
	if v, ok := flags.Get(padID(id)); ok {
		flagTree = v.(*avl.Tree)
	} else {
		flagTree = avl.NewTree()
	}
	if _, already := flagTree.Get(caller.String()); already {
		panic("already flagged")
	}
	flagTree.Set(caller.String(), true)
	flags.Set(padID(id), flagTree)

	fb.Used++
	flagSpend.Set(caller.String(), fb)

	p.FlagCount = flagTree.Size()
	wasHidden := p.Hidden
	if p.FlagCount >= FlagThreshold {
		p.Hidden = true
		removeFromLiveIndexes(p)
		// A flag-hidden post is deliberately NOT tombstoned: its node and its
		// `flags` subtree (the flagger set) are retained on purpose as the audit
		// trail the W8.2 moderation board reviews (and UnhidePost needs, to
		// reverse a brigade). It leaves the live indexes (B1 render bounds still
		// hold), so this is bounded, intentional retention — not a leak. Author
		// delete / mod-remove are the paths that tombstone for GC.
	}
	posts.Set(padID(id), p)

	chain.Emit("PostFlagged",
		"postId", strconv.FormatUint(id, 10),
		"flagger", caller.String(),
		"flagCount", strconv.Itoa(p.FlagCount),
	)
	if !wasHidden && p.Hidden {
		chain.Emit("PostAutoHidden", "postId", strconv.FormatUint(id, 10))
	}
}

// ── Reactions (one-per-emoji toggle; open-write, gas is the throttle) ─
//
// A wallet may add each supported emoji at most once per post, and remove it
// again. Reactions carry no content (no DoS/GDPR surface like a post body), so
// there is no account-age gate — the per-(post,emoji,addr) dedup plus the gas
// cost of an on-chain tx are the throttle. Per-emoji COUNTS are aggregated
// off-chain by the indexer from the events below; the realm NEVER scans a
// post's reaction set, so the B1 render bounds are untouched.

// reactionEmojis is the fixed on-chain reaction set. Changing it is a realm
// version bump (redeploy), so it is deliberately small and stable.
var reactionEmojis = []string{"👍", "❤️", "😂", "😮", "😢", "🔥", "🎉", "👀", "🚀"}

func isReactionEmoji(e string) bool {
	for _, r := range reactionEmojis {
		if r == e {
			return true
		}
	}
	return false
}

// reactionSubKey namespaces a reactor's entry within a post's reaction tree.
// The NUL separator cannot appear in a fixed-set emoji or a bech32 address, so
// (emoji, addr) round-trips unambiguously.
func reactionSubKey(emoji string, addr address) string {
	return emoji + "\x00" + addr.String()
}

// HasReacted reports whether addr currently has the given emoji on the post.
// O(log n) point lookup — never a scan.
func HasReacted(id uint64, emoji string, addr address) bool {
	v, ok := reactions.Get(padID(id))
	if !ok {
		return false
	}
	_, exists := v.(*avl.Tree).Get(reactionSubKey(emoji, addr))
	return exists
}

// AddReaction records the caller's emoji reaction. A repeat aborts (rather than
// no-op) so an optimistic client's double-tap cannot silently burn gas twice —
// the client gates the button on HasReacted / indexed state.
func AddReaction(cur realm, id uint64, emoji string) {
	assertNotPaused()
	if !isReactionEmoji(emoji) {
		panic("unsupported reaction")
	}
	caller := unsafe.PreviousRealm().Address()
	now := runtime.ChainHeight()

	p := mustGetPost(id)
	if p.Deleted {
		panic("cannot react to a deleted post")
	}
	if p.Hidden {
		panic("cannot react to a hidden post")
	}
	touchFirstSeen(caller, now)

	var tree *avl.Tree
	if v, ok := reactions.Get(padID(id)); ok {
		tree = v.(*avl.Tree)
	} else {
		tree = avl.NewTree()
	}
	key := reactionSubKey(emoji, caller)
	if _, already := tree.Get(key); already {
		panic("already reacted with this emoji")
	}
	tree.Set(key, true)
	reactions.Set(padID(id), tree)

	chain.Emit("ReactionAdded",
		"postId", strconv.FormatUint(id, 10),
		"emoji", emoji,
		"by", caller.String(),
	)
}

// RemoveReaction removes the caller's emoji reaction (toggle-off). Allowed even
// on a hidden/deleted post so a reactor can always retract; aborts if the caller
// had not reacted with that emoji.
func RemoveReaction(cur realm, id uint64, emoji string) {
	assertNotPaused()
	if !isReactionEmoji(emoji) {
		panic("unsupported reaction")
	}
	caller := unsafe.PreviousRealm().Address()
	mustGetPost(id) // aborts if the post never existed

	v, ok := reactions.Get(padID(id))
	if !ok {
		panic("you have not reacted to this post")
	}
	tree := v.(*avl.Tree)
	key := reactionSubKey(emoji, caller)
	if _, exists := tree.Get(key); !exists {
		panic("you have not reacted with this emoji")
	}
	tree.Remove(key)
	if tree.Size() == 0 {
		reactions.Remove(padID(id)) // GC the empty subtree
	} else {
		reactions.Set(padID(id), tree)
	}

	chain.Emit("ReactionRemoved",
		"postId", strconv.FormatUint(id, 10),
		"emoji", emoji,
		"by", caller.String(),
	)
}

// ── Moderator role (W8.2) ────────────────────────────────────
// The owner grants/revokes moderator addresses that can ModRemovePost /
// UnhidePost. Fast (no owner-multisig-per-post) and reversible; grant/revoke
// stays owner-only. Every mutation is emitted for public audit.

func assertCallerIsOwnerOrModerator() {
	caller := unsafe.PreviousRealm().Address()
	if caller == owner {
		return
	}
	if _, ok := moderators.Get(caller.String()); ok {
		return
	}
	panic("unauthorized: caller " + caller.String() + " is not the owner or a moderator")
}

// IsModerator reports whether addr currently holds the moderator role.
func IsModerator(addr address) bool {
	_, ok := moderators.Get(addr.String())
	return ok
}

// AddModerator grants the moderator role (owner only).
func AddModerator(cur realm, addr address) {
	assertCallerIsOwner()
	if addr == "" {
		panic("address cannot be empty")
	}
	moderators.Set(addr.String(), true)
	chain.Emit("ModeratorAdded", "moderator", addr.String(), "by", owner.String())
}

// RemoveModerator revokes the moderator role (owner only).
func RemoveModerator(cur realm, addr address) {
	assertCallerIsOwner()
	if _, ok := moderators.Get(addr.String()); !ok {
		panic("address is not a moderator")
	}
	moderators.Remove(addr.String())
	chain.Emit("ModeratorRemoved", "moderator", addr.String(), "by", owner.String())
}

// ── Moderation (owner OR moderator; W8.2 hot-key lever) ───────

// ModRemovePost permanently hides a post by moderation. Emits an audited
// ModAction. The node is tombstoned for hard-GC like an author delete.
func ModRemovePost(cur realm, id uint64) {
	assertCallerIsOwnerOrModerator()

	p := mustGetPost(id)
	if !p.Deleted {
		removeFromLiveIndexes(p)
		tombstones.Set(padID(id), true)
	}
	p.Deleted = true
	p.Hidden = true
	p.Body = ""
	p.MediaCIDs = nil
	posts.Set(padID(id), p)

	chain.Emit("ModAction",
		"action", "remove",
		"postId", strconv.FormatUint(id, 10),
		"moderator", unsafe.PreviousRealm().Address().String(),
	)
}

// UnhidePost clears flags and restores a flag-hidden post to the live set.
func UnhidePost(cur realm, id uint64) {
	assertCallerIsOwnerOrModerator()

	p := mustGetPost(id)
	if p.Deleted {
		panic("cannot unhide a deleted post")
	}
	if !p.Hidden {
		panic("post is not hidden")
	}
	p.Hidden = false
	p.FlagCount = 0
	posts.Set(padID(id), p)
	flags.Remove(padID(id))
	addToLiveIndexes(p)

	chain.Emit("ModAction",
		"action", "unhide",
		"postId", strconv.FormatUint(id, 10),
		"moderator", unsafe.PreviousRealm().Address().String(),
	)
}

// ── Tombstone sweep (B2 hard-GC, ported from channels_v2) ────

// SweepTombstones hard-removes up to `limit` soft-deleted posts, reclaiming
// AVL storage so post+delete spam cannot accrete permanent state.
// Permissionless by design (state-shrink hygiene primitive, not a refund
// path). Bounded + idempotent: keep `limit` small (1-10); re-running drains
// the next batch and stops at 0. Returns the number of posts swept.
//
// For a swept post that was a PARENT, its surviving replies' byParent links
// (`padID(parent):padID(child)`) would otherwise be orphaned under an id no
// longer in `posts` — a permanent leak plus a read inconsistency (replies
// still enumerable, getReplyCount() disagreeing). So the sweep range-deletes
// that byParent prefix; the reply posts themselves stay as standalone live
// content (their parent was removed by its own author). Bounded because the
// live reply set per post is capped at MaxRepliesPerPost — but a reply-heavy
// parent makes one sweep step do up to that many removes, so keep `limit`
// small (1) when draining known reply-heavy tombstones.
func SweepTombstones(cur realm, limit int) int {
	assertNotPaused()
	if limit <= 0 {
		return 0
	}

	// Collect the oldest `limit` tombstoned ids (ascending), then mutate —
	// never remove from the tree we are iterating (AVL footgun).
	ids := []uint64{}
	tombstones.Iterate("", "", func(key string, _ interface{}) bool {
		ids = append(ids, idFromPadded(key))
		return len(ids) >= limit
	})

	for _, id := range ids {
		// Drop this parent's remaining child links (if any) so no byParent
		// entry outlives its parent. Collect-then-remove over the prefix.
		prefix := padID(id) + ":"
		childKeys := []string{}
		byParent.Iterate(prefix, prefix+"\xff", func(k string, _ interface{}) bool {
			childKeys = append(childKeys, k)
			return false
		})
		for _, k := range childKeys {
			byParent.Remove(k)
		}

		posts.Remove(padID(id))
		flags.Remove(padID(id))
		replyCount.Remove(padID(id))
		tombstones.Remove(padID(id))
	}

	if len(ids) > 0 {
		chain.Emit("TombstonesSwept", "count", strconv.Itoa(len(ids)))
	}
	return len(ids)
}

// GetTombstoneCount returns how many soft-deleted posts await hard-GC.
func GetTombstoneCount() int { return tombstones.Size() }

// ── JSON reads (vm/qeval; cursor-paginated, O(limit) at any depth) ──

// jsonEscape escapes a string for embedding in a JSON string literal.
func jsonEscape(s string) string {
	var sb strings.Builder
	for _, c := range s {
		switch c {
		case '"':
			sb.WriteString("\\\"")
		case '\\':
			sb.WriteString("\\\\")
		case '\n':
			sb.WriteString("\\n")
		case '\r':
			sb.WriteString("\\r")
		case '\t':
			sb.WriteString("\\t")
		default:
			if c < 0x20 {
				continue // drop raw control chars (ufmt has no \uXXXX support)
			}
			sb.WriteRune(c)
		}
	}
	return sb.String()
}

// postJSON is the qeval read fallback. Note it exposes `mediaCids` (P2) and
// `repostOf` (P1) which the CANONICAL indexed path (chain.Emit → backend →
// feed_rpc → UI) does NOT carry yet — PostCreated emits neither, the proto
// reserves repost_of, and there is no media column. A future dev wiring the
// qeval fallback must not assume those two are plumbed end-to-end.
func postJSON(p *Post) string {
	var media strings.Builder
	media.WriteString("[")
	for i, cid := range p.MediaCIDs {
		if i > 0 {
			media.WriteString(",")
		}
		media.WriteString("\"" + jsonEscape(cid) + "\"")
	}
	media.WriteString("]")

	return ufmt.Sprintf(
		`{"id":%d,"author":"%s","body":"%s","mediaCids":%s,"replyTo":%d,"repostOf":%d,"blockH":%d,"editedAt":%d,"flagCount":%d,"hidden":%s,"deleted":%s,"replies":%d}`,
		p.ID, p.Author.String(), jsonEscape(p.Body), media.String(),
		p.ReplyTo, p.RepostOf, p.BlockH, p.EditedAt, p.FlagCount,
		boolStr(p.Hidden), boolStr(p.Deleted), getReplyCount(p.ID),
	)
}

func boolStr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

func clampLimit(limit int) int {
	if limit <= 0 {
		return FeedPageSize
	}
	if limit > MaxPageLimit {
		return MaxPageLimit
	}
	return limit
}

// GetPostJSON returns one post (any state — the indexer needs tombstones too).
func GetPostJSON(id uint64) string {
	p, ok := getPost(id)
	if !ok {
		return "null"
	}
	return postJSON(p)
}

// listWindow walks `tree` REVERSE (newest first) starting below cursorKey
// ("" = from the newest), collecting up to limit ids via extract.
func listWindow(tree *avl.Tree, cursorKey string, limit int, extract func(key string) uint64) []uint64 {
	ids := []uint64{}
	count := 0
	tree.ReverseIterate("", cursorKey, func(key string, _ interface{}) bool {
		id := extract(key)
		if id != 0 {
			ids = append(ids, id)
			count++
		}
		return count >= limit
	})
	return ids
}

func idFromPadded(key string) uint64 {
	n, err := strconv.ParseUint(key, 10, 64)
	if err != nil {
		return 0
	}
	return n
}

func idFromComposite(key string) uint64 {
	i := strings.LastIndexByte(key, ':')
	if i < 0 {
		return 0
	}
	return idFromPadded(key[i+1:])
}

func idsToJSON(ids []uint64) string {
	var sb strings.Builder
	sb.WriteString("[")
	for i, id := range ids {
		if i > 0 {
			sb.WriteString(",")
		}
		if p, ok := getPost(id); ok {
			sb.WriteString(postJSON(p))
		}
	}
	sb.WriteString("]")
	return sb.String()
}

// ListFeedJSON returns the newest live posts strictly older than cursor
// (cursor == 0 → from the top). Pass the last id of the previous window as
// the next cursor.
//
// ReverseIterate treats BOTH bounds as inclusive (avl/v0 TraverseInRange), so
// "strictly older than cursor" = end bound padID(cursor-1): ids are integers,
// keys are fixed-width, hence key < padID(cursor) ⟺ key ≤ padID(cursor-1).
func ListFeedJSON(cursor uint64, limit int) string {
	limit = clampLimit(limit)
	cursorKey := ""
	if cursor != 0 {
		cursorKey = padID(cursor - 1)
	}
	return idsToJSON(listWindow(liveFeed, cursorKey, limit, idFromPadded))
}

// ListUserJSON returns a user's newest live posts strictly older than cursor
// (same inclusive-bound rule as ListFeedJSON).
func ListUserJSON(addr string, cursor uint64, limit int) string {
	limit = clampLimit(limit)
	cursorKey := ""
	if cursor != 0 {
		cursorKey = addr + ":" + padID(cursor-1)
	} else {
		// End bound just past every "addr:XXXXXXXXXXXX" key: ':' + 0xff.
		cursorKey = addr + ":\xff"
	}
	ids := []uint64{}
	count := 0
	byAuthor.ReverseIterate(addr+":", cursorKey, func(key string, _ interface{}) bool {
		if id := idFromComposite(key); id != 0 {
			ids = append(ids, id)
			count++
		}
		return count >= limit
	})
	return idsToJSON(ids)
}

// ListRepliesJSON returns a post's live replies, OLDEST first (conversation
// order), starting strictly after cursor (0 → from the beginning).
func ListRepliesJSON(parent uint64, cursor uint64, limit int) string {
	limit = clampLimit(limit)
	start := padID(parent) + ":"
	if cursor != 0 {
		start = parentKey(parent, cursor) + "\x00" // strictly after the cursor child
	}
	ids := []uint64{}
	count := 0
	byParent.Iterate(start, padID(parent)+":\xff", func(key string, _ interface{}) bool {
		if id := idFromComposite(key); id != 0 {
			ids = append(ids, id)
			count++
		}
		return count >= limit
	})
	return idsToJSON(ids)
}

// GetStatsJSON returns realm-level counters (monotonic id is informational —
// no read iterates it).
func GetStatsJSON() string {
	return ufmt.Sprintf(`{"livePosts":%d,"nextPostId":%d,"tombstones":%d,"paused":%s}`,
		liveCount, nextPostID, tombstones.Size(), boolStr(paused))
}

// ── Render (gnoweb human view; bounded — B1) ─────────────────
//
// Paths:
//   ""            → newest window (page 1)
//   page/K        → K-th newest window, K ≤ MaxRenderPage
//   user/ADDR     → ADDR's newest window
//   user/ADDR/K   → K-th window of ADDR's posts
//   post/ID       → one post + its newest reply window
//
// Every page scans at most MaxRenderPage*FeedPageSize live-index keys and
// fetches at most FeedPageSize posts — bounded regardless of feed size or
// churn (deleted/hidden posts are not in the live indexes at all).

func Render(path string) string {
	if path == "" {
		return renderFeedPage(1)
	}
	if strings.HasPrefix(path, "page/") {
		k, err := strconv.ParseUint(strings.TrimPrefix(path, "page/"), 10, 64)
		if err != nil || k == 0 {
			return "# 404\nBad page"
		}
		return renderFeedPage(k)
	}
	if strings.HasPrefix(path, "user/") {
		rest := strings.TrimPrefix(path, "user/")
		addr := rest
		k := uint64(1)
		if i := strings.IndexByte(rest, '/'); i >= 0 {
			addr = rest[:i]
			n, err := strconv.ParseUint(rest[i+1:], 10, 64)
			if err != nil || n == 0 {
				return "# 404\nBad page"
			}
			k = n
		}
		return renderUserPage(addr, k)
	}
	if strings.HasPrefix(path, "post/") {
		id, err := strconv.ParseUint(strings.TrimPrefix(path, "post/"), 10, 64)
		if err != nil {
			return "# 404\nBad post id"
		}
		return renderPost(id)
	}
	return "# 404\nPage not found: " + path
}

// collectPage walks a live index reverse and returns the ids for window k
// (1-based). Scan is bounded: k is capped at MaxRenderPage by callers.
func collectPage(tree *avl.Tree, prefix, endKey string, k uint64) []uint64 {
	skip := (k - 1) * FeedPageSize
	ids := []uint64{}
	seen := uint64(0)
	tree.ReverseIterate(prefix, endKey, func(key string, _ interface{}) bool {
		if seen >= skip {
			var id uint64
			if prefix == "" {
				id = idFromPadded(key)
			} else {
				id = idFromComposite(key)
			}
			if id != 0 {
				ids = append(ids, id)
			}
		}
		seen++
		return len(ids) >= FeedPageSize
	})
	return ids
}

func renderPostLine(sb *strings.Builder, p *Post) {
	sb.WriteString(ufmt.Sprintf("**%s** (block %d)", truncAddr(p.Author), p.BlockH))
	if p.EditedAt != 0 {
		sb.WriteString(" *(edited)*")
	}
	if p.ReplyTo != 0 {
		sb.WriteString(ufmt.Sprintf(" — reply to [post %d](:post/%d)", p.ReplyTo, p.ReplyTo))
	}
	sb.WriteString("\n\n")
	sb.WriteString(sanitizeForRender(p.Body) + "\n\n")
	rc := getReplyCount(p.ID)
	sb.WriteString(ufmt.Sprintf("[permalink](:post/%d) | %d replies\n\n---\n\n", p.ID, rc))
}

func renderFeedPage(k uint64) string {
	if k > MaxRenderPage {
		return ufmt.Sprintf("# Memba Feed\n\n*Pages beyond %d are not rendered — use the JSON cursor API (ListFeedJSON) or the Memba app.*\n", MaxRenderPage)
	}
	var sb strings.Builder
	sb.WriteString("# Memba Feed\n\n")
	sb.WriteString(ufmt.Sprintf("**Live posts:** %d\n\n", liveCount))

	ids := collectPage(liveFeed, "", "", k)
	if len(ids) == 0 {
		sb.WriteString("*No posts on this page.*\n")
		return sb.String()
	}
	for _, id := range ids {
		if p, ok := getPost(id); ok {
			renderPostLine(&sb, p)
		}
	}
	sb.WriteString(ufmt.Sprintf("*page %d — older: `:page/%d`*\n", k, k+1))
	return sb.String()
}

func renderUserPage(addr string, k uint64) string {
	if k > MaxRenderPage {
		return ufmt.Sprintf("# Feed — %s\n\n*Pages beyond %d are not rendered — use ListUserJSON or the Memba app.*\n", addr, MaxRenderPage)
	}
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Feed — %s\n\n", addr))
	ids := collectPage(byAuthor, addr+":", addr+":\xff", k)
	if len(ids) == 0 {
		sb.WriteString("*No posts on this page.*\n")
		return sb.String()
	}
	for _, id := range ids {
		if p, ok := getPost(id); ok {
			renderPostLine(&sb, p)
		}
	}
	sb.WriteString(ufmt.Sprintf("*page %d — older: `:user/%s/%d`*\n", k, addr, k+1))
	return sb.String()
}

func renderPost(id uint64) string {
	p, ok := getPost(id)
	if !ok {
		return "# 404\nPost not found"
	}
	// Same suppression rule as channels_v2: the direct path must not leak
	// hidden/deleted content.
	if p.Hidden || p.Deleted {
		return "# Post unavailable\n\n*This post has been hidden or removed.*\n"
	}

	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Post %d\n\n", p.ID))
	renderPostLine(&sb, p)

	// Newest reply window only (fixed size); full thread = JSON cursor API.
	rc := getReplyCount(p.ID)
	if rc > 0 {
		sb.WriteString("## Replies\n\n")
		if rc > FeedPageSize {
			sb.WriteString(ufmt.Sprintf("*Showing the %d newest of %d — full thread via ListRepliesJSON or the app.*\n\n", FeedPageSize, rc))
		}
		ids := collectPage(byParent, padID(p.ID)+":", padID(p.ID)+":\xff", 1)
		// collectPage walks reverse (newest first); show oldest→newest.
		for i := len(ids) - 1; i >= 0; i-- {
			if r, ok := getPost(ids[i]); ok {
				renderPostLine(&sb, r)
			}
		}
	}
	return sb.String()
}

// ── Shared render helpers (ported verbatim from channels_v2) ─

func truncAddr(addr address) string {
	s := string(addr)
	if len(s) > 13 {
		return s[:10] + "..."
	}
	return s
}

// sanitizeForRender strips markdown-sensitive characters to prevent injection.
func sanitizeForRender(s string) string {
	var out strings.Builder
	for _, c := range s {
		switch c {
		case '[', ']', '(', ')', '#', '*', '`', '!', '<', '>', '|', '\\', '_', '~', '\n', '\r', '\t':
			continue
		default:
			out.WriteRune(c)
		}
	}
	return out.String()
}

package memba_appstore_v1

import "chain"

// Admin surface — owner-gated. The owner is the samcrew multisig at launch and can
// be handed to the memba_dao executor via the 2-step TransferOwnership/AcceptOwnership
// (never a 1-step transfer to a mistyped/dead address).

// SetRegistrationFee sets the flat listing fee in ugnot (0..MaxRegistrationFee).
// Zero is allowed (a fee waiver). Owner only.
func SetRegistrationFee(cur realm, fee int64) {
	assertOwner()
	if fee < 0 || fee > MaxRegistrationFee {
		panic("fee out of range [0, MaxRegistrationFee]")
	}
	registrationFee = fee
	chain.Emit("RegistrationFeeSet", "fee", itoa64(uint64(fee)))
}

// SetTreasury repoints the fee recipient. Must be non-empty (an empty treasury would
// fail-close RegisterApp). Owner only. Keep this in sync with
// memba_market_config.GetTreasury().
func SetTreasury(cur realm, addr address) {
	assertOwner()
	if addr == "" {
		panic("treasury must be non-empty")
	}
	treasury = addr
	chain.Emit("TreasurySet", "treasury", addr.String())
}

// AddCurator grants the curate role (approve pending listings). Owner only.
func AddCurator(cur realm, addr address) {
	assertOwner()
	if addr == "" {
		panic("curator must be non-empty")
	}
	curators.Set(addr.String(), true)
	chain.Emit("CuratorAdded", "curator", addr.String())
}

// RemoveCurator revokes the curate role. Owner only.
func RemoveCurator(cur realm, addr address) {
	assertOwner()
	curators.Remove(addr.String())
	chain.Emit("CuratorRemoved", "curator", addr.String())
}

// Pause is the kill switch: while paused, RegisterApp aborts (reads stay available).
// Owner only.
func Pause(cur realm, state bool) {
	assertOwner()
	paused = state
	chain.Emit("PauseSet", "paused", boolStr(state))
}

// TransferOwnership stages a new owner; it takes effect only after AcceptOwnership
// is called BY that address (2-step, so a typo can't brick admin).
func TransferOwnership(cur realm, newOwner address) {
	assertOwner()
	if newOwner == "" {
		panic("newOwner must be non-empty")
	}
	pendingOwner = newOwner
	chain.Emit("OwnershipTransferStarted", "pending", newOwner.String())
}

// AcceptOwnership completes the handoff. Only the staged pendingOwner may call it.
func AcceptOwnership(cur realm) {
	if pendingOwner == "" {
		panic("no pending ownership transfer")
	}
	if caller() != pendingOwner {
		panic("unauthorized: only the pending owner may accept")
	}
	owner = pendingOwner
	pendingOwner = ""
	chain.Emit("OwnershipTransferAccepted", "owner", owner.String())
}

func boolStr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

// Package memba_appstore_v1 is a curated App Store for gno.land dApps: publishers
// pay a flat listing fee to register an app; a curator flips it live.
//
// MONEY PATH (the only one): RegisterApp collects a flat `registrationFee` in ugnot
// and forwards 100% to the treasury in the SAME call — nothing is ever custodied.
// The safety contract mirrors memba_token_otc_v1 + the O-13 lesson:
//   1. IsUserCall() guard BEFORE reading OriginSend — an ephemeral `maketx run`
//      realm can never attach unrecoverable coins (the guard agent_registry missed).
//   2. exact-coin via unsafe.OriginSend() (the coins on THIS call, not the wallet
//      balance) — closes the overpay-trap and the wallet-balance bypass.
//   3. treasury-misconfig is fail-closed: an unset treasury panics (→ tx reverts →
//      coins refunded), never silent custody.
//   4. CEI: state is written before the banker moves funds.
//   5. NewBanker(RealmSend, cur) sends the fee from the realm's own address to the
//      treasury — no custody, no escrow (which is why no escrow is needed to be safe).
//
// TREASURY: stored LOCALLY (admin-settable, 2-step handoff, defaults to the samcrew
// multisig) rather than read from memba_market_config — this keeps the realm
// self-contained so the whole money path is unit-tested locally. Keep it in sync with
// memba_market_config.GetTreasury(); a future version may read the fee spine directly
// (which makes the realm non-locally-testable — a deliberate later trade-off).
package memba_appstore_v1

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"
)

// AdminAddress is the samcrew-core 2-of-2 multisig (same as the fee spine's admin/
// treasury). It is the initial owner AND the initial treasury.
const AdminAddress = "g10kw7e55e9wc8j8v6904ck29dqwr9fm9u280juh"

const (
	// DefaultRegistrationFee is the launch listing fee: 1 GNOT (1_000_000 ugnot).
	// The DAO/admin can change it via SetRegistrationFee (bounded by MaxRegistrationFee).
	DefaultRegistrationFee = int64(1_000_000)
	// MaxRegistrationFee caps a fat-finger / compromised-proposal fee at 100 GNOT.
	MaxRegistrationFee = int64(100_000_000)

	MaxNameLen    = 80
	MaxTaglineLen = 140
	MaxDescrLen   = 2000
	MaxURLLen     = 400
	MaxPkgPathLen = 200
	MaxCIDLen     = 100
	// FlagHideThreshold auto-hides a listing from the live list once this many
	// distinct addresses have flagged it (a curator can DelistApp / restore).
	FlagHideThreshold = 5
)

// StatusPending / StatusLive / StatusDelisted are the listing lifecycle states.
const (
	StatusPending  = "pending"
	StatusLive     = "live"
	StatusDelisted = "delisted"
)

// Listing is one app. PkgPath (the realm/package path) is the unique key.
type Listing struct {
	Id        uint64
	PkgPath   string
	Name      string
	Tagline   string
	Descr     string
	Category  string
	IconCID   string
	AppURL    string
	Publisher address
	Status    string
	FlagCount int
	CreatedAt int64
}

var (
	owner            address
	pendingOwner     address
	treasury         address
	registrationFee  int64
	paused           bool
	curators         = avl.NewTree() // address string -> bool
	listings         = avl.NewTree() // pkgPath -> *Listing
	flaggedBy        = avl.NewTree() // pkgPath + "\x00" + addr -> bool (one flag per addr)
	nextId    uint64 = 1
)

func init() {
	owner = address(AdminAddress)
	treasury = address(AdminAddress)
	registrationFee = DefaultRegistrationFee
	curators.Set(AdminAddress, true) // the admin is a curator by default
}

func caller() address { return unsafe.PreviousRealm().Address() }

func assertOwner() {
	if caller() != owner {
		panic("unauthorized: owner only")
	}
}

func assertNotPaused() {
	if paused {
		panic("appstore is paused")
	}
}

// ── Money path ────────────────────────────────────────────────────────────────

// RegisterApp lists a new app. The caller pays EXACTLY registrationFee ugnot with
// the call; the whole fee is forwarded to the treasury (no custody). The listing
// starts `pending` and is not shown live until a curator approves it.
func RegisterApp(
	cur realm,
	pkgPath, name, tagline, descr, category, iconCID, appURL string,
) uint64 {
	assertNotPaused()

	// O-13 guard: a payable entrypoint MUST be a direct user call, so an ephemeral
	// `maketx run` realm can never attach coins that become unrecoverable.
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("RegisterApp must be a direct user call")
	}

	pkgPath = validatePkgPath(pkgPath)
	if _, dup := listings.Get(pkgPath); dup {
		panic("app already registered for this package path")
	}
	if len(name) == 0 || len(name) > MaxNameLen {
		panic("name must be 1.." + itoa(MaxNameLen) + " chars")
	}
	if len(tagline) > MaxTaglineLen {
		panic("tagline too long")
	}
	if len(descr) > MaxDescrLen {
		panic("description too long")
	}
	if len(appURL) > MaxURLLen {
		panic("appURL too long")
	}
	if len(iconCID) > MaxCIDLen {
		panic("iconCID too long")
	}

	// Exact-coin: read the coins attached to THIS call (not the wallet balance).
	sent := unsafe.OriginSend()
	if sent.AmountOf("ugnot") != registrationFee {
		panic(ufmt.Sprintf("must send exactly %d ugnot (sent %d)", registrationFee, sent.AmountOf("ugnot")))
	}
	// Fail-closed on a misconfigured treasury — reverting refunds the coins; we never
	// keep custody of a fee we can't route.
	if treasury == "" {
		panic("treasury unset — registration disabled")
	}

	// CEI: write state before moving funds.
	id := nextId
	nextId++
	l := &Listing{
		Id:        id,
		PkgPath:   pkgPath,
		Name:      name,
		Tagline:   tagline,
		Descr:     descr,
		Category:  category,
		IconCID:   iconCID,
		AppURL:    appURL,
		Publisher: caller(),
		Status:    StatusPending,
		CreatedAt: runtime.ChainHeight(),
	}
	listings.Set(pkgPath, l)

	// Forward the whole fee to the treasury from the realm's own account.
	if registrationFee > 0 {
		bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
		bnk.SendCoins(
			unsafe.CurrentRealm().Address(),
			treasury,
			chain.Coins{chain.NewCoin("ugnot", registrationFee)},
		)
	}

	chain.Emit("AppRegistered", "pkgPath", pkgPath, "id", itoa64(id), "publisher", caller().String())
	return id
}

// ── Curation & moderation ───────────────────────────────────────────────────

// ApproveApp flips a pending listing live. Curator-only.
func ApproveApp(cur realm, pkgPath string) {
	if !isCurator(caller()) {
		panic("unauthorized: curator only")
	}
	l := mustGet(pkgPath)
	if l.Status == StatusDelisted {
		panic("cannot approve a delisted app")
	}
	l.Status = StatusLive
	listings.Set(pkgPath, l)
	chain.Emit("AppApproved", "pkgPath", pkgPath)
}

// DelistApp removes a listing from public view. The publisher or a curator may do it.
func DelistApp(cur realm, pkgPath string) {
	l := mustGet(pkgPath)
	if caller() != l.Publisher && !isCurator(caller()) {
		panic("unauthorized: publisher or curator only")
	}
	l.Status = StatusDelisted
	listings.Set(pkgPath, l)
	chain.Emit("AppDelisted", "pkgPath", pkgPath)
}

// RestoreApp brings a delisted app back to `pending` (re-curation required before it
// shows live again). Curator-only — this is the reverse of DelistApp, so a mistaken
// or contested delist is recoverable.
func RestoreApp(cur realm, pkgPath string) {
	if !isCurator(caller()) {
		panic("unauthorized: curator only")
	}
	l := mustGet(pkgPath)
	if l.Status != StatusDelisted {
		panic("only a delisted app can be restored")
	}
	l.Status = StatusPending
	listings.Set(pkgPath, l)
	chain.Emit("AppRestored", "pkgPath", pkgPath)
}

// FlagApp lets any user flag a LIVE listing once. At FlagHideThreshold distinct flags
// the listing stops appearing live; a curator then DelistApp's it or leaves it for
// review (a delisted app can be brought back with RestoreApp).
func FlagApp(cur realm, pkgPath string) {
	l := mustGet(pkgPath)
	if l.Status != StatusLive {
		panic("can only flag a live app")
	}
	key := pkgPath + "\x00" + caller().String()
	if _, done := flaggedBy.Get(key); done {
		panic("already flagged")
	}
	flaggedBy.Set(key, true)
	l.FlagCount++
	listings.Set(pkgPath, l)
	chain.Emit("AppFlagged", "pkgPath", pkgPath, "count", itoa(l.FlagCount))
}

// isVisible reports whether a listing shows in the live list.
func isVisible(l *Listing) bool {
	return l.Status == StatusLive && l.FlagCount < FlagHideThreshold
}

// ── Read getters (pure, non-failing) ─────────────────────────────────────────

// GetRegistrationFee returns the current flat listing fee in ugnot.
func GetRegistrationFee() int64 { return registrationFee }

// GetTreasury returns the address that receives listing fees.
func GetTreasury() address { return treasury }

// GetOwner returns the current owner (multisig, or a DAO executor after handoff).
func GetOwner() address { return owner }

// AppCount returns the total number of registered listings (any status).
func AppCount() int { return listings.Size() }

// GetStatsJSON returns a small stats object for a status header.
func GetStatsJSON() string {
	live := 0
	listings.Iterate("", "", func(_ string, v any) bool {
		if isVisible(v.(*Listing)) {
			live++
		}
		return false
	})
	return ufmt.Sprintf(`{"total":%d,"live":%d,"registrationFee":%d,"paused":%t}`,
		listings.Size(), live, registrationFee, paused)
}

// ── internal helpers ─────────────────────────────────────────────────────────

func isCurator(a address) bool {
	_, ok := curators.Get(a.String())
	return ok
}

func mustGet(pkgPath string) *Listing {
	v, ok := listings.Get(pkgPath)
	if !ok {
		panic("app not found: " + pkgPath)
	}
	return v.(*Listing)
}

// validatePkgPath normalizes + sanity-checks a realm/package path.
func validatePkgPath(p string) string {
	if len(p) == 0 || len(p) > MaxPkgPathLen {
		panic("pkgPath must be 1.." + itoa(MaxPkgPathLen) + " chars")
	}
	// Must be a gno.land realm ("/r/") or package ("/p/") path.
	if !hasPrefix(p, "gno.land/r/") && !hasPrefix(p, "gno.land/p/") {
		panic("pkgPath must be a gno.land/r/... or gno.land/p/... path")
	}
	return p
}

func hasPrefix(s, pre string) bool {
	return len(s) >= len(pre) && s[:len(pre)] == pre
}

func itoa(n int) string    { return ufmt.Sprintf("%d", n) }
func itoa64(n uint64) string { return ufmt.Sprintf("%d", n) }

package memba_appstore_v1

import (
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

const (
	DefaultPageSize = 20  // default JSON window
	MaxPageLimit    = 100 // hard cap on any JSON read window (read-DoS guard)
)

func clampLimit(limit int) int {
	if limit <= 0 {
		return DefaultPageSize
	}
	if limit > MaxPageLimit {
		return MaxPageLimit
	}
	return limit
}

// jsonEscape escapes a string for embedding in a JSON string literal — every
// listing text field is attacker-supplied, so this is the only thing between a
// malicious name/tagline and a broken/injected JSON payload on the read path.
func jsonEscape(s string) string {
	var sb strings.Builder
	for _, r := range s {
		switch r {
		case '"':
			sb.WriteString("\\\"")
		case '\\':
			sb.WriteString("\\\\")
		case '\n':
			sb.WriteString("\\n")
		case '\r':
			sb.WriteString("\\r")
		case '\t':
			sb.WriteString("\\t")
		default:
			if r < 0x20 {
				sb.WriteString(ufmt.Sprintf("\\u%04x", r))
			} else {
				sb.WriteString(string(r))
			}
		}
	}
	return sb.String()
}

// listingJSON renders one listing. `full` adds the (large) description — omitted
// from list windows so a bounded page stays small.
func listingJSON(l *Listing, full bool) string {
	descr := ""
	if full {
		descr = ufmt.Sprintf(`,"descr":"%s"`, jsonEscape(l.Descr))
	}
	return ufmt.Sprintf(
		`{"id":%d,"pkgPath":"%s","name":"%s","tagline":"%s","category":"%s","iconCID":"%s","appURL":"%s","publisher":"%s","status":"%s","flagCount":%d,"createdAt":%d%s}`,
		l.Id,
		jsonEscape(l.PkgPath),
		jsonEscape(l.Name),
		jsonEscape(l.Tagline),
		jsonEscape(l.Category),
		jsonEscape(l.IconCID),
		jsonEscape(l.AppURL),
		l.Publisher.String(),
		l.Status,
		l.FlagCount,
		l.CreatedAt,
		descr,
	)
}

// ListLiveJSON returns a bounded JSON array of the visible (live, un-hidden)
// listings: skip `offset`, take up to clamped `limit`. Iteration stops as soon as
// the window is filled, so the scan is bounded by offset+limit regardless of
// catalog size.
func ListLiveJSON(offset, limit int) string {
	if offset < 0 {
		offset = 0
	}
	limit = clampLimit(limit)

	var sb strings.Builder
	sb.WriteString("[")
	skipped := 0
	taken := 0
	first := true
	listings.Iterate("", "", func(_ string, v any) bool {
		l := v.(*Listing)
		if !isVisible(l) {
			return false
		}
		if skipped < offset {
			skipped++
			return false
		}
		if taken >= limit {
			return true // window full — stop
		}
		if !first {
			sb.WriteString(",")
		}
		first = false
		sb.WriteString(listingJSON(l, false))
		taken++
		return false
	})
	sb.WriteString("]")
	return sb.String()
}

// GetListingJSON returns a single listing (any status) with its description, or
// the JSON literal `null` if the package path is not registered.
func GetListingJSON(pkgPath string) string {
	v, ok := listings.Get(pkgPath)
	if !ok {
		return "null"
	}
	return listingJSON(v.(*Listing), true)
}

package memba_appstore_v1

import (
	"chain/runtime"

	"gno.land/p/nt/ufmt/v0"
)

// RenderMaxRows bounds the Render() output so a large catalog can never make the
// realm render-DoS (mirrors the feed's live-only bounded render).
const RenderMaxRows = 100

// Render shows the live catalog (bounded) — a read-only trust surface for gnoweb.
// The frontend reads structured data via the getters, not this markdown.
func Render(path string) string {
	sb := ""
	sb += "# Memba App Store\n\n"
	sb += ufmt.Sprintf("Curated gno.land dApps. **Listing fee:** %d ugnot → treasury.\n\n", registrationFee)
	if paused {
		sb += "> ⏸️ Registration is paused.\n\n"
	}

	rows := 0
	live := 0
	sb += "| App | Package | Category |\n|---|---|---|\n"
	listings.Iterate("", "", func(_ string, v any) bool {
		l := v.(*Listing)
		if !isVisible(l) {
			return false
		}
		live++
		if rows >= RenderMaxRows {
			return false // stop appending, keep counting via the header below
		}
		rows++
		sb += ufmt.Sprintf("| %s | `%s` | %s |\n", esc(l.Name), esc(l.PkgPath), esc(l.Category))
		return false
	})

	if live == 0 {
		sb += "\n*No live apps yet.*\n"
	} else {
		sb += ufmt.Sprintf("\n*%d live app(s)%s. Block %d.*\n", live, moreNote(live), runtime.ChainHeight())
	}
	return sb
}

func moreNote(live int) string {
	if live > RenderMaxRows {
		return ufmt.Sprintf(" (showing first %d)", RenderMaxRows)
	}
	return ""
}

// esc neutralizes the markdown/table metachars that could break the table or inject
// layout from an attacker-supplied listing field.
func esc(s string) string {
	out := ""
	for _, r := range s {
		switch r {
		case '|':
			out += "\\|"
		case '\n', '\r':
			out += " "
		case '`':
			out += "'"
		default:
			out += string(r)
		}
	}
	return out
}

package memba_appstore_v2

import "chain"

// Admin surface — owner-gated. The owner is the samcrew multisig at launch and can
// be handed to the memba_dao executor via the 2-step TransferOwnership/AcceptOwnership
// (never a 1-step transfer to a mistyped/dead address).

// SetRegistrationFee sets the flat listing fee in ugnot (0..MaxRegistrationFee).
// Zero is allowed (a fee waiver). Owner only.
func SetRegistrationFee(cur realm, fee int64) {
	assertOwner()
	if fee < 0 || fee > MaxRegistrationFee {
		panic("fee out of range [0, MaxRegistrationFee]")
	}
	registrationFee = fee
	chain.Emit("RegistrationFeeSet", "fee", itoa64(uint64(fee)))
}

// SetTreasury repoints the fee recipient. Must be non-empty (an empty treasury would
// fail-close RegisterApp). Owner only. Keep this in sync with
// memba_market_config.GetTreasury().
func SetTreasury(cur realm, addr address) {
	assertOwner()
	if addr == "" {
		panic("treasury must be non-empty")
	}
	treasury = addr
	chain.Emit("TreasurySet", "treasury", addr.String())
}

// AddCurator grants the curate role (approve pending listings). Owner only.
func AddCurator(cur realm, addr address) {
	assertOwner()
	if addr == "" {
		panic("curator must be non-empty")
	}
	curators.Set(addr.String(), true)
	chain.Emit("CuratorAdded", "curator", addr.String())
}

// RemoveCurator revokes the curate role. Owner only.
func RemoveCurator(cur realm, addr address) {
	assertOwner()
	curators.Remove(addr.String())
	chain.Emit("CuratorRemoved", "curator", addr.String())
}

// Pause is the kill switch: while paused, RegisterApp aborts (reads stay available).
// Owner only.
func Pause(cur realm, state bool) {
	assertOwner()
	paused = state
	chain.Emit("PauseSet", "paused", boolStr(state))
}

// TransferOwnership stages a new owner; it takes effect only after AcceptOwnership
// is called BY that address (2-step, so a typo can't brick admin).
func TransferOwnership(cur realm, newOwner address) {
	assertOwner()
	if newOwner == "" {
		panic("newOwner must be non-empty")
	}
	pendingOwner = newOwner
	chain.Emit("OwnershipTransferStarted", "pending", newOwner.String())
}

// AcceptOwnership completes the handoff. Only the staged pendingOwner may call it.
func AcceptOwnership(cur realm) {
	if pendingOwner == "" {
		panic("no pending ownership transfer")
	}
	if caller() != pendingOwner {
		panic("unauthorized: only the pending owner may accept")
	}
	owner = pendingOwner
	pendingOwner = ""
	chain.Emit("OwnershipTransferAccepted", "owner", owner.String())
}

func boolStr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

// Package memba_appstore_v2 is a curated App Store for gno.land dApps: publishers
// pay a flat listing fee to register an app; a curator flips it live.
//
// MONEY PATH (the only one): RegisterApp collects a flat `registrationFee` in ugnot
// and forwards 100% to the treasury in the SAME call — nothing is ever custodied.
// The safety contract mirrors memba_token_otc_v1 + the O-13 lesson:
//   1. IsUserCall() guard BEFORE reading OriginSend — an ephemeral `maketx run`
//      realm can never attach unrecoverable coins (the guard agent_registry missed).
//   2. exact-coin via unsafe.OriginSend() (the coins on THIS call, not the wallet
//      balance) — closes the overpay-trap and the wallet-balance bypass.
//   3. treasury-misconfig is fail-closed: an unset treasury panics (→ tx reverts →
//      coins refunded), never silent custody.
//   4. CEI: state is written before the banker moves funds.
//   5. NewBanker(RealmSend, cur) sends the fee from the realm's own address to the
//      treasury — no custody, no escrow (which is why no escrow is needed to be safe).
//
// TREASURY: stored LOCALLY (admin-settable, 2-step handoff, defaults to the samcrew
// multisig) rather than read from memba_market_config — this keeps the realm
// self-contained so the whole money path is unit-tested locally. Keep it in sync with
// memba_market_config.GetTreasury(); a future version may read the fee spine directly
// (which makes the realm non-locally-testable — a deliberate later trade-off).
package memba_appstore_v2

import (
	"chain"
	"chain/banker"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/samcrew/avl"
	"gno.land/p/nt/ufmt/v0"
)

// AdminAddress is the samcrew-core 2-of-2 multisig (same as the fee spine's admin/
// treasury). It is the initial owner AND the initial treasury.
const AdminAddress = "g1x7k4628w93a7wzdhqc06atzx0v50rnshweuxu0"

const (
	// DefaultRegistrationFee is the launch listing fee: 1 GNOT (1_000_000 ugnot).
	// The DAO/admin can change it via SetRegistrationFee (bounded by MaxRegistrationFee).
	DefaultRegistrationFee = int64(1_000_000)
	// MaxRegistrationFee caps a fat-finger / compromised-proposal fee at 100 GNOT.
	MaxRegistrationFee = int64(100_000_000)

	MaxNameLen    = 80
	MaxTaglineLen = 140
	MaxDescrLen   = 2000
	MaxURLLen     = 400
	MaxPkgPathLen = 200
	MaxCIDLen     = 100
	// FlagHideThreshold auto-hides a listing from the live list once this many
	// distinct addresses have flagged it (a curator can DelistApp / restore).
	FlagHideThreshold = 5
)

// StatusPending / StatusLive / StatusDelisted are the listing lifecycle states.
const (
	StatusPending  = "pending"
	StatusLive     = "live"
	StatusDelisted = "delisted"
)

// Listing is one app. PkgPath (the realm/package path) is the unique key.
type Listing struct {
	Id        uint64
	PkgPath   string
	Name      string
	Tagline   string
	Descr     string
	Category  string
	IconCID   string
	AppURL    string
	Publisher address
	Status    string
	FlagCount int
	CreatedAt int64
}

var (
	owner            address
	pendingOwner     address
	treasury         address
	registrationFee  int64
	paused           bool
	curators         = avl.NewTree() // address string -> bool
	listings         = avl.NewTree() // pkgPath -> *Listing
	flaggedBy        = avl.NewTree() // pkgPath + "\x00" + addr -> bool (one flag per addr)
	nextId    uint64 = 1
)

func init() {
	owner = address(AdminAddress)
	treasury = address(AdminAddress)
	registrationFee = DefaultRegistrationFee
	curators.Set(AdminAddress, true) // the admin is a curator by default
}

func caller() address { return unsafe.PreviousRealm().Address() }

func assertOwner() {
	if caller() != owner {
		panic("unauthorized: owner only")
	}
}

func assertNotPaused() {
	if paused {
		panic("appstore is paused")
	}
}

// ── Money path ────────────────────────────────────────────────────────────────

// RegisterApp lists a new app. The caller pays EXACTLY registrationFee ugnot with
// the call; the whole fee is forwarded to the treasury (no custody). The listing
// starts `pending` and is not shown live until a curator approves it.
func RegisterApp(
	cur realm,
	pkgPath, name, tagline, descr, category, iconCID, appURL string,
) uint64 {
	assertNotPaused()

	// O-13 guard: a payable entrypoint MUST be a direct user call, so an ephemeral
	// `maketx run` realm can never attach coins that become unrecoverable.
	if !unsafe.PreviousRealm().IsUserCall() {
		panic("RegisterApp must be a direct user call")
	}

	pkgPath = validatePkgPath(pkgPath)
	if _, dup := listings.Get(pkgPath); dup {
		panic("app already registered for this package path")
	}
	if len(name) == 0 || len(name) > MaxNameLen {
		panic("name must be 1.." + itoa(MaxNameLen) + " chars")
	}
	if len(tagline) > MaxTaglineLen {
		panic("tagline too long")
	}
	if len(descr) > MaxDescrLen {
		panic("description too long")
	}
	if len(appURL) > MaxURLLen {
		panic("appURL too long")
	}
	if len(iconCID) > MaxCIDLen {
		panic("iconCID too long")
	}

	// Exact-coin: read the coins attached to THIS call (not the wallet balance).
	sent := unsafe.OriginSend()
	if sent.AmountOf("ugnot") != registrationFee {
		panic(ufmt.Sprintf("must send exactly %d ugnot (sent %d)", registrationFee, sent.AmountOf("ugnot")))
	}
	// Fail-closed on a misconfigured treasury — reverting refunds the coins; we never
	// keep custody of a fee we can't route.
	if treasury == "" {
		panic("treasury unset — registration disabled")
	}

	// CEI: write state before moving funds.
	id := nextId
	nextId++
	l := &Listing{
		Id:        id,
		PkgPath:   pkgPath,
		Name:      name,
		Tagline:   tagline,
		Descr:     descr,
		Category:  category,
		IconCID:   iconCID,
		AppURL:    appURL,
		Publisher: caller(),
		Status:    StatusPending,
		CreatedAt: runtime.ChainHeight(),
	}
	listings.Set(pkgPath, l)

	// Forward the whole fee to the treasury from the realm's own account.
	if registrationFee > 0 {
		bnk := banker.NewBanker(banker.BankerTypeRealmSend, cur)
		bnk.SendCoins(
			unsafe.CurrentRealm().Address(),
			treasury,
			chain.Coins{chain.NewCoin("ugnot", registrationFee)},
		)
	}

	chain.Emit("AppRegistered", "pkgPath", pkgPath, "id", itoa64(id), "publisher", caller().String())
	return id
}

// ── Curation & moderation ───────────────────────────────────────────────────

// ApproveApp flips a pending listing live. Curator-only.
func ApproveApp(cur realm, pkgPath string) {
	if !isCurator(caller()) {
		panic("unauthorized: curator only")
	}
	l := mustGet(pkgPath)
	if l.Status == StatusDelisted {
		panic("cannot approve a delisted app")
	}
	l.Status = StatusLive
	listings.Set(pkgPath, l)
	chain.Emit("AppApproved", "pkgPath", pkgPath)
}

// DelistApp removes a listing from public view. The publisher or a curator may do it.
func DelistApp(cur realm, pkgPath string) {
	l := mustGet(pkgPath)
	if caller() != l.Publisher && !isCurator(caller()) {
		panic("unauthorized: publisher or curator only")
	}
	l.Status = StatusDelisted
	listings.Set(pkgPath, l)
	chain.Emit("AppDelisted", "pkgPath", pkgPath)
}

// RestoreApp brings a delisted app back to `pending` (re-curation required before it
// shows live again). Curator-only — this is the reverse of DelistApp, so a mistaken
// or contested delist is recoverable.
func RestoreApp(cur realm, pkgPath string) {
	if !isCurator(caller()) {
		panic("unauthorized: curator only")
	}
	l := mustGet(pkgPath)
	if l.Status != StatusDelisted {
		panic("only a delisted app can be restored")
	}
	l.Status = StatusPending
	listings.Set(pkgPath, l)
	chain.Emit("AppRestored", "pkgPath", pkgPath)
}

// FlagApp lets any user flag a LIVE listing once. At FlagHideThreshold distinct flags
// the listing stops appearing live; a curator then DelistApp's it or leaves it for
// review (a delisted app can be brought back with RestoreApp).
func FlagApp(cur realm, pkgPath string) {
	l := mustGet(pkgPath)
	if l.Status != StatusLive {
		panic("can only flag a live app")
	}
	key := pkgPath + "\x00" + caller().String()
	if _, done := flaggedBy.Get(key); done {
		panic("already flagged")
	}
	flaggedBy.Set(key, true)
	l.FlagCount++
	listings.Set(pkgPath, l)
	chain.Emit("AppFlagged", "pkgPath", pkgPath, "count", itoa(l.FlagCount))
}

// isVisible reports whether a listing shows in the live list.
func isVisible(l *Listing) bool {
	return l.Status == StatusLive && l.FlagCount < FlagHideThreshold
}

// ── Read getters (pure, non-failing) ─────────────────────────────────────────

// GetRegistrationFee returns the current flat listing fee in ugnot.
func GetRegistrationFee() int64 { return registrationFee }

// GetTreasury returns the address that receives listing fees.
func GetTreasury() address { return treasury }

// GetOwner returns the current owner (multisig, or a DAO executor after handoff).
func GetOwner() address { return owner }

// AppCount returns the total number of registered listings (any status).
func AppCount() int { return listings.Size() }

// GetStatsJSON returns a small stats object for a status header.
func GetStatsJSON() string {
	live := 0
	listings.Iterate("", "", func(_ string, v any) bool {
		if isVisible(v.(*Listing)) {
			live++
		}
		return false
	})
	return ufmt.Sprintf(`{"total":%d,"live":%d,"registrationFee":%d,"paused":%t}`,
		listings.Size(), live, registrationFee, paused)
}

// ── internal helpers ─────────────────────────────────────────────────────────

func isCurator(a address) bool {
	_, ok := curators.Get(a.String())
	return ok
}

func mustGet(pkgPath string) *Listing {
	v, ok := listings.Get(pkgPath)
	if !ok {
		panic("app not found: " + pkgPath)
	}
	return v.(*Listing)
}

// validatePkgPath normalizes + sanity-checks a realm/package path.
func validatePkgPath(p string) string {
	if len(p) == 0 || len(p) > MaxPkgPathLen {
		panic("pkgPath must be 1.." + itoa(MaxPkgPathLen) + " chars")
	}
	// Must be a gno.land realm ("/r/") or package ("/p/") path.
	if !hasPrefix(p, "gno.land/r/") && !hasPrefix(p, "gno.land/p/") {
		panic("pkgPath must be a gno.land/r/... or gno.land/p/... path")
	}
	return p
